// â SEGURANĂA v153: AUTENTICAĂĂO POR TOKEN ASSINADO (HMAC-SHA256)
// Problema anterior: API confiava no header X-User-ID que qualquer um podia forjar
// SoluĂ§ĂŁo: Token assinado pelo servidor = userId.expiresAt.signature
// O token ĂŠ gerado no login/register/google e verificado em cada requisiĂ§ĂŁo
// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ

// Derivar chave HMAC a partir de um segredo
async function getHMACKey(secret: string): Promise<CryptoKey> {
  const encoder = new TextEncoder()
  return crypto.subtle.importKey(
    'raw',
    encoder.encode(secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign', 'verify']
  )
}

// Gerar token de sessĂŁo: base64(userId.expiresAt.hmac)
async function generateSessionToken(userId: number | string, secret: string, ttlDays: number = 30): Promise<string> {
  const expiresAt = Date.now() + (ttlDays * 24 * 60 * 60 * 1000)
  const payload = `${userId}.${expiresAt}`
  
  const key = await getHMACKey(secret)
  const encoder = new TextEncoder()
  const signature = await crypto.subtle.sign('HMAC', key, encoder.encode(payload))
  
  // Converter para hex
  const sigHex = Array.from(new Uint8Array(signature))
    .map(b => b.toString(16).padStart(2, '0'))
    .join('')
  
  return `${payload}.${sigHex}`
}

// Validar token de sessĂŁo e retornar userId ou null
async function validateSessionToken(token: string, secret: string): Promise<string | null> {
  if (!token || !secret) return null
  
  const parts = token.split('.')
  if (parts.length !== 3) return null
  
  const [userId, expiresAtStr, sigHex] = parts
  const expiresAt = parseInt(expiresAtStr)
  
  // Verificar expiraĂ§ĂŁo
  if (isNaN(expiresAt) || Date.now() > expiresAt) return null
  
  // Verificar assinatura HMAC
  const payload = `${userId}.${expiresAtStr}`
  const key = await getHMACKey(secret)
  const encoder = new TextEncoder()
  
  // Converter hex para bytes
  const sigBytes = new Uint8Array(sigHex.match(/.{2}/g)!.map(byte => parseInt(byte, 16)))
  
  const valid = await crypto.subtle.verify('HMAC', key, sigBytes, encoder.encode(payload))
  
  if (!valid) return null
  return userId
}

// Obter o segredo para HMAC (de env ou fallback seguro)
function getAuthSecret(env: any): string {
  return env.AUTH_SECRET || env.MP_WEBHOOK_SECRET || 'iaprova-default-secret-change-me'
}

// â v156: Hash do token para armazenar na tabela de sessĂľes (nĂŁo armazena token completo)
async function hashToken(token: string): Promise<string> {
  const encoder = new TextEncoder()
  const hash = await crypto.subtle.digest('SHA-256', encoder.encode(token))
  return Array.from(new Uint8Array(hash)).map(b => b.toString(16).padStart(2, '0')).join('')
}

// â v156: Registrar sessĂŁo ao fazer login
async function registerSession(DB: any, userId: number | string, token: string, c: any): Promise<void> {
  try {
    // Auto-criar tabela se nĂŁo existir
    await DB.prepare(`CREATE TABLE IF NOT EXISTS active_sessions (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      token_hash TEXT NOT NULL UNIQUE,
      device_info TEXT,
      ip_address TEXT,
      user_agent TEXT,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      last_seen_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      is_revoked INTEGER DEFAULT 0,
      revoked_at DATETIME,
      revoked_by TEXT
    )`).run()

    const tokenHash = await hashToken(token)
    const userAgent = c.req.header('User-Agent') || 'Desconhecido'
    const ip = c.req.header('cf-connecting-ip') || c.req.header('x-forwarded-for') || 'Desconhecido'
    
    // Extrair info do dispositivo do User-Agent
    let deviceInfo = 'Desconhecido'
    if (/iPhone|iPad/i.test(userAgent)) deviceInfo = 'iOS - Safari'
    else if (/Android/i.test(userAgent)) deviceInfo = 'Android'
    else if (/Windows/i.test(userAgent)) deviceInfo = 'Windows'
    else if (/Mac/i.test(userAgent)) deviceInfo = 'MacOS'
    else if (/Linux/i.test(userAgent)) deviceInfo = 'Linux'
    
    if (/Chrome/i.test(userAgent) && !/Edge/i.test(userAgent)) deviceInfo += ' - Chrome'
    else if (/Firefox/i.test(userAgent)) deviceInfo += ' - Firefox'
    else if (/Safari/i.test(userAgent) && !/Chrome/i.test(userAgent)) deviceInfo += ' - Safari'
    else if (/Edge/i.test(userAgent)) deviceInfo += ' - Edge'

    await DB.prepare(`
      INSERT OR REPLACE INTO active_sessions (user_id, token_hash, device_info, ip_address, user_agent, created_at, last_seen_at, is_revoked)
      VALUES (?, ?, ?, ?, ?, datetime('now'), datetime('now'), 0)
    `).bind(userId, tokenHash, deviceInfo, ip, userAgent.substring(0, 500)).run()
    
    console.log(`đą v156: SessĂŁo registrada para userId=${userId} | ${deviceInfo} | IP=${ip}`)
  } catch (e) {
    console.error('â ď¸ Erro ao registrar sessĂŁo (nĂŁo crĂ­tico):', e)
  }
}

// â v156: Verificar se sessĂŁo foi revogada
async function isSessionRevoked(DB: any, token: string): Promise<boolean> {
  try {
    const tokenHash = await hashToken(token)
    const session = await DB.prepare(
      'SELECT is_revoked FROM active_sessions WHERE token_hash = ?'
    ).bind(tokenHash).first() as any
    // Se sessĂŁo nĂŁo existe na tabela, permitir (token vĂĄlido por assinatura)
    if (!session) return false
    return session.is_revoked === 1
  } catch {
    return false // Em caso de erro, nĂŁo bloquear (tabela pode nĂŁo existir ainda)
  }
}

// â v156: Atualizar last_seen da sessĂŁo
async function touchSession(DB: any, token: string): Promise<void> {
  try {
    const tokenHash = await hashToken(token)
    await DB.prepare(
      'UPDATE active_sessions SET last_seen_at = datetime(\'now\') WHERE token_hash = ? AND is_revoked = 0'
    ).bind(tokenHash).run()
  } catch { /* nĂŁo crĂ­tico */ }
}

// â v156 SEGURANĂA: Extrair e validar userId â verifica assinatura E revogaĂ§ĂŁo
async function getAuthenticatedUserId(c: any): Promise<string | null> {
  const authHeader = c.req.header('Authorization') || ''
  const secret = getAuthSecret(c.env)
  
  if (authHeader.startsWith('Bearer ')) {
    const token = authHeader.substring(7)
    const userId = await validateSessionToken(token, secret)
    if (!userId) return null
    
    // Verificar se sessĂŁo foi revogada pelo admin
    const { DB } = c.env
    if (DB && await isSessionRevoked(DB, token)) {
      console.warn(`đ¨ v156: Token revogado usado por userId=${userId}`)
      return null
    }
    
    // Atualizar last_seen (background, nĂŁo bloqueia)
    if (DB) touchSession(DB, token)
    
    return userId
  }
  
  return null
}

// â v153: isAdmin reescrito para usar token assinado
async function isAdminAuthenticated(c: any): Promise<boolean> {
  const userId = await getAuthenticatedUserId(c)
  if (!userId) return false
  
  const { DB } = c.env
  const user = await DB.prepare('SELECT email, auth_provider FROM users WHERE id = ?').bind(userId).first() as any
  if (!user || user.email !== ADMIN_EMAIL) return false
  
  // Admin DEVE ter autenticado via Google
  const provider = (user.auth_provider || '').toLowerCase()
  if (provider !== 'google' && provider !== 'both') {
    console.warn(`đ¨ SEGURANĂA v153: Admin ${userId} rejeitado â auth_provider=${provider}`)
    return false
  }
  
  return true
}

// â FUNĂĂO PARA PDFs GRANDES - USA FILES API DO GEMINI
async function extractLargePDFWithFilesAPI(pdfBytes: Uint8Array, geminiKey: string): Promise<string> {
  console.log('đ Usando Files API do Gemini para PDF grande...')
  
  // PASSO 1: Upload do arquivo para o Gemini Files API
  const uploadUrl = `https://generativelanguage.googleapis.com/upload/v1beta/files?key=${geminiKey}`
  
  // Criar FormData com o arquivo
  const formData = new FormData()
  const blob = new Blob([pdfBytes], { type: 'application/pdf' })
  formData.append('file', blob, 'edital.pdf')
  
  console.log('đ¤ Fazendo upload do PDF para Gemini Files API...')
  
  const uploadResponse = await fetch(uploadUrl, {
    method: 'POST',
    headers: {
      'X-Goog-Upload-Protocol': 'multipart',
    },
    body: formData
  })
  
  if (!uploadResponse.ok) {
    const errorText = await uploadResponse.text()
    console.error('â Erro no upload:', uploadResponse.status, errorText)
    throw new Error(`Falha no upload: ${uploadResponse.status}`)
  }
  
  const uploadData = await uploadResponse.json() as any
  const fileUri = uploadData.file?.uri
  
  if (!fileUri) {
    console.error('â URI do arquivo nĂŁo retornada:', uploadData)
    throw new Error('URI do arquivo nĂŁo retornada pelo Gemini')
  }
  
  console.log('â Upload concluĂ­do. URI:', fileUri)
  
  // PASSO 2: Aguardar processamento do arquivo (pode levar alguns segundos)
  const sleep = (ms: number) => new Promise(r => setTimeout(r, ms))
  let fileReady = false
  let attempts = 0
  
  while (!fileReady && attempts < 30) {
    await sleep(2000)
    attempts++
    
    const statusResponse = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/${uploadData.file.name}?key=${geminiKey}`
    )
    
    if (statusResponse.ok) {
      const statusData = await statusResponse.json() as any
      console.log(`đ Status do arquivo (tentativa ${attempts}): ${statusData.state}`)
      
      if (statusData.state === 'ACTIVE') {
        fileReady = true
      } else if (statusData.state === 'FAILED') {
        throw new Error('Processamento do arquivo falhou')
      }
    }
  }
  
  if (!fileReady) {
    throw new Error('Timeout aguardando processamento do arquivo')
  }
  
  // PASSO 3: Gerar conteĂşdo usando o arquivo
  console.log('đ Gerando extraĂ§ĂŁo do texto com Gemini...')
  
  const generateUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${geminiKey}`
  
  const generateResponse = await fetch(generateUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      contents: [{
        parts: [
          {
            file_data: {
              mime_type: 'application/pdf',
              file_uri: fileUri
            }
          },
          {
            text: `EXTRAIA O CONTEĂDO PROGRAMĂTICO COMPLETO deste edital de concurso.

FOCO: VĂĄ direto para os ANEXOS (geralmente Anexo II ou III) que contĂŞm o CONTEĂDO PROGRAMĂTICO.

EXTRAIA:
1. TODAS as disciplinas (PortuguĂŞs, RaciocĂ­nio LĂłgico, InformĂĄtica, Conhecimentos EspecĂ­ficos, etc.)
2. TODOS os tĂłpicos de cada disciplina
3. O quadro de provas com pesos se houver

TRANSCREVA literalmente. NĂO resuma. NĂO comente.

INICIE A TRANSCRIĂĂO:`
          }
        ]
      }],
      generationConfig: {
        temperature: 0.1,
        maxOutputTokens: 65536
      }
    })
  })
  
  if (!generateResponse.ok) {
    const errorText = await generateResponse.text()
    console.error('â Erro na geraĂ§ĂŁo:', generateResponse.status, errorText)
    throw new Error(`Falha na geraĂ§ĂŁo: ${generateResponse.status}`)
  }
  
  const generateData = await generateResponse.json() as any
  const texto = generateData.candidates?.[0]?.content?.parts?.[0]?.text || ''
  
  console.log(`â Texto extraĂ­do: ${texto.length} caracteres`)
  
  // PASSO 4: Deletar o arquivo do Gemini (limpeza)
  try {
    await fetch(
      `https://generativelanguage.googleapis.com/v1beta/${uploadData.file.name}?key=${geminiKey}`,
      { method: 'DELETE' }
    )
    console.log('đď¸ Arquivo temporĂĄrio deletado do Gemini')
  } catch (e) {
    console.warn('â ď¸ Falha ao deletar arquivo temporĂĄrio (nĂŁo crĂ­tico)')
  }
  
  return texto
}

// âââ FUNĂĂO OTIMIZADA DE EXTRAĂĂO DE PDF - RĂPIDA E EFICIENTE
async function extractTextFromPDF(pdfBuffer: ArrayBuffer, geminiKey: string): Promise<string> {
  console.log('âĄ Iniciando extraĂ§ĂŁo de texto do PDF com Gemini API...')
  
  const bytes = new Uint8Array(pdfBuffer)
  const fileSizeMB = bytes.length / (1024 * 1024)
  console.log(`đ PDF: ${bytes.length} bytes (${fileSizeMB.toFixed(2)} MB)`)
  
  // Para PDFs muito grandes (>10MB), tentar usar Files API do Gemini
  if (fileSizeMB > 10) {
    console.log(`đŚ PDF grande (${fileSizeMB.toFixed(1)}MB) - usando Files API do Gemini...`)
    try {
      const textoGrande = await extractLargePDFWithFilesAPI(bytes, geminiKey)
      if (textoGrande && textoGrande.length > 500) {
        return textoGrande
      }
    } catch (largeError) {
      console.warn(`â ď¸ Files API falhou, tentando mĂŠtodo padrĂŁo...`, largeError)
    }
  }
  
  // Converter para base64 de forma otimizada
  let binary = ''
  const len = bytes.length
  const chunkSize = 8192
  
  for (let i = 0; i < len; i += chunkSize) {
    const chunk = bytes.subarray(i, Math.min(i + chunkSize, len))
    binary += String.fromCharCode.apply(null, Array.from(chunk))
  }
  const base64 = btoa(binary)
  
  console.log(`đ Base64: ${base64.length} caracteres`)
  
  // Limite aumentado para 30MB em base64 (~22MB arquivo real)
  if (base64.length > 40000000) {
    throw new Error(`PDF muito grande (${fileSizeMB.toFixed(1)}MB). Converta para TXT em smallpdf.com`)
  }
  
  // â PROMPT OTIMIZADO PARA EDITAIS DE CONCURSOS - EXTRAĂĂO COMPLETA DOS ANEXOS
  const promptOtimizado = `VOCĂ ESTĂ EXTRAINDO UM EDITAL DE CONCURSO PĂBLICO BRASILEIRO.

đŻ MISSĂO CRĂTICA: EXTRAIR O CONTEĂDO PROGRAMĂTICO DOS ANEXOS

â ď¸ IMPORTANTE: O ConteĂşdo ProgramĂĄtico SEMPRE estĂĄ nos ANEXOS (geralmente Anexo II ou III)
- NĂO extraia as primeiras pĂĄginas (sĂŁo instruĂ§Ăľes gerais)
- VĂ DIRETO para os ANEXOS no final do documento
- PROCURE por: "ANEXO II - CONTEĂDO PROGRAMĂTICO" ou "CONTEĂDO DAS DISCIPLINAS"

đ O QUE EXTRAIR (em ordem de prioridade):

1. QUADRO DE PROVAS (peso e questĂľes):
   - Estrutura da prova objetiva
   - Peso de Conhecimentos Gerais vs EspecĂ­ficos
   - NĂşmero de questĂľes por disciplina

2. CONTEĂDO PROGRAMĂTICO COMPLETO:
   - TODAS as disciplinas listadas
   - TODOS os tĂłpicos de cada disciplina
   - Estrutura: DISCIPLINA: tĂłpico 1, tĂłpico 2, etc.

3. DISCIPLINAS TĂPICAS A ENCONTRAR:
   - CONHECIMENTOS GERAIS: PortuguĂŞs, RaciocĂ­nio LĂłgico, InformĂĄtica, Atualidades, LegislaĂ§ĂŁo
   - CONHECIMENTOS ESPECĂFICOS: depende do cargo (Enfermagem, SUS, SaĂşde, etc.)

đ FORMATO DE SAĂDA:
Transcreva literalmente o conteĂşdo programĂĄtico encontrado nos anexos.
NĂO resuma. NĂO comente. Apenas transcreva.

INICIE A TRANSCRIĂĂO DO CONTEĂDO PROGRAMĂTICO (ANEXOS):`

  // â ESTRATĂGIAS COM MĂLTIPLOS MODELOS E RETRIES
  const estrategias = [
    { prompt: promptOtimizado, modelo: 'gemini-2.5-flash', desc: 'Lite (tentativa 1)' },
    { prompt: promptOtimizado, modelo: 'gemini-2.5-flash', desc: 'Flash (tentativa 1)' },
    { prompt: promptOtimizado, modelo: 'gemini-2.5-flash', desc: 'Flash Exp' },
    { prompt: promptOtimizado, modelo: 'gemini-2.5-flash', desc: 'Lite (tentativa 2)' },
    { prompt: promptOtimizado, modelo: 'gemini-2.5-flash', desc: 'Flash (tentativa 2)' }
  ]
  
  let melhorTexto = ''
  let allErrors: string[] = []
  let consecutiveRateLimits = 0
  
  // FunĂ§ĂŁo para delay
  const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms))
  
  for (let i = 0; i < estrategias.length; i++) {
    const estrategia = estrategias[i]
    console.log(`\nđ Tentativa ${i + 1}/${estrategias.length}: ${estrategia.desc}`)
    
    // Se jĂĄ teve muitos rate limits consecutivos, aguardar mais
    if (consecutiveRateLimits >= 2) {
      console.log(`   âł Aguardando 5s devido a rate limits consecutivos...`)
      await sleep(5000)
    }
    
    try {
      const response = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/${estrategia.modelo}:generateContent?key=${geminiKey}`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            contents: [{
              parts: [
                { text: estrategia.prompt },
                { inline_data: { mime_type: 'application/pdf', data: base64 } }
              ]
            }],
            generationConfig: {
              temperature: 0.01,
              topP: 0.95,
              topK: 40,
              maxOutputTokens: 65536
            }
          })
        }
      )
      
      console.log(`   đĄ Status: ${response.status}`)
      
      // â Rate limit ou serviĂ§o indisponĂ­vel - aguardar e tentar prĂłximo
      if (response.status === 429 || response.status === 503) {
        consecutiveRateLimits++
        const waitTime = Math.min(consecutiveRateLimits * 2000, 10000)
        console.log(`   âŠ Erro ${response.status} - aguardando ${waitTime/1000}s antes do prĂłximo...`)
        await sleep(waitTime)
        continue
      }
      
      // Reset contador se nĂŁo foi rate limit
      consecutiveRateLimits = 0
      
      if (!response.ok) {
        const errorText = await response.text()
        console.error(`   â Erro ${response.status}: ${errorText.substring(0, 100)}`)
        allErrors.push(`Erro ${response.status}`)
        continue
      }
      
      const data = await response.json() as any
      
      // ValidaĂ§ĂŁo simples
      if (!data.candidates?.[0]?.content?.parts?.[0]?.text) {
        console.error(`   â Resposta invĂĄlida`)
        allErrors.push('Resposta invĂĄlida')
        continue
      }
      
      const texto = data.candidates[0].content.parts[0].text
      
      // ValidaĂ§ĂŁo mĂ­nima de tamanho
      if (texto.length < 500) {
        console.error(`   â Texto muito curto: ${texto.length} chars`)
        allErrors.push(`Texto curto (${texto.length})`)
        continue
      }
      
      console.log(`   â ExtraĂ­do: ${texto.length} caracteres`)
      
      // â RETORNAR IMEDIATAMENTE se texto for vĂĄlido (sem validaĂ§Ăľes complexas)
      if (texto.length >= 1000) {
        console.log(`   đŻ SUCESSO! Retornando texto extraĂ­do.`)
        return texto
      }
      
      // Guardar como backup
      if (texto.length > melhorTexto.length) {
        melhorTexto = texto
      }
      
    } catch (error) {
      const msg = error instanceof Error ? error.message : String(error)
      console.error(`   â Erro: ${msg}`)
      allErrors.push(msg)
    }
  }
  
  // â Retornar melhor resultado se houver
  if (melhorTexto.length >= 500) {
    console.log(`\nâ Retornando melhor resultado: ${melhorTexto.length} caracteres`)
    return melhorTexto
  }
  
  // â Falha total
  console.error('\nâ FALHA - Todas as tentativas falharam')
  throw new Error(
    `Falha ao extrair texto do PDF.\n` +
    `Erros: ${allErrors.join(', ')}\n\n` +
    `SOLUĂĂES:\n` +
    `1. â RECOMENDADO: Converta o PDF para TXT em https://smallpdf.com/pdf-to-text\n` +
    `2. Use um arquivo XLSX com o cronograma de estudos\n` +
    `3. Aguarde 2-3 minutos (possĂ­vel rate limit da API Gemini)`
  )
}

// FunĂ§ĂŁo para extrair texto de DOC/DOCX usando Gemini
async function extractTextFromDocx(docBuffer: ArrayBuffer, geminiKey: string, mimeType: string): Promise<string> {
  console.log('đ Iniciando extraĂ§ĂŁo de texto do DOCX com Gemini API...')
  
  const bytes = new Uint8Array(docBuffer)
  const fileSizeMB = bytes.length / (1024 * 1024)
  console.log(`đ DOCX: ${bytes.length} bytes (${fileSizeMB.toFixed(2)} MB)`)
  
  // Converter para base64
  let binary = ''
  const len = bytes.length
  const chunkSize = 8192
  
  for (let i = 0; i < len; i += chunkSize) {
    const chunk = bytes.subarray(i, Math.min(i + chunkSize, len))
    binary += String.fromCharCode.apply(null, Array.from(chunk))
  }
  const base64 = btoa(binary)
  
  console.log(`đ Base64: ${base64.length} caracteres`)
  
  const prompt = `Extraia TODO o texto deste documento Word. Retorne o conteĂşdo completo, preservando a estrutura (parĂĄgrafos, tĂ­tulos, listas). NĂŁo adicione comentĂĄrios ou anĂĄlises, apenas o texto extraĂ­do do documento.`

  const geminiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${geminiKey}`
  
  const response = await fetch(geminiUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      contents: [{
        parts: [
          { text: prompt },
          { 
            inlineData: { 
              mimeType: mimeType,
              data: base64 
            } 
          }
        ]
      }],
      generationConfig: {
        temperature: 0.1,
        maxOutputTokens: 30000
      }
    })
  })
  
  if (!response.ok) {
    const errText = await response.text()
    console.error('Gemini DOCX error:', errText)
    throw new Error(`Gemini API error: ${response.status}`)
  }
  
  const data = await response.json() as any
  const textoExtraido = data?.candidates?.[0]?.content?.parts?.[0]?.text || ''
  
  console.log(`đ Texto extraĂ­do do DOCX: ${textoExtraido.length} caracteres`)
  return textoExtraido
}

// FunĂ§ĂŁo para extrair disciplinas e tĂłpicos de um arquivo XLSX (cronograma)
async function extractFromXLSX(xlsxBuffer: ArrayBuffer): Promise<{ disciplinas: Array<{ nome: string, topicos: string[] }> }> {
  try {
    console.log('đ Iniciando extraĂ§ĂŁo de disciplinas e tĂłpicos do XLSX...')
    
    // Ler o arquivo XLSX
    const workbook = XLSX.read(xlsxBuffer, { type: 'array' })
    
    // Verificar se a planilha "Cronograma Intercalado" existe
    const sheetName = 'Cronograma Intercalado'
    if (!workbook.SheetNames.includes(sheetName)) {
      throw new Error('Planilha "Cronograma Intercalado" nĂŁo encontrada no arquivo')
    }
    
    const sheet = workbook.Sheets[sheetName]
    const rows = XLSX.utils.sheet_to_json(sheet, { header: 1, defval: '' }) as any[][]
    
    console.log(`đ Lendo ${rows.length} linhas da planilha "${sheetName}"`)
    
    // Estrutura para agrupar disciplinas e tĂłpicos
    const disciplinasMap = new Map<string, Set<string>>()
    
    // Processar linhas (pular cabeĂ§alho na linha 0)
    for (let i = 1; i < rows.length; i++) {
      const row = rows[i]
      
      // Colunas: [Semana, PerĂ­odo, Fase, Data, Dia, TĂłpico, Disciplina, Horas, DescriĂ§ĂŁo]
      const topico = row[5]?.toString().trim() || ''
      const disciplina = row[6]?.toString().trim() || ''
      
      // Ignorar linhas vazias ou invĂĄlidas
      if (!topico || !disciplina || disciplina === 'Disciplina') continue
      
      // Ignorar disciplinas auxiliares (RevisĂŁo, PrĂĄtica, Simulado, PROVA)
      const disciplinasIgnoradas = ['RevisĂŁo', 'PrĂĄtica', 'Simulado', 'PROVA']
      if (disciplinasIgnoradas.includes(disciplina)) continue
      
      // Adicionar Ă  estrutura
      if (!disciplinasMap.has(disciplina)) {
        disciplinasMap.set(disciplina, new Set())
      }
      
      // Limpar tĂłpicos com prefixos especiais (â­, â, etc.)
      const topicoLimpo = topico.replace(/^[â­ââđđĽđĄ]+\s*/, '').trim()
      
      if (topicoLimpo && topicoLimpo.length > 3) {
        disciplinasMap.get(disciplina)!.add(topicoLimpo)
      }
    }
    
    // đŻ AGRUPAMENTO INTELIGENTE: Mapear para estrutura do edital
    const agrupamento = new Map<string, Set<string>>()
    
    // Regras de mapeamento baseadas no edital real
    const mapeamento: { [key: string]: string } = {
      'PortuguĂŞs': 'LĂ­ngua Portuguesa',
      'LĂłgica': 'RaciocĂ­nio LĂłgico-MatemĂĄtico',
      'PiauĂ­': 'Conhecimentos Regionais do PiauĂ­',
      'SUS': 'Sistema Ănico de SaĂşde (SUS)',
      'EmergĂŞncia': 'Enfermagem (Conhecimentos EspecĂ­ficos)',
      'AssistĂŞncia Geral': 'Enfermagem (Conhecimentos EspecĂ­ficos)',
      'Farmacologia': 'Enfermagem (Conhecimentos EspecĂ­ficos)',
      'SaĂşde Mulher': 'Enfermagem (Conhecimentos EspecĂ­ficos)',
      'SaĂşde CrianĂ§a': 'Enfermagem (Conhecimentos EspecĂ­ficos)',
      'SaĂşde Idoso': 'Enfermagem (Conhecimentos EspecĂ­ficos)',
      'Cuidados CrĂ­ticos': 'Enfermagem (Conhecimentos EspecĂ­ficos)',
      'DoenĂ§as Infecciosas': 'Enfermagem (Conhecimentos EspecĂ­ficos)'
    }
    
    // Aplicar mapeamento
    for (const [discOriginal, topicosSet] of disciplinasMap.entries()) {
      const discAgrupada = mapeamento[discOriginal] || discOriginal
      
      if (!agrupamento.has(discAgrupada)) {
        agrupamento.set(discAgrupada, new Set())
      }
      
      // Adicionar todos os tĂłpicos ao grupo
      for (const topico of topicosSet) {
        agrupamento.get(discAgrupada)!.add(topico)
      }
    }
    
    // Converter para formato final com ordem
    const disciplinas = Array.from(agrupamento.entries()).map(([nome, topicosSet], index) => ({
      nome,
      topicos: Array.from(topicosSet).sort(),
      ordem: index
    })).sort((a, b) => a.nome.localeCompare(b.nome))
    
    console.log(`â Agrupamento aplicado: ${disciplinas.length} disciplinas finais (de ${disciplinasMap.size} originais)`)
    
    // Log resumido
    disciplinas.forEach(d => {
      console.log(`  đ ${d.nome}: ${d.topicos.length} tĂłpicos`)
    })
    
    return { disciplinas }
    
  } catch (error: any) {
    console.error('â Erro ao processar XLSX:', error)
    throw new Error(`Falha ao extrair dados do XLSX: ${error.message || error}`)
  }
}

