// Alias para /api/register (usado pela landing page)
app.post('/api/register', async (c) => {
  const { DB } = c.env
  const body = await c.req.json()
  
  const email = body.email?.toLowerCase()?.trim()
  const password = body.password || body.senha
  const name = body.name || body.nome || email?.split('@')[0] || 'UsuĂĄrio'
  
  console.log('đ Registro via landing:', { email, hasPassword: !!password })

  // Validar campos obrigatĂłrios
  if (!email) {
    return c.json({ error: 'Email ĂŠ obrigatĂłrio' }, 400)
  }
  
  if (!password || password.length < 4) {
    return c.json({ error: 'Senha deve ter pelo menos 4 caracteres' }, 400)
  }
  
  // Validar formato do email
  if (!isValidEmail(email)) {
    return c.json({ error: 'Email invĂĄlido' }, 400)
  }

  // â SEGURANĂA v146: Bloquear registro por email/senha para o admin
  if (email === ADMIN_EMAIL) {
    console.warn(`đ¨ SEGURANĂA: Tentativa de registro por email/senha bloqueada para admin (${email})`)
    return c.json({ 
      error: 'Esta conta utiliza exclusivamente autenticaĂ§ĂŁo via Google. Use o botĂŁo "Entrar com Google".',
      googleOnly: true
    }, 403)
  }

  try {
    // Verificar se email jĂĄ existe
    const existingUser = await DB.prepare(
      'SELECT id, email_verified, password FROM users WHERE email = ?'
    ).bind(email).first() as {id: number, email_verified: number, password: string} | undefined

    if (existingUser) {
      // Se usuĂĄrio existe, tentar fazer login automĂĄtico
      if (existingUser.password === password) {
        // Senha correta - fazer login
        const user = await DB.prepare(
          'SELECT id, email, name, created_at FROM users WHERE id = ?'
        ).bind(existingUser.id).first() as any
        
        // â v154 SEGURANĂA: Gerar token assinado no auto-login via register
        const secret = getAuthSecret(c.env)
        const sessionToken = await generateSessionToken(user.id, secret)
        
        // â v156: Registrar sessĂŁo/dispositivo
        await registerSession(DB, user.id, sessionToken, c)
        
        return c.json({ 
          user,
          token: sessionToken,
          message: 'Login realizado com sucesso!',
          isLogin: true
        })
      } else {
        return c.json({ error: 'Email jĂĄ cadastrado. Use a opĂ§ĂŁo de login ou recupere sua senha.' }, 400)
      }
    }

    // â CORREĂĂO v10: Criar novo usuĂĄrio COM verificaĂ§ĂŁo de email obrigatĂłria
    const verificationToken = crypto.randomUUID()
    
    const result = await DB.prepare(
      `INSERT INTO users (name, email, password, email_verified, verification_token, trial_started_at, trial_expires_at, subscription_status) 
       VALUES (?, ?, ?, 0, ?, datetime('now'), datetime('now', '+14 days'), 'trial')`
    ).bind(name, email, password, verificationToken).run()

    // Enviar email de verificaĂ§ĂŁo
    let emailSent = false
    try {
      emailSent = await sendVerificationEmail(email, verificationToken, name, c.env)
      console.log(`đ§ Email de verificaĂ§ĂŁo ${emailSent ? 'ENVIADO' : 'NĂO ENVIADO'} para ${email}`)
      
      // â v84: Registrar no histĂłrico mesmo quando sendVerificationEmail jĂĄ registra internamente
      // Se NĂO foi enviado (retornou false sem exception), registrar como 'failed' 
      if (!emailSent) {
        await logEmailSent(
          DB,
          email,
          'verification',
          'đŻ Ative sua conta no IAprova',
          'failed',
          result.meta.last_row_id as number,
          'Email nĂŁo enviado - RESEND_API_KEY nĂŁo configurada ou modo de teste'
        )
      }
    } catch (emailError: any) {
      console.error('â ď¸ Erro ao enviar email de verificaĂ§ĂŁo:', emailError)
      // Registrar falha no histĂłrico
      await logEmailSent(
        DB,
        email,
        'verification',
        'đŻ Ative sua conta no IAprova',
        'failed',
        result.meta.last_row_id as number,
        emailError?.message || 'Erro desconhecido ao enviar email'
      )
    }

    // Buscar usuĂĄrio criado
    const newUser = await DB.prepare(
      'SELECT id, email, name, created_at, email_verified FROM users WHERE id = ?'
    ).bind(result.meta.last_row_id).first()

    return c.json({ 
      user: newUser,
      message: emailSent 
        ? 'đ Conta criada! Verifique seu email para ativar sua conta.'
        : 'đ Conta criada! Verifique seu email (pode estar na pasta spam) ou solicite o reenvio.',
      requiresVerification: true,
      emailSent
    })
  } catch (error) {
    console.error('Erro no registro:', error)
    return c.json({ error: 'Erro ao criar conta. Tente novamente.' }, 500)
  }
})

