// â SEGURANĂA v147: Cache de token em memĂłria (por request no Workers, mas previne mĂşltiplas chamadas dentro do mesmo request)
let cachedMPToken: { token: string; expiresAt: number } | null = null

// â SEGURANĂA v147: Obter token MP vĂĄlido - tenta usar o configurado, se falhar faz refresh via OAuth
async function getValidMPToken(env: any): Promise<string> {
  const { MP_ACCESS_TOKEN, MP_CLIENT_ID, MP_CLIENT_SECRET } = env as any
  
  // Se nĂŁo temos credenciais OAuth, usar token direto
  if (!MP_CLIENT_ID || !MP_CLIENT_SECRET) {
    if (!MP_ACCESS_TOKEN) throw new Error('MP_ACCESS_TOKEN nĂŁo configurado')
    return MP_ACCESS_TOKEN
  }
  
  // Se temos cache vĂĄlido (com margem de 5 min), usar
  if (cachedMPToken && cachedMPToken.expiresAt > Date.now() + 300000) {
    return cachedMPToken.token
  }
  
  // Testar se o token atual funciona
  if (MP_ACCESS_TOKEN) {
    try {
      const testResponse = await fetch('https://api.mercadopago.com/v1/payment_methods', {
        headers: { 'Authorization': `Bearer ${MP_ACCESS_TOKEN}` }
      })
      if (testResponse.ok) {
        console.log('â MP_ACCESS_TOKEN vĂĄlido')
        return MP_ACCESS_TOKEN
      }
      console.warn('â ď¸ MP_ACCESS_TOKEN expirado ou invĂĄlido, tentando refresh...')
    } catch (e) {
      console.warn('â ď¸ Erro ao testar MP_ACCESS_TOKEN, tentando refresh...')
    }
  }
  
  // Fazer refresh via OAuth client_credentials
  try {
    console.log('đ Renovando token MP via OAuth...')
    const response = await fetch('https://api.mercadopago.com/oauth/token', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        grant_type: 'client_credentials',
        client_id: MP_CLIENT_ID,
        client_secret: MP_CLIENT_SECRET
      })
    })
    
    if (!response.ok) {
      const errorText = await response.text()
      console.error('đ¨ Falha ao renovar token MP:', response.status, errorText)
      // Fallback para o token configurado
      if (MP_ACCESS_TOKEN) return MP_ACCESS_TOKEN
      throw new Error('Falha na renovaĂ§ĂŁo do token MP')
    }
    
    const data = await response.json() as any
    const newToken = data.access_token
    
    if (!newToken) {
      console.error('đ¨ Token renovado vazio')
      if (MP_ACCESS_TOKEN) return MP_ACCESS_TOKEN
      throw new Error('Token renovado vazio')
    }
    
    // Cachear o novo token
    cachedMPToken = {
      token: newToken,
      expiresAt: Date.now() + (data.expires_in || 21600) * 1000
    }
    
    console.log(`â Token MP renovado com sucesso. Expira em ${data.expires_in || 21600}s`)
    return newToken
  } catch (error: any) {
    console.error('đ¨ Erro ao renovar token MP:', error.message)
    // Ăltimo fallback
    if (MP_ACCESS_TOKEN) {
      console.warn('â ď¸ Usando MP_ACCESS_TOKEN como fallback')
      return MP_ACCESS_TOKEN
    }
    throw new Error('NĂŁo foi possĂ­vel obter token MP vĂĄlido')
  }
}

// Criar preferĂŞncia de pagamento no Mercado Pago
app.post('/api/mercadopago/create-preference', async (c) => {
  const { DB, APP_URL } = c.env as any
  
  // â v167 SEGURANĂA: Validar que o usuĂĄrio autenticado ĂŠ o mesmo do body
  const authenticatedUserId = c.get('authenticatedUserId')
  if (!authenticatedUserId) {
    return c.json({ error: 'AutenticaĂ§ĂŁo obrigatĂłria' }, 401)
  }
  
  // â v147: Usar token com refresh automĂĄtico
  let MP_ACCESS_TOKEN: string
  try {
    MP_ACCESS_TOKEN = await getValidMPToken(c.env)
  } catch {
    return c.json({ error: 'Mercado Pago nĂŁo configurado' }, 500)
  }
  const { user_id, plan } = await c.req.json()
  
  // â v167 SEGURANĂA CRĂTICA: user_id do body DEVE ser igual ao do token autenticado
  // Impede que um usuĂĄrio crie preferĂŞncias de pagamento para outros usuĂĄrios
  if (!user_id || user_id.toString() !== authenticatedUserId.toString()) {
    console.warn(`đ¨ SEGURANĂA v167: UsuĂĄrio ${authenticatedUserId} tentou criar preferĂŞncia para user_id ${user_id}`)
    // Log de auditoria
    try {
      await DB.prepare(`
        CREATE TABLE IF NOT EXISTS audit_log (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          action TEXT NOT NULL,
          user_id INTEGER,
          details TEXT,
          ip_address TEXT,
          created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        )
      `).run()
      await DB.prepare(`
        INSERT INTO audit_log (action, user_id, details, ip_address, created_at)
        VALUES ('payment_user_spoof_attempt', ?, ?, ?, datetime('now'))
      `).bind(
        parseInt(authenticatedUserId),
        JSON.stringify({ authenticatedUserId, requestedUserId: user_id, plan }),
        c.req.header('cf-connecting-ip') || c.req.header('x-forwarded-for') || 'unknown'
      ).run()
    } catch (e) { /* audit nĂŁo ĂŠ crĂ­tico */ }
    return c.json({ error: 'VocĂŞ sĂł pode criar pagamentos para sua prĂłpria conta' }, 403)
  }
  
  try {
    // Buscar usuĂĄrio
    const user = await DB.prepare('SELECT email, name FROM users WHERE id = ?').bind(user_id).first() as any
    if (!user) {
      return c.json({ error: 'UsuĂĄrio nĂŁo encontrado' }, 404)
    }
    
    // â v69: Buscar planos do banco de dados (dinĂ˘mico)
    // â v162: Incluir discount_percent para aplicar desconto no pagamento
    const dbPlans = await DB.prepare(
      'SELECT id, name, price, duration_days, discount_percent FROM payment_plans WHERE is_active = 1 ORDER BY price ASC'
    ).all() as any
    
    // Mapear planos por tipo (mensal/anual/trimestral) baseado no nome ou duration_days
    const plans: Record<string, { title: string; price: number; originalPrice: number; discountPercent: number; days: number }> = {}
    
    if (dbPlans?.results?.length > 0) {
      for (const p of dbPlans.results) {
        let key = ''
        const nameLower = (p.name || '').toLowerCase()
        if (nameLower.includes('mensal') || (p.duration_days >= 28 && p.duration_days <= 31)) {
          key = 'mensal'
        } else if (nameLower.includes('trimestral') || (p.duration_days >= 80 && p.duration_days <= 100)) {
          key = 'trimestral'
        } else if (nameLower.includes('anual') || p.duration_days >= 360) {
          key = 'anual'
        }
        if (key && p.price > 0) {
          const discount = p.discount_percent || 0
          const finalPrice = discount > 0 
            ? Math.round(p.price * (1 - discount / 100) * 100) / 100 
            : p.price
          plans[key] = { 
            title: `IAprova ${p.name}`, 
            price: finalPrice,
            originalPrice: p.price,
            discountPercent: discount,
            days: p.duration_days 
          }
        }
      }
    }
    
    // Fallback se banco vazio
    if (Object.keys(plans).length === 0) {
      plans['mensal'] = { title: 'IAprova Premium Mensal', price: 29.90, originalPrice: 29.90, discountPercent: 0, days: 30 }
      plans['anual'] = { title: 'IAprova Premium Anual', price: 249.90, originalPrice: 249.90, discountPercent: 0, days: 365 }
    }
    
    const selectedPlan = plans[plan]
    if (!selectedPlan) {
      return c.json({ error: 'Plano invĂĄlido. Planos disponĂ­veis: ' + Object.keys(plans).join(', ') }, 400)
    }
    
    // Criar preferĂŞncia no Mercado Pago
    // â v162: unit_price jĂĄ inclui o desconto aplicado
    const itemTitle = selectedPlan.discountPercent > 0
      ? `${selectedPlan.title} (${selectedPlan.discountPercent}% OFF)`
      : selectedPlan.title
    
    console.log(`đ° v162: Plano ${plan} â original: R$${selectedPlan.originalPrice}, desconto: ${selectedPlan.discountPercent}%, final: R$${selectedPlan.price}`)
    
    const preference = {
      items: [{
        id: plan,
        title: itemTitle,
        description: `Assinatura ${plan === 'anual' ? 'Anual' : plan === 'trimestral' ? 'Trimestral' : 'Mensal'} do IAprova - PreparaĂ§ĂŁo Inteligente para Concursos`,
        quantity: 1,
        unit_price: selectedPlan.price,
        currency_id: 'BRL'
      }],
      payer: {
        email: user.email,
        name: user.name || 'UsuĂĄrio IAprova'
      },
      // â Habilitar todos os mĂŠtodos de pagamento
      payment_methods: {
        // Excluir apenas mĂŠtodos que nĂŁo queremos
        excluded_payment_types: [],
        excluded_payment_methods: [],
        // Parcelas: atĂŠ 12x para plano anual, atĂŠ 3x para mensal
        installments: plan === 'anual' ? 12 : 3,
        // Valor mĂ­nimo parcela
        default_installments: 1
      },
      back_urls: {
        success: `${APP_URL || 'https://iaprova.app'}/pagamento/sucesso`,
        failure: `${APP_URL || 'https://iaprova.app'}/pagamento/falha`,
        pending: `${APP_URL || 'https://iaprova.app'}/pagamento/pendente`
      },
      auto_return: 'approved',
      external_reference: JSON.stringify({ user_id, plan, days: selectedPlan.days }),
      notification_url: `${APP_URL || 'https://iaprova.app'}/api/webhook/mercadopago`,
      statement_descriptor: 'IAPROVA',
      // Habilitar binĂĄrio mode para processar pagamento sem pendĂŞncias
      binary_mode: false,
      expires: true,
      expiration_date_to: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString() // 24h
    }
    
    console.log(`đ Criando preferĂŞncia MP para usuĂĄrio ${user_id}, plano ${plan}...`)
    console.log(`đ Token (primeiros 20 chars): ${MP_ACCESS_TOKEN?.substring(0, 20)}...`)
    
    const response = await fetch('https://api.mercadopago.com/checkout/preferences', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${MP_ACCESS_TOKEN}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(preference)
    })
    
    const result = await response.json() as any
    
    console.log(`đŚ Resposta MP (status ${response.status}):`, JSON.stringify(result).substring(0, 500))
    
    if (!response.ok || result.error) {
      console.error('â Erro ao criar preferĂŞncia:', result)
      return c.json({ 
        error: result.message || result.error || 'Erro ao criar pagamento',
        details: result
      }, 500)
    }
    
    if (!result.init_point) {
      console.error('â Resposta sem init_point:', result)
      return c.json({ error: 'Resposta invĂĄlida do Mercado Pago - sem URL de pagamento' }, 500)
    }
    
    console.log(`â PreferĂŞncia criada: ${result.id} para usuĂĄrio ${user_id}`)
    console.log(`đ URL de pagamento: ${result.init_point}`)
    
    return c.json({
      success: true,
      preference_id: result.id,
      init_point: result.init_point, // URL para redirecionar o usuĂĄrio
      sandbox_init_point: result.sandbox_init_point
    })
  } catch (error: any) {
    console.error('Erro ao criar preferĂŞncia:', error)
    return c.json({ error: error.message }, 500)
  }
})

// â SEGURANĂA v145: FunĂ§ĂŁo para validar assinatura HMAC do webhook MercadoPago
async function validarWebhookHMAC(
  xSignature: string | null, 
  xRequestId: string | null, 
  dataId: string,
  webhookSecret: string
): Promise<boolean> {
  if (!xSignature || !webhookSecret) return false
  
  try {
    // Formato: ts=TIMESTAMP,v1=HASH
    const parts: Record<string, string> = {}
    xSignature.split(',').forEach(part => {
      const [key, ...valueParts] = part.trim().split('=')
      if (key && valueParts.length > 0) {
        parts[key] = valueParts.join('=')
      }
    })
    
    const ts = parts['ts']
    const v1 = parts['v1']
    
    if (!ts || !v1) {
      console.log('đ Assinatura webhook: formato invĂĄlido')
      return false
    }
    
    // Montar template de validaĂ§ĂŁo conforme documentaĂ§ĂŁo MP
    // template: id:[data_id];request-id:[x-request-id];ts:[ts];
    let manifest = ''
    if (dataId) manifest += `id:${dataId};`
    if (xRequestId) manifest += `request-id:${xRequestId};`
    manifest += `ts:${ts};`
    
    // Gerar HMAC-SHA256 com Web Crypto API (compatĂ­vel com Cloudflare Workers)
    const encoder = new TextEncoder()
    const keyData = encoder.encode(webhookSecret)
    const messageData = encoder.encode(manifest)
    
    const cryptoKey = await crypto.subtle.importKey(
      'raw', keyData, { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']
    )
    const signatureBuffer = await crypto.subtle.sign('HMAC', cryptoKey, messageData)
    
    // Converter para hex
    const hashArray = Array.from(new Uint8Array(signatureBuffer))
    const computedHash = hashArray.map(b => b.toString(16).padStart(2, '0')).join('')
    
    const isValid = computedHash === v1
    console.log(`đ ValidaĂ§ĂŁo HMAC webhook: ${isValid ? 'â VĂLIDA' : 'â INVĂLIDA'}`)
    
    return isValid
  } catch (e: any) {
    console.error('đ Erro ao validar HMAC webhook:', e.message)
    return false
  }
}

// â SEGURANĂA v145: FunĂ§ĂŁo auxiliar para ativar assinatura de forma segura (usada pelo webhook e verify-and-activate)
async function ativarAssinaturaSegura(
  DB: any, 
  userId: number, 
  plan: string, 
  days: number, 
  paymentId: string, 
  paymentAmount: number, 
  externalReference: string | null,
  payerEmail: string | null,
  paymentDetails: any,
  env: any
): Promise<{ success: boolean; expiresAt: string }> {
  const now = new Date()
  const expiresAt = new Date(now.getTime() + (days || 30) * 24 * 60 * 60 * 1000).toISOString()
  
  // Verificar se o usuĂĄrio existe e NĂO ĂŠ admin
  const user = await DB.prepare('SELECT id, email, name, is_premium, subscription_status, payment_id FROM users WHERE id = ?').bind(userId).first() as any
  if (!user) {
    throw new Error('UsuĂĄrio nĂŁo encontrado')
  }
  
  // â SEGURANĂA: Nunca alterar o admin via pagamento
  if (user.email === ADMIN_EMAIL) {
    console.log(`đĄď¸ SEGURANĂA: Tentativa de alterar admin via pagamento bloqueada`)
    throw new Error('OperaĂ§ĂŁo nĂŁo permitida')
  }
  
  // â SEGURANĂA: Verificar se este pagamento jĂĄ foi processado (idempotĂŞncia)
  if (user.payment_id === paymentId.toString()) {
    console.log(`âšď¸ Pagamento ${paymentId} jĂĄ foi processado para usuĂĄrio ${userId}`)
    return { success: true, expiresAt: user.subscription_expires_at || expiresAt }
  }
  
  // Ativar assinatura - NUNCA como admin, apenas como premium
  await DB.prepare(`
    UPDATE users SET 
      subscription_status = 'active',
      subscription_plan = ?,
      subscription_expires_at = ?,
      payment_id = ?,
      payment_date = ?,
      is_premium = 1,
      premium_expires_at = ?
    WHERE id = ? AND email != ?
  `).bind(plan, expiresAt, paymentId.toString(), now.toISOString(), expiresAt, userId, ADMIN_EMAIL).run()
  
  console.log(`â Assinatura ${plan} ativada para usuĂĄrio ${userId} atĂŠ ${expiresAt}`)
  
  // Enviar email de confirmaĂ§ĂŁo
  try {
    await sendPaymentConfirmationEmail(
      user.email,
      user.name || 'UsuĂĄrio',
      plan,
      paymentAmount,
      expiresAt,
      paymentId.toString(),
      env
    )
    console.log(`đ§ Email de confirmaĂ§ĂŁo enviado para ${user.email}`)
  } catch (emailError) {
    console.error('â ď¸ Erro ao enviar email de confirmaĂ§ĂŁo (nĂŁo crĂ­tico):', emailError)
  }
  
  // Registrar histĂłrico de pagamento
  try {
    await DB.prepare(`
      CREATE TABLE IF NOT EXISTS payment_history (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL,
        payment_id TEXT NOT NULL UNIQUE,
        plan TEXT NOT NULL,
        amount REAL,
        status TEXT NOT NULL,
        external_reference TEXT,
        payer_email TEXT,
        transaction_details TEXT,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
      )
    `).run()
    
    await DB.prepare(`
      INSERT OR REPLACE INTO payment_history (user_id, payment_id, plan, amount, status, external_reference, payer_email, transaction_details, created_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).bind(
      userId, 
      paymentId.toString(), 
      plan, 
      paymentAmount, 
      'approved',
      externalReference,
      payerEmail,
      JSON.stringify(paymentDetails || {}),
      now.toISOString()
    ).run()
    console.log(`đ HistĂłrico de pagamento registrado: payment_id=${paymentId}, user_id=${userId}`)
  } catch (e: any) {
    console.log('â ď¸ Erro ao registrar histĂłrico de pagamento:', e.message)
  }
  
  // â SEGURANĂA v145: Log de auditoria
  try {
    await DB.prepare(`
      CREATE TABLE IF NOT EXISTS audit_log (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        action TEXT NOT NULL,
        user_id INTEGER,
        details TEXT,
        ip_address TEXT,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
      )
    `).run()
    await DB.prepare(`
      INSERT INTO audit_log (action, user_id, details, created_at)
      VALUES ('payment_activated', ?, ?, datetime('now'))
    `).bind(userId, JSON.stringify({ plan, paymentId, amount: paymentAmount })).run()
  } catch (e: any) {
    // Log de auditoria nĂŁo ĂŠ crĂ­tico
  }
  
  return { success: true, expiresAt }
}

// Webhook para receber confirmaĂ§ĂŁo de pagamento do Mercado Pago
// â SEGURANĂA v148: ValidaĂ§ĂŁo HMAC obrigatĂłria + verificaĂ§ĂŁo completa

// GET: endpoint de health/teste do webhook (usado pelo painel MP para verificar conectividade)
app.get('/api/webhook/mercadopago', async (c) => {
  const { MP_WEBHOOK_SECRET } = c.env as any
  return c.json({
    status: 'ok',
    webhook: 'iaprova-mercadopago',
    hmac_validation: MP_WEBHOOK_SECRET ? 'enabled' : 'disabled - configure MP_WEBHOOK_SECRET!',
    timestamp: new Date().toISOString()
  })
})

app.post('/api/webhook/mercadopago', async (c) => {
  const { DB, MP_WEBHOOK_SECRET } = c.env as any
  
  // â SEGURANĂA v148: MP_WEBHOOK_SECRET ĂŠ OBRIGATĂRIO em produĂ§ĂŁo
  // Sem ele, qualquer pessoa pode chamar o webhook e ativar planos fraudulentos
  if (!MP_WEBHOOK_SECRET) {
    console.error('đ¨ SEGURANĂA CRĂTICA: MP_WEBHOOK_SECRET nĂŁo configurado!')
    console.error('   Configure com: npx wrangler pages secret put MP_WEBHOOK_SECRET')
    // Retornar 200 para nĂŁo causar retry loop no MP, mas NĂO processar
    return c.json({ received: true, processed: false, reason: 'Webhook desabilitado: secret nĂŁo configurado' })
  }
  
  try {
    const body = await c.req.json()
    console.log('đŚ Webhook Mercado Pago recebido:', JSON.stringify(body).substring(0, 500))
    
    // â SEGURANĂA v148: Validar assinatura HMAC â OBRIGATĂRIA
    const signature = c.req.header('x-signature')
    const requestId = c.req.header('x-request-id')
    const dataId = body.data?.id?.toString() || ''
    
    const isValidSignature = await validarWebhookHMAC(signature, requestId, dataId, MP_WEBHOOK_SECRET)
    if (!isValidSignature) {
      console.error('đ¨ SEGURANĂA: Webhook com assinatura INVĂLIDA rejeitado!')
      console.error(`   Signature: ${signature}`)
      console.error(`   Request ID: ${requestId}`)
      console.error(`   Data ID: ${dataId}`)
      // Registrar tentativa de fraude
      try {
        await DB.prepare(`
          CREATE TABLE IF NOT EXISTS audit_log (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            action TEXT NOT NULL,
            user_id INTEGER,
            details TEXT,
            ip_address TEXT,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
          )
        `).run()
        await DB.prepare(`
          INSERT INTO audit_log (action, details, ip_address, created_at)
          VALUES ('webhook_invalid_signature', ?, ?, datetime('now'))
        `).bind(
          JSON.stringify({ signature, requestId, dataId, body: JSON.stringify(body).substring(0, 200) }),
          c.req.header('cf-connecting-ip') || c.req.header('x-forwarded-for') || 'unknown'
        ).run()
      } catch (e) { /* audit nĂŁo ĂŠ crĂ­tico */ }
      return c.json({ error: 'Assinatura invĂĄlida' }, 401)
    }
    
    console.log('â Assinatura HMAC do webhook validada com sucesso')
    
    // Verificar tipo de notificaĂ§ĂŁo
    if (body.type !== 'payment' && body.action !== 'payment.created' && body.action !== 'payment.updated') {
      console.log('NotificaĂ§ĂŁo ignorada:', body.type, body.action)
      return c.json({ received: true })
    }
    
    // â SEGURANĂA v147: Obter token MP com refresh automĂĄtico
    let MP_ACCESS_TOKEN: string
    try {
      MP_ACCESS_TOKEN = await getValidMPToken(c.env)
    } catch {
      console.error('đ¨ NĂŁo foi possĂ­vel obter token MP vĂĄlido!')
      return c.json({ error: 'ConfiguraĂ§ĂŁo incompleta' }, 500)
    }
    
    // Buscar detalhes do pagamento na API do Mercado Pago
    const paymentId = body.data?.id || body.id
    if (!paymentId) {
      console.log('Payment ID nĂŁo encontrado')
      return c.json({ received: true })
    }
    
    const paymentResponse = await fetch(`https://api.mercadopago.com/v1/payments/${paymentId}`, {
      headers: { 'Authorization': `Bearer ${MP_ACCESS_TOKEN}` }
    })
    
    if (!paymentResponse.ok) {
      console.error(`đ¨ Erro ao consultar pagamento ${paymentId}: ${paymentResponse.status}`)
      return c.json({ error: 'Erro ao consultar pagamento' }, 500)
    }
    
    const payment = await paymentResponse.json() as any
    console.log('đł Detalhes do pagamento:', JSON.stringify(payment).substring(0, 500))
    
    // â SEGURANĂA: Verificar se pagamento foi aprovado - CONFIAR APENAS na API do MP
    if (payment.status !== 'approved') {
      console.log(`Pagamento ${paymentId} nĂŁo aprovado: ${payment.status}`)
      return c.json({ received: true, status: payment.status })
    }
    
    // â SEGURANĂA: Extrair dados do external_reference (que nĂłs mesmos criamos na preferĂŞncia)
    let userData
    try {
      userData = JSON.parse(payment.external_reference)
    } catch {
      console.error('đ¨ external_reference invĂĄlido:', payment.external_reference)
      return c.json({ error: 'ReferĂŞncia invĂĄlida' }, 400)
    }
    
    // â SEGURANĂA: Validar que user_id e plan existem no external_reference
    if (!userData?.user_id || !userData?.plan) {
      console.error('đ¨ Dados incompletos no external_reference:', userData)
      return c.json({ error: 'Dados de referĂŞncia incompletos' }, 400)
    }
    
    const { user_id, plan, days } = userData
    
    // â SEGURANĂA: Usar funĂ§ĂŁo centralizada e segura para ativar assinatura
    const result = await ativarAssinaturaSegura(
      DB, user_id, plan, days || 30, paymentId.toString(),
      payment.transaction_amount,
      payment.external_reference,
      payment.payer?.email || null,
      {
        status_detail: payment.status_detail,
        payment_method: payment.payment_method_id,
        date_approved: payment.date_approved,
        date_created: payment.date_created,
        source: 'webhook'
      },
      c.env
    )
    
    return c.json({ 
      received: true, 
      processed: true,
      user_id,
      plan,
      expires_at: result.expiresAt
    })
  } catch (error: any) {
    console.error('Erro no webhook:', error)
    return c.json({ error: 'Erro ao processar webhook' }, 500)
  }
})

// â CORREĂĂO v11: Endpoint para histĂłrico de pagamentos de um usuĂĄrio
app.get('/api/user/:user_id/payments', async (c) => {
  const { DB } = c.env
  const userId = c.req.param('user_id')
  // â v154 SEGURANĂA: Usar token assinado em vez de X-User-ID
  const requestUserId = await getAuthenticatedUserId(c)
  
  // Verificar se ĂŠ o prĂłprio usuĂĄrio ou admin
  if (!requestUserId || (requestUserId !== userId && !await isAdmin(c))) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    // Criar tabela se nĂŁo existir
    await DB.prepare(`
      CREATE TABLE IF NOT EXISTS payment_history (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL,
        payment_id TEXT NOT NULL UNIQUE,
        plan TEXT NOT NULL,
        amount REAL,
        status TEXT NOT NULL,
        external_reference TEXT,
        payer_email TEXT,
        transaction_details TEXT,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
      )
    `).run()
    
    // Buscar histĂłrico de pagamentos
    const payments = await DB.prepare(`
      SELECT 
        id, payment_id, plan, amount, status, payer_email, 
        created_at, transaction_details
      FROM payment_history 
      WHERE user_id = ?
      ORDER BY created_at DESC
    `).bind(userId).all()
    
    // Buscar tambĂŠm o pagamento atual do usuĂĄrio (se existir)
    const user = await DB.prepare(`
      SELECT payment_id, payment_date, subscription_plan, subscription_status, subscription_expires_at
      FROM users WHERE id = ?
    `).bind(userId).first() as any
    
    return c.json({
      success: true,
      payments: payments.results || [],
      current_subscription: user ? {
        payment_id: user.payment_id,
        payment_date: user.payment_date,
        plan: user.subscription_plan,
        status: user.subscription_status,
        expires_at: user.subscription_expires_at
      } : null
    })
  } catch (error: any) {
    console.error('Erro ao buscar histĂłrico de pagamentos:', error)
    return c.json({ error: 'Erro ao buscar pagamentos' }, 500)
  }
})

// â CORREĂĂO v11: Endpoint admin para listar TODOS os pagamentos
app.get('/api/admin/payments', async (c) => {
  const { DB } = c.env
  
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    // Criar tabela se nĂŁo existir
    await DB.prepare(`
      CREATE TABLE IF NOT EXISTS payment_history (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL,
        payment_id TEXT NOT NULL UNIQUE,
        plan TEXT NOT NULL,
        amount REAL,
        status TEXT NOT NULL,
        external_reference TEXT,
        payer_email TEXT,
        transaction_details TEXT,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
      )
    `).run()
    
    // Buscar todos os pagamentos com dados do usuĂĄrio
    const payments = await DB.prepare(`
      SELECT 
        ph.id, ph.user_id, ph.payment_id, ph.plan, ph.amount, ph.status, 
        ph.payer_email, ph.created_at, ph.external_reference,
        u.name as user_name, u.email as user_email
      FROM payment_history ph
      LEFT JOIN users u ON u.id = ph.user_id
      ORDER BY ph.created_at DESC
    `).all()
    
    // Buscar tambĂŠm usuĂĄrios com assinatura ativa (podem nĂŁo ter payment_history)
    const activeUsers = await DB.prepare(`
      SELECT id, name, email, payment_id, payment_date, subscription_plan, subscription_status
      FROM users 
      WHERE subscription_status = 'active' OR is_premium = 1
    `).all()
    
    return c.json({
      success: true,
      payment_history: payments.results || [],
      active_subscriptions: activeUsers.results || []
    })
  } catch (error: any) {
    console.error('Erro ao listar pagamentos:', error)
    return c.json({ error: 'Erro ao listar pagamentos' }, 500)
  }
})

// â v148: DiagnĂłstico da configuraĂ§ĂŁo de pagamentos (admin only)
// Verifica se MP_ACCESS_TOKEN, MP_WEBHOOK_SECRET e webhook estĂŁo configurados corretamente
app.get('/api/admin/payment-health', async (c) => {
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403)
  }

  const { DB, MP_ACCESS_TOKEN, MP_WEBHOOK_SECRET, MP_CLIENT_ID, MP_CLIENT_SECRET } = c.env as any

  const checks: Record<string, { ok: boolean; message: string }> = {}

  // 1. Verificar MP_WEBHOOK_SECRET
  checks.webhook_secret = MP_WEBHOOK_SECRET
    ? { ok: true, message: 'MP_WEBHOOK_SECRET configurado â' }
    : { ok: false, message: 'â MP_WEBHOOK_SECRET NĂO configurado â webhook DESABILITADO!' }

  // 2. Verificar token de acesso
  checks.access_token = MP_ACCESS_TOKEN
    ? { ok: true, message: 'MP_ACCESS_TOKEN presente â' }
    : { ok: false, message: 'â MP_ACCESS_TOKEN nĂŁo configurado' }

  // 3. Testar se o token MP realmente funciona chamando a API
  if (MP_ACCESS_TOKEN || MP_CLIENT_ID) {
    try {
      const token = await getValidMPToken(c.env)
      const testResp = await fetch('https://api.mercadopago.com/v1/payment_methods', {
        headers: { 'Authorization': `Bearer ${token}` }
      })
      checks.mp_api_connection = testResp.ok
        ? { ok: true, message: `Token MP vĂĄlido e API acessĂ­vel â (status ${testResp.status})` }
        : { ok: false, message: `â Token MP invĂĄlido ou API indisponĂ­vel (status ${testResp.status})` }
    } catch (e: any) {
      checks.mp_api_connection = { ok: false, message: `â Erro ao testar API MP: ${e.message}` }
    }
  } else {
    checks.mp_api_connection = { ok: false, message: 'â Sem credenciais MP para testar' }
  }

  // 4. Verificar OAuth MP (refresh automĂĄtico)
  checks.mp_oauth = (MP_CLIENT_ID && MP_CLIENT_SECRET)
    ? { ok: true, message: 'MP_CLIENT_ID e MP_CLIENT_SECRET configurados â (refresh automĂĄtico ativo)' }
    : { ok: true, message: 'âšď¸ Usando MP_ACCESS_TOKEN fixo (sem refresh automĂĄtico)' }

  // 5. Verificar planos ativos no banco
  try {
    const plans = await DB.prepare('SELECT COUNT(*) as count FROM payment_plans WHERE is_active = 1').first() as any
    checks.payment_plans = (plans?.count > 0)
      ? { ok: true, message: `${plans.count} plano(s) ativo(s) no banco â` }
      : { ok: false, message: 'â Nenhum plano ativo no banco â pagamentos sem plano configurado' }
  } catch {
    checks.payment_plans = { ok: false, message: 'â Tabela payment_plans nĂŁo existe ou erro ao consultar' }
  }

  // 6. Verificar tabela payment_history
  try {
    const hist = await DB.prepare('SELECT COUNT(*) as count FROM payment_history').first() as any
    checks.payment_history = { ok: true, message: `Tabela payment_history existe com ${hist?.count || 0} registros â` }
  } catch {
    checks.payment_history = { ok: false, message: 'â ď¸ Tabela payment_history ainda nĂŁo criada (serĂĄ criada no primeiro pagamento)' }
  }

  // 7. Verificar tabela audit_log
  try {
    const audit = await DB.prepare('SELECT COUNT(*) as count FROM audit_log').first() as any
    checks.audit_log = { ok: true, message: `Tabela audit_log existe com ${audit?.count || 0} registros â` }
  } catch {
    checks.audit_log = { ok: false, message: 'â ď¸ Tabela audit_log ainda nĂŁo criada (serĂĄ criada no primeiro evento)' }
  }

  const allOk = Object.values(checks).every(c => c.ok)
  const criticalFail = !checks.webhook_secret.ok || !checks.access_token.ok || !checks.mp_api_connection?.ok

  return c.json({
    status: criticalFail ? 'critical' : (allOk ? 'healthy' : 'warnings'),
    summary: criticalFail
      ? 'đ¨ ConfiguraĂ§ĂŁo crĂ­tica ausente â pagamentos podem NĂO funcionar!'
      : (allOk ? 'â Sistema de pagamentos configurado corretamente' : 'â ď¸ Algumas configuraĂ§Ăľes precisam de atenĂ§ĂŁo'),
    checks,
    webhook_url: 'https://iaprova.pages.dev/api/webhook/mercadopago',
    instructions: {
      configure_secrets: [
        'npx wrangler pages secret put MP_ACCESS_TOKEN --project-name iaprova',
        'npx wrangler pages secret put MP_WEBHOOK_SECRET --project-name iaprova',
        'npx wrangler pages secret put MP_CLIENT_ID --project-name iaprova',
        'npx wrangler pages secret put MP_CLIENT_SECRET --project-name iaprova',
      ],
      list_secrets: 'npx wrangler pages secret list --project-name iaprova',
      mp_webhook_config: 'Configure a URL do webhook no painel MP: https://www.mercadopago.com.br/developers/panel/app'
    }
  })
})

// Verificar status de pagamento
// â SEGURANĂA v145: Requer autenticaĂ§ĂŁo e MP_ACCESS_TOKEN
app.get('/api/mercadopago/payment-status/:payment_id', async (c) => {
  const paymentId = c.req.param('payment_id')
  // â v154 SEGURANĂA: Usar token assinado
  const requestUserId = await getAuthenticatedUserId(c)
  
  // â SEGURANĂA: Requer usuĂĄrio autenticado
  if (!requestUserId) {
    return c.json({ error: 'AutenticaĂ§ĂŁo obrigatĂłria' }, 401)
  }
  
  // â v147: Obter token com refresh automĂĄtico
  let MP_ACCESS_TOKEN: string
  try {
    MP_ACCESS_TOKEN = await getValidMPToken(c.env)
  } catch {
    return c.json({ error: 'ServiĂ§o de pagamento nĂŁo configurado' }, 500)
  }
  
  try {
    const response = await fetch(`https://api.mercadopago.com/v1/payments/${paymentId}`, {
      headers: { 'Authorization': `Bearer ${MP_ACCESS_TOKEN}` }
    })
    
    if (!response.ok) {
      return c.json({ error: 'Pagamento nĂŁo encontrado' }, 404)
    }
    
    const payment = await response.json() as any
    
    // â SEGURANĂA: Verificar que o pagamento pertence ao usuĂĄrio que estĂĄ consultando
    let isOwner = false
    try {
      const refData = JSON.parse(payment.external_reference || '{}')
      isOwner = refData.user_id?.toString() === requestUserId.toString()
    } catch { /* ignore parse errors */ }
    
    if (!isOwner && !await isAdmin(c)) {
      return c.json({ error: 'Acesso negado' }, 403)
    }
    
    return c.json({
      status: payment.status,
      status_detail: payment.status_detail,
      amount: payment.transaction_amount,
      date: payment.date_approved || payment.date_created
    })
  } catch (error: any) {
    return c.json({ error: error.message }, 500)
  }
})

// Callback de retorno apĂłs pagamento
// â SEGURANĂA v145: ValidaĂ§ĂŁo completa via API do MP (nĂŁo confiar em query params)
app.get('/pagamento/sucesso', async (c) => {
  const { DB } = c.env as any
  const paymentId = c.req.query('payment_id')
  const status = c.req.query('status')
  const externalReference = c.req.query('external_reference')
  
  console.log(`đ° Retorno de pagamento: ${paymentId}, status: ${status}, ref: ${externalReference}`)
  
  // â SEGURANĂA v147: Ativar assinatura SOMENTE se podemos verificar via API do MP
  let MP_ACCESS_TOKEN: string | null = null
  try {
    MP_ACCESS_TOKEN = await getValidMPToken(c.env)
  } catch {
    console.warn('â ď¸ Callback sem token MP - nĂŁo pode verificar pagamento!')
  }
  
  if (paymentId && MP_ACCESS_TOKEN) {
    try {
      // SEMPRE consultar a API do MP para confirmar status real
      const paymentResponse = await fetch(`https://api.mercadopago.com/v1/payments/${paymentId}`, {
        headers: { 'Authorization': `Bearer ${MP_ACCESS_TOKEN}` }
      })
      
      if (paymentResponse.ok) {
        const payment = await paymentResponse.json() as any
        console.log('đł Pagamento verificado via API MP:', payment.status)
        
        // â SEGURANĂA: CONFIAR APENAS no status da API do MP, nĂŁo no query param
        if (payment.status === 'approved' && payment.external_reference) {
          let userData
          try {
            userData = JSON.parse(payment.external_reference)
          } catch {
            console.error('external_reference invĂĄlido no callback:', payment.external_reference)
          }
          
          if (userData?.user_id) {
            try {
              await ativarAssinaturaSegura(
                DB, userData.user_id, userData.plan || 'mensal', userData.days || 30,
                paymentId.toString(),
                payment.transaction_amount,
                payment.external_reference,
                payment.payer?.email || null,
                {
                  status_detail: payment.status_detail,
                  payment_method: payment.payment_method_id,
                  date_approved: payment.date_approved,
                  source: 'callback'
                },
                c.env
              )
              console.log(`â Assinatura ativada via callback para usuĂĄrio ${userData.user_id}`)
            } catch (err: any) {
              console.log(`âšď¸ Callback: ${err.message}`)
            }
          }
        } else {
          console.log(`â ď¸ Pagamento ${paymentId} nĂŁo aprovado via API MP: ${payment.status} (query param dizia: ${status})`)
        }
      } else {
        console.error(`â ď¸ Erro ao verificar pagamento via API MP: ${paymentResponse.status}`)
      }
    } catch (error) {
      console.error('Erro ao ativar assinatura no callback:', error)
    }
  } else if (!MP_ACCESS_TOKEN) {
    console.warn('â ď¸ Callback sem token MP vĂĄlido - nĂŁo pode verificar pagamento!')
  }
  
  // Redirecionar para o app com parĂ˘metros
  return c.redirect(`/?payment=success&payment_id=${paymentId}&status=${status}`)
})

// â SEGURANĂA v145: Endpoint para verificar e ativar pagamento (com validaĂ§ĂŁo completa via API MP)
app.post('/api/mercadopago/verify-and-activate/:payment_id', async (c) => {
  const { DB } = c.env as any
  const paymentId = c.req.param('payment_id')
  // â v154 SEGURANĂA: Usar token assinado
  const requestUserId = await getAuthenticatedUserId(c)
  
  // â SEGURANĂA: Requer usuĂĄrio autenticado
  if (!requestUserId) {
    console.warn('đ¨ SEGURANĂA v154: verify-and-activate chamado sem token vĂĄlido')
    return c.json({ error: 'AutenticaĂ§ĂŁo obrigatĂłria' }, 401)
  }
  
  // â SEGURANĂA v147: Obter token com refresh automĂĄtico
  let MP_ACCESS_TOKEN: string
  try {
    MP_ACCESS_TOKEN = await getValidMPToken(c.env)
  } catch {
    console.error('đ¨ NĂŁo foi possĂ­vel obter token MP vĂĄlido!')
    return c.json({ error: 'ServiĂ§o de pagamento nĂŁo configurado' }, 500)
  }
  
  console.log(`đ Verificando pagamento ${paymentId} para usuĂĄrio ${requestUserId}`)
  
  try {
    // â SEGURANĂA: Consultar pagamento DIRETAMENTE na API do Mercado Pago
    const paymentResponse = await fetch(`https://api.mercadopago.com/v1/payments/${paymentId}`, {
      headers: { 'Authorization': `Bearer ${MP_ACCESS_TOKEN}` }
    })
    
    if (!paymentResponse.ok) {
      console.error(`đ¨ Erro ao consultar pagamento ${paymentId}: ${paymentResponse.status}`)
      return c.json({ error: 'Pagamento nĂŁo encontrado ou erro ao consultar', status: paymentResponse.status }, 400)
    }
    
    const payment = await paymentResponse.json() as any
    
    if (payment.status !== 'approved') {
      return c.json({ 
        error: 'Pagamento nĂŁo aprovado', 
        status: payment.status,
        status_detail: payment.status_detail 
      }, 400)
    }
    
    // â SEGURANĂA: Extrair e validar external_reference
    let userData
    try {
      userData = JSON.parse(payment.external_reference)
    } catch {
      console.error('đ¨ external_reference invĂĄlido no verify-and-activate:', payment.external_reference)
      return c.json({ error: 'ReferĂŞncia de pagamento invĂĄlida' }, 400)
    }
    
    // â SEGURANĂA CRĂTICA: Verificar que o pagamento pertence ao usuĂĄrio que estĂĄ solicitando
    const targetUserId = userData?.user_id
    if (!targetUserId) {
      console.error('đ¨ user_id nĂŁo encontrado no external_reference')
      return c.json({ error: 'Dados de pagamento incompletos' }, 400)
    }
    
    // O userId do external_reference DEVE ser igual ao userId do header (quem estĂĄ solicitando)
    if (targetUserId.toString() !== requestUserId.toString()) {
      console.warn(`đ¨ SEGURANĂA: UsuĂĄrio ${requestUserId} tentou ativar pagamento ${paymentId} que pertence ao usuĂĄrio ${targetUserId}`)
      // Log de auditoria
      try {
        await DB.prepare(`
          CREATE TABLE IF NOT EXISTS audit_log (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            action TEXT NOT NULL,
            user_id INTEGER,
            details TEXT,
            ip_address TEXT,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
          )
        `).run()
        await DB.prepare(`
          INSERT INTO audit_log (action, user_id, details, ip_address, created_at)
          VALUES ('payment_user_mismatch', ?, ?, ?, datetime('now'))
        `).bind(
          parseInt(requestUserId),
          JSON.stringify({ paymentId, requestUserId, targetUserId }),
          c.req.header('cf-connecting-ip') || c.req.header('x-forwarded-for') || 'unknown'
        ).run()
      } catch (e) { /* audit nĂŁo ĂŠ crĂ­tico */ }
      return c.json({ error: 'Este pagamento nĂŁo pertence a este usuĂĄrio' }, 403)
    }
    
    const { plan, days } = userData
    
    // â SEGURANĂA: Usar funĂ§ĂŁo centralizada e segura para ativar
    const result = await ativarAssinaturaSegura(
      DB, targetUserId, plan || 'mensal', days || 30, paymentId.toString(),
      payment.transaction_amount,
      payment.external_reference,
      payment.payer?.email || null,
      {
        status_detail: payment.status_detail,
        payment_method: payment.payment_method_id,
        date_approved: payment.date_approved,
        source: 'verify-and-activate'
      },
      c.env
    )
    
    // Buscar usuĂĄrio atualizado
    const user = await DB.prepare('SELECT id, email, name, subscription_status, subscription_plan, is_premium FROM users WHERE id = ?').bind(targetUserId).first()
    
    return c.json({ 
      success: true, 
      message: 'Assinatura ativada com sucesso!',
      user,
      expires_at: result.expiresAt
    })
  } catch (error: any) {
    console.error('Erro ao verificar pagamento:', error)
    return c.json({ error: error.message || 'Erro ao verificar pagamento' }, 500)
  }
})

