// â v86-fix: Endpoint de Analytics completo para o admin
app.get('/api/admin/analytics', async (c) => {
  const { DB } = c.env
  
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    // Helper: query segura que nĂŁo quebra se tabela nĂŁo existir
    const safeQuery = async (query: string, params: any[] = []) => {
      try {
        const stmt = DB.prepare(query)
        const bound = params.length > 0 ? stmt.bind(...params) : stmt
        return await bound.all()
      } catch (e: any) {
        console.warn(`â ď¸ Analytics query falhou: ${e.message?.substring(0, 100)}`)
        return { results: [] }
      }
    }
    const safeFirst = async (query: string, params: any[] = []) => {
      try {
        const stmt = DB.prepare(query)
        const bound = params.length > 0 ? stmt.bind(...params) : stmt
        return await bound.first() as any
      } catch (e: any) {
        console.warn(`â ď¸ Analytics query falhou: ${e.message?.substring(0, 100)}`)
        return null
      }
    }

    // 1. Totais de conteĂşdo por tipo - combinar conteudo_estudo + materiais_salvos
    const totaisCE = await safeQuery(`SELECT tipo, COUNT(*) as total FROM conteudo_estudo GROUP BY tipo`)
    const totaisMS = await safeQuery(`SELECT tipo, COUNT(*) as total FROM materiais_salvos GROUP BY tipo`)
    
    // Mesclar totais das duas tabelas
    const totaisMap: Record<string, number> = {}
    for (const r of (totaisCE.results || [])) { totaisMap[(r as any).tipo] = (totaisMap[(r as any).tipo] || 0) + ((r as any).total || 0) }
    for (const r of (totaisMS.results || [])) { totaisMap[(r as any).tipo] = (totaisMap[(r as any).tipo] || 0) + ((r as any).total || 0) }
    const totaisTipo = Object.entries(totaisMap).map(([tipo, total]) => ({ tipo, total }))
    
    // 2. Total de flashcards (de conteudo_estudo tipo 'flashcards')
    const flashcardsTotal = await safeFirst(`SELECT COUNT(*) as total FROM conteudo_estudo WHERE tipo = 'flashcards'`)
    
    // 3. Total de simulados
    const simuladosTotal = await safeFirst(`SELECT COUNT(*) as total FROM simulados_historico`)
    
    // 4. Total de revisĂľes
    const revisoesTotalCE = await safeFirst(`SELECT COUNT(*) as total FROM conteudo_estudo WHERE tipo = 'revisao'`)
    const revisoesTotalMS = await safeFirst(`SELECT COUNT(*) as total FROM materiais_salvos WHERE tipo = 'revisao'`)
    const revisoesTotal = (revisoesTotalCE?.total || 0) + (revisoesTotalMS?.total || 0)
    
    // 5. ConteĂşdos por dia (Ăşltimos 30 dias) - combinar ambas tabelas
    const conteudoPorDiaCE = await safeQuery(`
      SELECT DATE(created_at) as dia, tipo, COUNT(*) as total
      FROM conteudo_estudo
      WHERE created_at >= datetime('now', '-30 days')
      GROUP BY dia, tipo ORDER BY dia ASC
    `)
    const conteudoPorDiaMS = await safeQuery(`
      SELECT DATE(created_at) as dia, tipo, COUNT(*) as total
      FROM materiais_salvos
      WHERE created_at >= datetime('now', '-30 days')
      GROUP BY dia, tipo ORDER BY dia ASC
    `)
    const conteudoPorDia = [...(conteudoPorDiaCE.results || []), ...(conteudoPorDiaMS.results || [])]
    
    // 6. Flashcards por dia (de conteudo_estudo)
    const flashcardsPorDiaRes = await safeQuery(`
      SELECT DATE(created_at) as dia, COUNT(*) as total
      FROM conteudo_estudo
      WHERE tipo = 'flashcards' AND created_at >= datetime('now', '-30 days')
      GROUP BY dia ORDER BY dia ASC
    `)
    
    // 7. Simulados por dia
    const simuladosPorDiaRes = await safeQuery(`
      SELECT DATE(created_at) as dia, COUNT(*) as total
      FROM simulados_historico
      WHERE created_at >= datetime('now', '-30 days')
      GROUP BY dia ORDER BY dia ASC
    `)
    
    // 8. ExercĂ­cios por dia
    const exerciciosPorDiaCE = await safeQuery(`
      SELECT DATE(created_at) as dia, COUNT(*) as total
      FROM conteudo_estudo
      WHERE tipo = 'exercicios' AND created_at >= datetime('now', '-30 days')
      GROUP BY dia ORDER BY dia ASC
    `)
    const exerciciosPorDiaMS = await safeQuery(`
      SELECT DATE(created_at) as dia, COUNT(*) as total
      FROM materiais_salvos
      WHERE tipo = 'exercicios' AND created_at >= datetime('now', '-30 days')
      GROUP BY dia ORDER BY dia ASC
    `)
    const exerciciosPorDia = [...(exerciciosPorDiaCE.results || []), ...(exerciciosPorDiaMS.results || [])]
    
    // 9. Feedbacks: estatĂ­sticas (user_feedbacks ĂŠ a tabela correta)
    const feedbackStats = await safeFirst(`
      SELECT 
        COUNT(*) as total,
        ROUND(AVG(CASE WHEN rating > 0 THEN rating ELSE NULL END), 1) as media_geral,
        SUM(CASE WHEN is_read = 0 THEN 1 ELSE 0 END) as nao_lidos,
        SUM(CASE WHEN rating >= 4 OR feedback_type = 'praise' OR feedback_type = 'bom' THEN 1 ELSE 0 END) as positivos
      FROM user_feedbacks
    `)
    
    // 10. Feedbacks por tipo
    const feedbackPorTipoRes = await safeQuery(`
      SELECT feedback_type, COUNT(*) as total
      FROM user_feedbacks
      GROUP BY feedback_type
      ORDER BY total DESC
    `)
    
    // 11. Lista de feedbacks (Ăşltimos 100)
    const feedbackListaRes = await safeQuery(`
      SELECT 
        f.id,
        f.feedback_type,
        f.rating,
        f.message,
        f.page_context,
        f.is_read,
        f.created_at,
        u.name as user_name,
        u.email as user_email
      FROM user_feedbacks f
      LEFT JOIN users u ON f.user_id = u.id
      ORDER BY f.created_at DESC
      LIMIT 100
    `)
    
    return c.json({
      conteudos: {
        totais: totaisTipo,
        flashcards_total: flashcardsTotal?.total || 0,
        simulados_total: simuladosTotal?.total || 0,
        revisoes_total: revisoesTotal,
        por_dia: conteudoPorDia,
        flashcards_por_dia: flashcardsPorDiaRes.results || [],
        simulados_por_dia: simuladosPorDiaRes.results || [],
        exercicios_por_dia: exerciciosPorDia
      },
      feedbacks: {
        stats: {
          total: feedbackStats?.total || 0,
          media_geral: feedbackStats?.media_geral || '-',
          nao_lidos: feedbackStats?.nao_lidos || 0,
          positivos: feedbackStats?.positivos || 0
        },
        por_tipo: feedbackPorTipoRes.results || [],
        lista: feedbackListaRes.results || []
      },
      chat_lilu: await (async () => {
        try {
          const chatTotal = await safeFirst(`SELECT COUNT(*) as total FROM chat_interactions`)
          const chatUsuarios = await safeFirst(`SELECT COUNT(DISTINCT user_id) as total FROM chat_interactions`)
          const chatPorDiaRes = await safeQuery(`
            SELECT DATE(created_at) as dia, COUNT(*) as total
            FROM chat_interactions
            WHERE created_at >= datetime('now', '-30 days')
            GROUP BY dia ORDER BY dia ASC
          `)
          return {
            total: chatTotal?.total || 0,
            usuarios_unicos: chatUsuarios?.total || 0,
            por_dia: chatPorDiaRes.results || []
          }
        } catch (e) {
          return { total: 0, usuarios_unicos: 0, por_dia: [] }
        }
      })(),
      atualizado_em: new Date().toISOString(),
      user_growth: await (async () => {
        try {
          // Total de usuĂĄrios
          const totalU = await safeFirst(`SELECT COUNT(*) as total FROM users`)
          
          // Crescimento diĂĄrio (Ăşltimos 30 dias)
          // Conta novos registros por dia e calcula acumulado
          const dailyRes = await safeQuery(`
            WITH RECURSIVE dates(dia) AS (
              SELECT DATE('now', '-29 days')
              UNION ALL
              SELECT DATE(dia, '+1 day') FROM dates WHERE dia < DATE('now')
            ),
            daily_counts AS (
              SELECT DATE(created_at) as dia, COUNT(*) as novos
              FROM users
              WHERE created_at IS NOT NULL AND DATE(created_at) >= DATE('now', '-29 days')
              GROUP BY DATE(created_at)
            ),
            base_count AS (
              SELECT COUNT(*) as cnt FROM users 
              WHERE created_at IS NULL OR DATE(created_at) < DATE('now', '-29 days')
            )
            SELECT 
              d.dia,
              COALESCE(dc.novos, 0) as novos,
              (SELECT cnt FROM base_count) + 
                (SELECT COALESCE(SUM(COALESCE(dc2.novos, 0)), 0) 
                 FROM dates d2 LEFT JOIN daily_counts dc2 ON d2.dia = dc2.dia 
                 WHERE d2.dia <= d.dia) as total_acumulado
            FROM dates d
            LEFT JOIN daily_counts dc ON d.dia = dc.dia
            ORDER BY d.dia ASC
          `)
          
          // Crescimento mensal (Ăşltimos 12 meses)
          const monthlyRes = await safeQuery(`
            WITH RECURSIVE months(mes) AS (
              SELECT strftime('%Y-%m', 'now', '-11 months')
              UNION ALL
              SELECT strftime('%Y-%m', mes || '-01', '+1 month') FROM months 
              WHERE mes < strftime('%Y-%m', 'now')
            ),
            monthly_counts AS (
              SELECT strftime('%Y-%m', created_at) as mes, COUNT(*) as novos
              FROM users
              WHERE created_at IS NOT NULL AND strftime('%Y-%m', created_at) >= strftime('%Y-%m', 'now', '-11 months')
              GROUP BY strftime('%Y-%m', created_at)
            ),
            base_count AS (
              SELECT COUNT(*) as cnt FROM users 
              WHERE created_at IS NULL OR strftime('%Y-%m', created_at) < strftime('%Y-%m', 'now', '-11 months')
            )
            SELECT 
              m.mes,
              COALESCE(mc.novos, 0) as novos,
              (SELECT cnt FROM base_count) + 
                (SELECT COALESCE(SUM(COALESCE(mc2.novos, 0)), 0) 
                 FROM months m2 LEFT JOIN monthly_counts mc2 ON m2.mes = mc2.mes 
                 WHERE m2.mes <= m.mes) as total_acumulado
            FROM months m
            LEFT JOIN monthly_counts mc ON m.mes = mc.mes
            ORDER BY m.mes ASC
          `)
          
          // Crescimento anual
          const yearlyRes = await safeQuery(`
            WITH yearly_counts AS (
              SELECT strftime('%Y', created_at) as ano, COUNT(*) as novos
              FROM users
              WHERE created_at IS NOT NULL
              GROUP BY strftime('%Y', created_at)
              ORDER BY ano ASC
            ),
            null_count AS (
              SELECT COUNT(*) as cnt FROM users WHERE created_at IS NULL
            )
            SELECT 
              ano,
              novos,
              (SELECT cnt FROM null_count) + 
                (SELECT SUM(yc2.novos) FROM yearly_counts yc2 WHERE yc2.ano <= yc.ano) as total_acumulado
            FROM yearly_counts yc
            ORDER BY ano ASC
          `)
          
          return {
            total: totalU?.total || 0,
            daily: (dailyRes.results || []).map((r: any) => ({ dia: r.dia, novos: r.novos || 0, total_acumulado: r.total_acumulado || 0 })),
            monthly: (monthlyRes.results || []).map((r: any) => ({ mes: r.mes, novos: r.novos || 0, total_acumulado: r.total_acumulado || 0 })),
            yearly: (yearlyRes.results || []).map((r: any) => ({ ano: r.ano, novos: r.novos || 0, total_acumulado: r.total_acumulado || 0 }))
          }
        } catch (e) {
          console.warn('â ď¸ Erro ao buscar user_growth:', e)
          return { total: 0, daily: [], monthly: [], yearly: [] }
        }
      })()
    })
    
  } catch (error: any) {
    console.error('Erro ao carregar analytics:', error)
    return c.json({ error: 'Erro ao carregar analytics: ' + error.message }, 500)
  }
})

// â CORREĂĂO v13: Endpoint admin para listar todos os feedbacks
app.get('/api/admin/feedbacks', async (c) => {
  const { DB } = c.env
  
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    // Criar tabela se nĂŁo existir
    await DB.prepare(`
      CREATE TABLE IF NOT EXISTS user_feedbacks (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL,
        rating INTEGER,
        feedback_type TEXT DEFAULT 'suggestion',
        message TEXT NOT NULL,
        page_context TEXT,
        is_read INTEGER DEFAULT 0,
        admin_response TEXT,
        responded_at DATETIME,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
      )
    `).run()
    
    const page = parseInt(c.req.query('page') || '1')
    const limit = parseInt(c.req.query('limit') || '50')
    const filterRead = c.req.query('is_read') // 'all', '0', '1'
    const offset = (page - 1) * limit
    
    let whereClause = ''
    if (filterRead === '0') {
      whereClause = 'WHERE f.is_read = 0'
    } else if (filterRead === '1') {
      whereClause = 'WHERE f.is_read = 1'
    }
    
    const feedbacks = await DB.prepare(`
      SELECT 
        f.id, f.user_id, f.rating, f.feedback_type, f.message, 
        f.page_context, f.is_read, f.admin_response, f.responded_at, f.created_at,
        u.name as user_name, u.email as user_email
      FROM user_feedbacks f
      LEFT JOIN users u ON u.id = f.user_id
      ${whereClause}
      ORDER BY f.is_read ASC, f.created_at DESC
      LIMIT ? OFFSET ?
    `).bind(limit, offset).all()
    
    const total = await DB.prepare(`
      SELECT COUNT(*) as count FROM user_feedbacks f ${whereClause}
    `).first() as any
    
    const unreadCount = await DB.prepare(`
      SELECT COUNT(*) as count FROM user_feedbacks WHERE is_read = 0
    `).first() as any
    
    // EstatĂ­sticas
    const stats = await DB.prepare(`
      SELECT 
        feedback_type,
        COUNT(*) as total,
        AVG(rating) as avg_rating
      FROM user_feedbacks
      GROUP BY feedback_type
    `).all()
    
    return c.json({
      feedbacks: feedbacks.results,
      unread_count: unreadCount?.count || 0,
      stats: stats.results,
      pagination: {
        page,
        limit,
        total: total?.count || 0,
        pages: Math.ceil((total?.count || 0) / limit)
      }
    })
  } catch (error: any) {
    console.error('Erro ao listar feedbacks:', error)
    return c.json({ error: 'Erro ao listar feedbacks', details: error.message }, 500)
  }
})

// â CORREĂĂO v13: Marcar feedback como lido/responder
app.put('/api/admin/feedbacks/:id', async (c) => {
  const { DB } = c.env
  
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    const feedbackId = c.req.param('id')
    const { is_read, admin_response } = await c.req.json()
    
    let query = 'UPDATE user_feedbacks SET '
    const updates: string[] = []
    const bindings: any[] = []
    
    if (typeof is_read !== 'undefined') {
      updates.push('is_read = ?')
      bindings.push(is_read ? 1 : 0)
    }
    
    if (admin_response) {
      updates.push('admin_response = ?')
      bindings.push(admin_response)
      updates.push("responded_at = datetime('now')")
    }
    
    if (updates.length === 0) {
      return c.json({ error: 'Nenhum campo para atualizar' }, 400)
    }
    
    query += updates.join(', ') + ' WHERE id = ?'
    bindings.push(feedbackId)
    
    await DB.prepare(query).bind(...bindings).run()
    
    return c.json({ success: true })
  } catch (error: any) {
    console.error('Erro ao atualizar feedback:', error)
    return c.json({ error: 'Erro ao atualizar feedback' }, 500)
  }
})

// Dar/remover premium manualmente (admin)
app.post('/api/admin/users/:id/premium', async (c) => {
  const { DB } = c.env
  
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    const userId = c.req.param('id')
    const { is_premium, days, plan } = await c.req.json()
    
    if (is_premium && days) {
      // â CORREĂĂO v9: Ativar premium por X dias E subscription_status
      const selectedPlan = plan || (days >= 365 ? 'anual' : 'mensal')
      await DB.prepare(`
        UPDATE users 
        SET is_premium = 1, 
            premium_expires_at = DATE('now', '+' || ? || ' days'),
            subscription_status = 'active',
            subscription_plan = ?,
            subscription_expires_at = DATE('now', '+' || ? || ' days')
        WHERE id = ?
      `).bind(days, selectedPlan, days, userId).run()
      console.log(`â Premium ativado para usuĂĄrio ${userId} por ${days} dias (${selectedPlan})`)
    } else {
      // Remover premium
      await DB.prepare(`
        UPDATE users 
        SET is_premium = 0, 
            premium_expires_at = NULL,
            subscription_status = 'cancelled',
            subscription_plan = NULL,
            subscription_expires_at = NULL
        WHERE id = ?
      `).bind(userId).run()
      console.log(`â Premium removido do usuĂĄrio ${userId}`)
    }
    
    return c.json({ success: true })
  } catch (error) {
    console.error('Erro ao atualizar premium:', error)
    return c.json({ error: 'Erro ao atualizar premium' }, 500)
  }
})

// â NOVO v9: Sincronizar status premium com subscription_status
// Ătil para corrigir usuĂĄrios que pagaram mas nĂŁo tiveram is_premium atualizado
app.post('/api/admin/sync-premium', async (c) => {
  const { DB } = c.env
  
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    // Sincronizar: se subscription_status = 'active' e subscription_expires_at > now, entĂŁo is_premium = 1
    const result = await DB.prepare(`
      UPDATE users 
      SET is_premium = 1,
          premium_expires_at = subscription_expires_at
      WHERE subscription_status = 'active' 
        AND subscription_expires_at > datetime('now')
        AND is_premium = 0
    `).run()
    
    // TambĂŠm sincronizar ao contrĂĄrio: se expirou, remover premium
    const expiredResult = await DB.prepare(`
      UPDATE users 
      SET is_premium = 0,
          subscription_status = 'expired'
      WHERE subscription_status = 'active' 
        AND subscription_expires_at <= datetime('now')
    `).run()
    
    console.log(`â SincronizaĂ§ĂŁo premium: ${result.meta.changes} ativados, ${expiredResult.meta.changes} expirados`)
    
    return c.json({ 
      success: true,
      activated: result.meta.changes || 0,
      expired: expiredResult.meta.changes || 0
    })
  } catch (error) {
    console.error('Erro ao sincronizar premium:', error)
    return c.json({ error: 'Erro ao sincronizar premium' }, 500)
  }
})

