// â v154 SEGURANĂA: Endpoint para validar sessĂŁo via token assinado
// O frontend chama isso ao iniciar para verificar se o token ĂŠ vĂĄlido
app.get('/api/auth/validate-session', async (c) => {
  const { DB } = c.env
  // â v159: Validar via token assinado (nĂŁo depende de headers extras)
  const userId = await getAuthenticatedUserId(c)
  
  if (!userId) {
    return c.json({ valid: false, force_logout: true, reason: 'Token invĂĄlido ou expirado' })
  }
  
  try {
    // Auto-migrate: garantir que coluna force_logout_at existe
    try {
      await DB.prepare('SELECT force_logout_at FROM users LIMIT 1').first()
    } catch {
      await DB.prepare('ALTER TABLE users ADD COLUMN force_logout_at DATETIME DEFAULT NULL').run()
      console.log('â Coluna force_logout_at adicionada automaticamente')
    }
    
    const user = await DB.prepare(
      'SELECT id, email, name, google_picture, auth_provider, force_logout_at FROM users WHERE id = ?'
    ).bind(userId).first() as any
    
    if (!user) {
      return c.json({ valid: false, force_logout: true, reason: 'UsuĂĄrio nĂŁo encontrado' })
    }
    
    // â v159 SEGURANĂA: Admin DEVE ter auth_provider 'google' ou 'both' NO BANCO
    // NĂO depender do header X-Auth-Provider (pode ser forjado ou ausente)
    if (user.email === ADMIN_EMAIL) {
      const dbProvider = (user.auth_provider || '').toLowerCase()
      if (dbProvider !== 'google' && dbProvider !== 'both') {
        console.warn(`đ¨ SEGURANĂA v159: Admin auth_provider no banco = '${dbProvider}', forĂ§ando logout`)
        return c.json({ 
          valid: false, 
          force_logout: true, 
          reason: 'SessĂŁo administrativa requer autenticaĂ§ĂŁo via Google',
          googleOnly: true
        })
      }
    }
    
    // â Verificar force_logout_at (se definido, a sessĂŁo foi invalidada pelo admin)
    if (user.force_logout_at) {
      console.log(`đ Force logout ativo para usuĂĄrio ${userId} desde ${user.force_logout_at}`)
      await DB.prepare('UPDATE users SET force_logout_at = NULL WHERE id = ?').bind(userId).run()
      return c.json({ valid: false, force_logout: true, reason: 'SessĂŁo invalidada pelo administrador' })
    }
    
    // â v158: Retornar flag isAdmin para o frontend poder verificar corretamente
    const isUserAdmin = user.email === ADMIN_EMAIL && 
      (user.auth_provider === 'google' || user.auth_provider === 'both')
    
    return c.json({ valid: true, force_logout: false, isAdmin: isUserAdmin, name: user.name || null, picture: user.google_picture || null })
  } catch (error: any) {
    console.error('Erro ao validar sessĂŁo:', error)
    return c.json({ valid: true, force_logout: false, isAdmin: false }) // Em caso de erro, nĂŁo deslogar
  }
})

