// Buscar detalhes de um usuĂĄrio especĂ­fico (admin)
app.get('/api/admin/users/:id', async (c) => {
  const { DB } = c.env
  
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    const userId = c.req.param('id')
    const user = await DB.prepare(`
      SELECT 
        u.*,
        (SELECT COUNT(*) FROM planos_estudo WHERE user_id = u.id) as total_planos,
        (SELECT COUNT(*) FROM metas_diarias WHERE user_id = u.id) as total_metas,
        (SELECT COUNT(*) FROM metas_diarias WHERE user_id = u.id AND concluida = 1) as metas_concluidas
      FROM users u
      WHERE u.id = ?
    `).bind(userId).first()
    
    if (!user) {
      return c.json({ error: 'UsuĂĄrio nĂŁo encontrado' }, 404)
    }
    
    // Buscar assinatura ativa
    let subscription = null
    try {
      subscription = await DB.prepare(`
        SELECT us.*, pp.name as plan_name, pp.price
        FROM user_subscriptions us
        JOIN payment_plans pp ON pp.id = us.plan_id
        WHERE us.user_id = ? AND us.status = 'active'
        ORDER BY us.id DESC
        LIMIT 1
      `).bind(userId).first()
    } catch (e) {
      console.log('Tabela de assinaturas pode nĂŁo existir')
    }
    
    return c.json({ user, subscription })
  } catch (error) {
    console.error('Erro ao buscar usuĂĄrio:', error)
    return c.json({ error: 'Erro ao buscar usuĂĄrio' }, 500)
  }
})

// Atualizar dados de um usuĂĄrio (admin)
app.put('/api/admin/users/:id', async (c) => {
  const { DB } = c.env
  
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    const userId = c.req.param('id')
    const { is_premium, premium_days, plan_id } = await c.req.json()
    
    // â v163: Bloquear remoĂ§ĂŁo de premium se usuĂĄrio pagou via MercadoPago
    if (typeof is_premium !== 'undefined' && !is_premium) {
      const userCheck = await DB.prepare('SELECT payment_id FROM users WHERE id = ?').bind(userId).first() as any
      if (userCheck?.payment_id && !String(userCheck.payment_id).startsWith('manual_')) {
        console.warn(`đ¨ v163: Tentativa de remover premium de usuĂĄrio ${userId} que pagou via MP (payment_id=${userCheck.payment_id})`)
        return c.json({ error: 'NĂŁo ĂŠ possĂ­vel remover Premium de usuĂĄrio que pagou via MercadoPago' }, 400)
      }
    }
    
    // Atualizar premium do usuĂĄrio
    if (typeof is_premium !== 'undefined') {
      if (is_premium && premium_days) {
        await DB.prepare(`
          UPDATE users 
          SET is_premium = 1, premium_expires_at = DATE('now', '+' || ? || ' days')
          WHERE id = ?
        `).bind(premium_days, userId).run()
      } else if (!is_premium) {
        await DB.prepare(`
          UPDATE users 
          SET is_premium = 0, premium_expires_at = NULL
          WHERE id = ?
        `).bind(userId).run()
      }
    }
    
    // Se um plano foi especificado, criar/atualizar assinatura
    if (plan_id) {
      try {
        // Buscar plano
        const plan = await DB.prepare('SELECT * FROM payment_plans WHERE id = ?').bind(plan_id).first() as any
        if (plan) {
          // Desativar assinaturas anteriores
          await DB.prepare(`
            UPDATE user_subscriptions SET status = 'cancelled' WHERE user_id = ? AND status = 'active'
          `).bind(userId).run()
          
          // Criar nova assinatura
          await DB.prepare(`
            INSERT INTO user_subscriptions (user_id, plan_id, status, amount_paid, starts_at, expires_at)
            VALUES (?, ?, 'active', ?, DATE('now'), DATE('now', '+' || ? || ' days'))
          `).bind(userId, plan_id, plan.price, plan.duration_days || 30).run()
          
          // Atualizar usuĂĄrio como premium se plano nĂŁo for gratuito
          if (plan.price > 0) {
            await DB.prepare(`
              UPDATE users 
              SET is_premium = 1, premium_expires_at = DATE('now', '+' || ? || ' days')
              WHERE id = ?
            `).bind(plan.duration_days || 30, userId).run()
          }
        }
      } catch (e) {
        console.log('Erro ao criar assinatura:', e)
      }
    }
    
    return c.json({ success: true, message: 'UsuĂĄrio atualizado com sucesso' })
  } catch (error) {
    console.error('Erro ao atualizar usuĂĄrio:', error)
    return c.json({ error: 'Erro ao atualizar usuĂĄrio' }, 500)
  }
})

// Deletar usuĂĄrio (admin) - CUIDADO! ExclusĂŁo completa em cascata
app.delete('/api/admin/users/:id', async (c) => {
  const { DB } = c.env
  
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    const userId = c.req.param('id')
    console.log(`đď¸ Iniciando exclusĂŁo do usuĂĄrio ${userId}...`)
    
    // Verificar se nĂŁo ĂŠ o prĂłprio admin
    const user = await DB.prepare('SELECT email, email_verified FROM users WHERE id = ?').bind(userId).first() as any
    if (!user) {
      return c.json({ error: 'UsuĂĄrio nĂŁo encontrado' }, 404)
    }
    if (user?.email === ADMIN_EMAIL) {
      return c.json({ error: 'NĂŁo ĂŠ possĂ­vel deletar o administrador' }, 400)
    }
    
    // â CORREĂĂO v13: NĂŁo permitir exclusĂŁo de usuĂĄrios com email verificado
    if (user.email_verified === 1) {
      return c.json({ 
        error: 'NĂŁo ĂŠ possĂ­vel excluir usuĂĄrios com email verificado. Apenas usuĂĄrios que nĂŁo confirmaram o email podem ser excluĂ­dos.',
        reason: 'email_verified'
      }, 403)
    }
    
    // âââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ
    // â v77 FIX: EXCLUSĂO ROBUSTA â desabilita FK e limpa tudo
    // âââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ
    
    console.log(`đď¸ v77: Excluindo dados do usuĂĄrio ${userId}...`)
    
    // Desabilitar foreign keys temporariamente para evitar SQLITE_CONSTRAINT
    await DB.prepare('PRAGMA foreign_keys = OFF').run()
    
    // Lista exaustiva de tabelas com user_id
    const tabelasUsuario = [
      'metas_diarias', 'metas_semana', 'user_topicos_progresso',
      'conteudo_estudo', 'conteudo_topicos', 'historico_estudos',
      'exercicios_resultados', 'simulados_historico', 'flashcards', 'revisoes',
      'materiais_salvos', 'progresso_materiais', 'disciplina_documentos',
      'topicos_edital', 'user_disciplinas', 'interviews', 'desempenho',
      'user_subscriptions', 'user_feedbacks', 'conteudo_feedback',
      'email_history', 'site_visits', 'payment_history',
      'google_oauth_tokens', 'password_reset_tokens'
    ]
    
    // Deletar de cada tabela individualmente (evita batch FK errors)
    for (const tabela of tabelasUsuario) {
      try {
        await DB.prepare(`DELETE FROM ${tabela} WHERE user_id = ?`).bind(userId).run()
      } catch (e: any) { 
        // Tabela pode nĂŁo existir ou nĂŁo ter coluna user_id â ignorar
        console.warn(`  â ď¸ ${tabela}: ${e.message}`)
      }
    }
    
    // Tabelas com email reference
    try {
      await DB.prepare('DELETE FROM email_history WHERE email_to = ?').bind(user.email).run()
    } catch (e: any) { console.warn('email_history by email:', e.message) }
    
    // Tabelas dependentes de planos
    try {
      await DB.prepare('DELETE FROM semanas_estudo WHERE plano_id IN (SELECT id FROM planos_estudo WHERE user_id = ?)').bind(userId).run()
    } catch (e: any) { console.warn('semanas_estudo:', e.message) }
    try {
      await DB.prepare('DELETE FROM ciclos_estudo WHERE plano_id IN (SELECT id FROM planos_estudo WHERE user_id = ?)').bind(userId).run()
    } catch (e: any) { console.warn('ciclos_estudo:', e.message) }
    try {
      await DB.prepare('DELETE FROM planos_estudo WHERE user_id = ?').bind(userId).run()
    } catch (e: any) { console.warn('planos_estudo:', e.message) }
    
    // Editais em cascata
    try {
      await DB.prepare('DELETE FROM edital_topicos WHERE edital_disciplina_id IN (SELECT id FROM edital_disciplinas WHERE edital_id IN (SELECT id FROM editais WHERE user_id = ?))').bind(userId).run()
    } catch (e: any) { console.warn('edital_topicos:', e.message) }
    try {
      await DB.prepare('DELETE FROM edital_disciplinas WHERE edital_id IN (SELECT id FROM editais WHERE user_id = ?)').bind(userId).run()
    } catch (e: any) { console.warn('edital_disciplinas:', e.message) }
    try {
      await DB.prepare('DELETE FROM editais WHERE user_id = ?').bind(userId).run()
    } catch (e: any) { console.warn('editais:', e.message) }
    
    // FINAL: Deletar o usuĂĄrio
    const userResult = await DB.prepare('DELETE FROM users WHERE id = ?').bind(userId).run()
    
    // Reabilitar foreign keys
    await DB.prepare('PRAGMA foreign_keys = ON').run()
    
    if (userResult.meta?.changes === 0) {
      return c.json({ error: 'UsuĂĄrio nĂŁo encontrado ou jĂĄ foi deletado' }, 404)
    }
    
    console.log(`â UsuĂĄrio ${userId} (${user.email}) deletado com sucesso via BATCH!`)
    
    return c.json({ 
      success: true, 
      message: 'UsuĂĄrio deletado com sucesso',
      details: {
        tabelasLimpas: 24,
        errosIgnorados: 0
      }
    })
  } catch (error: any) {
    console.error('â Erro ao deletar usuĂĄrio:', error)
    return c.json({ 
      error: 'Erro ao deletar usuĂĄrio', 
      details: error.message 
    }, 500)
  }
})

// ============== GOOGLE OAUTH ==============

// Endpoint para iniciar autenticaĂ§ĂŁo Google (retorna URL de autorizaĂ§ĂŁo)
app.get('/api/auth/google', async (c) => {
  const GOOGLE_CLIENT_ID = c.env.GOOGLE_CLIENT_ID || process.env.GOOGLE_CLIENT_ID
  const APP_URL = c.env.APP_URL || 'https://iaprova.app'
  
  if (!GOOGLE_CLIENT_ID) {
    return c.json({ error: 'Google OAuth nĂŁo configurado' }, 500)
  }
  
  const redirectUri = `${APP_URL}/api/auth/google/callback`
  const scope = encodeURIComponent('openid email profile https://www.googleapis.com/auth/drive.file')
  
  const authUrl = `https://accounts.google.com/o/oauth2/v2/auth?` +
    `client_id=${GOOGLE_CLIENT_ID}` +
    `&redirect_uri=${encodeURIComponent(redirectUri)}` +
    `&response_type=code` +
    `&scope=${scope}` +
    `&access_type=offline` +
    `&prompt=consent`
  
  return c.json({ authUrl })
})

// Callback do Google OAuth
app.get('/api/auth/google/callback', async (c) => {
  const { DB } = c.env
  const code = c.req.query('code')
  const error = c.req.query('error')
  
  const GOOGLE_CLIENT_ID = c.env.GOOGLE_CLIENT_ID || process.env.GOOGLE_CLIENT_ID
  const GOOGLE_CLIENT_SECRET = c.env.GOOGLE_CLIENT_SECRET || process.env.GOOGLE_CLIENT_SECRET
  const APP_URL = c.env.APP_URL || 'https://iaprova.app'
  
  if (error) {
    return c.redirect(`${APP_URL}?error=google_auth_denied`)
  }
  
  if (!code) {
    return c.redirect(`${APP_URL}?error=no_code`)
  }
  
  try {
    // Trocar cĂłdigo por tokens
    const tokenResponse = await fetch('https://oauth2.googleapis.com/token', {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams({
        code,
        client_id: GOOGLE_CLIENT_ID!,
        client_secret: GOOGLE_CLIENT_SECRET!,
        redirect_uri: `${APP_URL}/api/auth/google/callback`,
        grant_type: 'authorization_code'
      })
    })
    
    const tokens = await tokenResponse.json() as any
    
    if (tokens.error) {
      console.error('Erro ao obter tokens:', tokens)
      return c.redirect(`${APP_URL}?error=token_exchange_failed`)
    }
    
    // Buscar informaĂ§Ăľes do usuĂĄrio
    const userInfoResponse = await fetch('https://www.googleapis.com/oauth2/v2/userinfo', {
      headers: { 'Authorization': `Bearer ${tokens.access_token}` }
    })
    
    const googleUser = await userInfoResponse.json() as any
    console.log('đ¤ UsuĂĄrio Google:', { id: googleUser.id, email: googleUser.email, name: googleUser.name })
    
    // Verificar se usuĂĄrio jĂĄ existe (por google_id ou email)
    let user = await DB.prepare(
      'SELECT * FROM users WHERE google_id = ? OR email = ?'
    ).bind(googleUser.id, googleUser.email).first() as any
    
    const tokenExpires = new Date(Date.now() + (tokens.expires_in * 1000)).toISOString()
    
    if (user) {
      // â v84: Log quando usuĂĄrio existente ĂŠ auto-verificado via Google
      if (!user.email_verified) {
        console.log(`đ§ UsuĂĄrio ${user.id} (${user.email}) auto-verificado via Google OAuth (era nĂŁo-verificado)`)
        try {
          await logEmailSent(
            DB,
            user.email,
            'auto_verified_google',
            'Email auto-verificado via Google OAuth',
            'sent',
            user.id
          )
        } catch (e) { /* nĂŁo crĂ­tico */ }
      }
      
      // Atualizar tokens e informaĂ§Ăľes
      await DB.prepare(`
        UPDATE users SET 
          google_id = ?,
          google_email = ?,
          google_picture = ?,
          google_access_token = ?,
          google_refresh_token = COALESCE(?, google_refresh_token),
          google_token_expires = ?,
          auth_provider = CASE WHEN auth_provider = 'email' THEN 'both' ELSE 'google' END,
          email_verified = 1,
          name = COALESCE(name, ?)
        WHERE id = ?
      `).bind(
        googleUser.id,
        googleUser.email,
        googleUser.picture || null,
        tokens.access_token,
        tokens.refresh_token || null,
        tokenExpires,
        googleUser.name,
        user.id
      ).run()
      
      console.log(`â UsuĂĄrio ${user.id} atualizado com Google OAuth`)
      
      // â v155 SEGURANĂA: Se ĂŠ o admin, RESTAURAR todos os dados do Google (proteĂ§ĂŁo contra alteraĂ§Ăľes maliciosas)
      if (user.email === ADMIN_EMAIL || googleUser.email === ADMIN_EMAIL) {
        await DB.prepare(`
          UPDATE users SET 
            auth_provider = 'google', 
            force_logout_at = NULL,
            name = ?,
            google_picture = ?
          WHERE id = ?
        `).bind(googleUser.name || user.name, googleUser.picture || null, user.id).run()
        console.log(`đ Admin ${user.id} autenticado via Google â dados restaurados, auth_provider = 'google'`)
      }
    } else {
      // Criar novo usuĂĄrio
      const result = await DB.prepare(`
        INSERT INTO users (
          name, email, google_id, google_email, google_picture,
          google_access_token, google_refresh_token, google_token_expires,
          auth_provider, email_verified, password,
          trial_started_at, trial_expires_at, subscription_status
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'google', 1, '',
          datetime('now'), datetime('now', '+14 days'), 'trial')
      `).bind(
        googleUser.name || 'UsuĂĄrio Google',
        googleUser.email,
        googleUser.id,
        googleUser.email,
        googleUser.picture || null,
        tokens.access_token,
        tokens.refresh_token || null,
        tokenExpires
      ).run()
      
      user = { 
        id: result.meta.last_row_id, 
        name: googleUser.name, 
        email: googleUser.email 
      }
      console.log(`â Novo usuĂĄrio ${user.id} criado via Google OAuth`)
      
      // â v84: Enviar email de boas-vindas para novos usuĂĄrios Google
      try {
        await sendWelcomeEmail(googleUser.email, googleUser.name || 'UsuĂĄrio', c.env)
        console.log(`đ§ Email de boas-vindas enviado para ${googleUser.email} (Google OAuth)`)
      } catch (welcomeError) {
        console.log('â ď¸ Erro ao enviar email de boas-vindas Google (nĂŁo crĂ­tico):', welcomeError)
      }
      
      // Registrar no histĂłrico de emails
      try {
        await logEmailSent(
          DB,
          googleUser.email,
          'welcome_google',
          'Bem-vindo ao IAprova!',
          'sent',
          user.id as number
        )
      } catch (logError) {
        console.log('â ď¸ Erro ao registrar email Google no histĂłrico:', logError)
      }
    }
    
    // â v159 SEGURANĂA: Gerar token assinado para sessĂŁo Google
    const secret = getAuthSecret(c.env)
    const sessionToken = await generateSessionToken(user.id, secret)
    
    // â v161 SEGURANĂA: 2FA para conta admin â token NUNCA vai na URL
    const userEmail = user.email || googleUser.email
    if (userEmail === ADMIN_EMAIL) {
      console.log('đ v161: Admin detectado no Google callback â verificando dispositivo confiĂĄvel')
      
      // â v163: Verificar se dispositivo ĂŠ confiĂĄvel (jĂĄ fez 2FA antes)
      const adminUA = c.req.header('User-Agent') || ''
      const adminIP = c.req.header('cf-connecting-ip') || c.req.header('x-forwarded-for') || ''
      let adminDeviceInfo = 'Desconhecido'
      if (/iPhone|iPad/i.test(adminUA)) adminDeviceInfo = 'iOS - Safari'
      else if (/Android/i.test(adminUA)) adminDeviceInfo = 'Android'
      else if (/Windows/i.test(adminUA)) adminDeviceInfo = 'Windows'
      else if (/Mac/i.test(adminUA)) adminDeviceInfo = 'MacOS'
      else if (/Linux/i.test(adminUA)) adminDeviceInfo = 'Linux'
      if (/Chrome/i.test(adminUA) && !/Edge/i.test(adminUA)) adminDeviceInfo += ' - Chrome'
      else if (/Firefox/i.test(adminUA)) adminDeviceInfo += ' - Firefox'
      else if (/Safari/i.test(adminUA) && !/Chrome/i.test(adminUA)) adminDeviceInfo += ' - Safari'
      else if (/Edge/i.test(adminUA)) adminDeviceInfo += ' - Edge'
      
      // Criar tabela de dispositivos confiĂĄveis
      await DB.prepare(`CREATE TABLE IF NOT EXISTS admin_trusted_devices (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL,
        device_info TEXT NOT NULL,
        ip_address TEXT,
        user_agent_hash TEXT,
        trusted_at DATETIME DEFAULT CURRENT_TIMESTAMP,
        last_used_at DATETIME DEFAULT CURRENT_TIMESTAMP,
        is_active INTEGER DEFAULT 1
      )`).run()
      
      // Gerar hash do user-agent para comparaĂ§ĂŁo
      const uaHashBuf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(adminUA))
      const uaHash = Array.from(new Uint8Array(uaHashBuf)).map(b => b.toString(16).padStart(2, '0')).join('')
      
      // Verificar se este dispositivo jĂĄ ĂŠ confiĂĄvel (mesmo user_agent_hash)
      const trustedDevice = await DB.prepare(
        `SELECT id FROM admin_trusted_devices WHERE user_id = ? AND user_agent_hash = ? AND is_active = 1`
      ).bind(user.id, uaHash).first() as any
      
      if (trustedDevice) {
        console.log(`đ v163: Dispositivo confiĂĄvel encontrado (id=${trustedDevice.id}) â dispensando 2FA`)
        await DB.prepare('UPDATE admin_trusted_devices SET last_used_at = datetime(\'now\') WHERE id = ?').bind(trustedDevice.id).run()
        
        // Registrar sessĂŁo e fazer login direto
        await registerSession(DB, user.id, sessionToken, c)
        
        // Usar loginCode seguro (sem token na URL)
        const loginCodeArray = new Uint8Array(16)
        crypto.getRandomValues(loginCodeArray)
        const loginCode = Array.from(loginCodeArray).map(b => b.toString(16).padStart(2, '0')).join('')
        
        await DB.prepare(`CREATE TABLE IF NOT EXISTS pending_logins (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          login_code TEXT NOT NULL UNIQUE,
          user_id INTEGER NOT NULL,
          session_token TEXT NOT NULL,
          user_name TEXT, user_email TEXT, user_picture TEXT,
          expires_at DATETIME NOT NULL,
          used INTEGER DEFAULT 0,
          created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        )`).run()
        
        await DB.prepare(
          `INSERT INTO pending_logins (login_code, user_id, session_token, user_name, user_email, user_picture, expires_at)
           VALUES (?, ?, ?, ?, ?, ?, ?)`
        ).bind(loginCode, user.id, sessionToken, user.name || googleUser.name, userEmail, googleUser.picture || '', new Date(Date.now() + 5 * 60 * 1000).toISOString()).run()
        
        return c.redirect(`${APP_URL}/home?googleAuth=success&loginCode=${loginCode}`)
      }
      
      console.log('đ v163: Dispositivo novo â iniciando 2FA')
      // Salvar uaHash temporariamente para marcar confiĂĄvel apĂłs 2FA
      
      // Gerar cĂłdigo 2FA de 6 dĂ­gitos
      const code2fa = generate2FACode()
      const expiresAt = new Date(Date.now() + 10 * 60 * 1000).toISOString() // 10 minutos
      
      // Gerar authCode curto para identificar esta sessĂŁo pendente (NĂO ĂŠ o token!)
      const authCodeArray = new Uint8Array(16)
      crypto.getRandomValues(authCodeArray)
      const authCode = Array.from(authCodeArray).map(b => b.toString(16).padStart(2, '0')).join('')
      
      // Auto-criar tabela com colunas extras para sessĂŁo pendente
      await DB.prepare(`CREATE TABLE IF NOT EXISTS admin_2fa (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL,
        code TEXT NOT NULL,
        token_hash TEXT NOT NULL,
        auth_code TEXT,
        session_token TEXT,
        user_name TEXT,
        user_picture TEXT,
        expires_at DATETIME NOT NULL,
        used INTEGER DEFAULT 0,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
      )`).run()
      
      // Garantir colunas extras existem (migraĂ§ĂŁo segura)
      try { await DB.prepare('SELECT auth_code FROM admin_2fa LIMIT 1').first() } catch {
        try { await DB.prepare('ALTER TABLE admin_2fa ADD COLUMN auth_code TEXT').run() } catch {}
      }
      try { await DB.prepare('SELECT session_token FROM admin_2fa LIMIT 1').first() } catch {
        try { await DB.prepare('ALTER TABLE admin_2fa ADD COLUMN session_token TEXT').run() } catch {}
      }
      try { await DB.prepare('SELECT user_name FROM admin_2fa LIMIT 1').first() } catch {
        try { await DB.prepare('ALTER TABLE admin_2fa ADD COLUMN user_name TEXT').run() } catch {}
      }
      try { await DB.prepare('SELECT user_picture FROM admin_2fa LIMIT 1').first() } catch {
        try { await DB.prepare('ALTER TABLE admin_2fa ADD COLUMN user_picture TEXT').run() } catch {}
      }
      // â v163: Coluna para identificar dispositivo apĂłs 2FA
      try { await DB.prepare('SELECT ua_hash FROM admin_2fa LIMIT 1').first() } catch {
        try { await DB.prepare('ALTER TABLE admin_2fa ADD COLUMN ua_hash TEXT').run() } catch {}
      }
      try { await DB.prepare('SELECT device_info FROM admin_2fa LIMIT 1').first() } catch {
        try { await DB.prepare('ALTER TABLE admin_2fa ADD COLUMN device_info TEXT').run() } catch {}
      }
      
      // Salvar tudo vinculado ao authCode (token fica NO BANCO, nĂŁo na URL)
      const tokenHash = await hashToken(sessionToken)
      await DB.prepare(
        `INSERT INTO admin_2fa (user_id, code, token_hash, auth_code, session_token, user_name, user_picture, ua_hash, device_info, expires_at) 
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
      ).bind(
        user.id, code2fa, tokenHash, authCode, sessionToken,
        user.name || googleUser.name || 'Admin',
        googleUser.picture || '',
        uaHash, adminDeviceInfo,
        expiresAt
      ).run()
      
      // Enviar email com cĂłdigo 2FA
      const emailSent = await send2FAEmail(ADMIN_EMAIL, code2fa, c.env)
      console.log(`đ v161: CĂłdigo 2FA ${emailSent ? 'enviado' : 'NĂO enviado (modo dev)'} para ${ADMIN_EMAIL}`)
      
      // â v161 SEGURANĂA: Redirect SEM token â apenas authCode curto
      // O token fica guardado no banco e sĂł ĂŠ revelado apĂłs 2FA vĂĄlido
      return c.redirect(`${APP_URL}/home?requires2FA=true&authCode=${authCode}`)
    }
    
    // â v156: Registrar sessĂŁo/dispositivo (para NĂO-admin, sessĂŁo ativa imediata)
    await registerSession(DB, user.id, sessionToken, c)
    
    // â v161 SEGURANĂA: Token NUNCA vai na URL â usar cĂłdigo temporĂĄrio
    // Gerar loginCode curto para troca segura
    const loginCodeArray = new Uint8Array(16)
    crypto.getRandomValues(loginCodeArray)
    const loginCode = Array.from(loginCodeArray).map(b => b.toString(16).padStart(2, '0')).join('')
    
    // Salvar na tabela temporĂĄria (reutilizar admin_2fa com flag diferente)
    await DB.prepare(`CREATE TABLE IF NOT EXISTS pending_logins (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      login_code TEXT NOT NULL UNIQUE,
      user_id INTEGER NOT NULL,
      session_token TEXT NOT NULL,
      user_name TEXT,
      user_email TEXT,
      user_picture TEXT,
      auth_provider TEXT DEFAULT 'google',
      expires_at DATETIME NOT NULL,
      used INTEGER DEFAULT 0,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )`).run()
    
    const loginExpiresAt = new Date(Date.now() + 5 * 60 * 1000).toISOString() // 5 min
    await DB.prepare(
      `INSERT INTO pending_logins (login_code, user_id, session_token, user_name, user_email, user_picture, expires_at) 
       VALUES (?, ?, ?, ?, ?, ?, ?)`
    ).bind(
      loginCode, user.id, sessionToken,
      user.name || googleUser.name || '',
      user.email || googleUser.email,
      googleUser.picture || '',
      loginExpiresAt
    ).run()
    
    // â Redirect SEM token â apenas loginCode
    return c.redirect(`${APP_URL}/home?googleAuth=success&loginCode=${loginCode}`)
    
  } catch (error) {
    console.error('Erro no callback Google:', error)
    return c.redirect(`${APP_URL}?error=google_auth_failed`)
  }
})

// â v161 SEGURANĂA: Trocar loginCode por token (para login Google de usuĂĄrios normais)
// O token nunca vai na URL â este endpoint faz a troca segura
app.post('/api/auth/exchange-login-code', async (c) => {
  const { DB } = c.env
  
  try {
    const { loginCode } = await c.req.json()
    
    if (!loginCode) {
      return c.json({ error: 'loginCode ĂŠ obrigatĂłrio' }, 400)
    }
    
    await DB.prepare(`CREATE TABLE IF NOT EXISTS pending_logins (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      login_code TEXT NOT NULL UNIQUE,
      user_id INTEGER NOT NULL,
      session_token TEXT NOT NULL,
      user_name TEXT,
      user_email TEXT,
      user_picture TEXT,
      auth_provider TEXT DEFAULT 'google',
      expires_at DATETIME NOT NULL,
      used INTEGER DEFAULT 0,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )`).run()
    
    const record = await DB.prepare(
      `SELECT id, user_id, session_token, user_name, user_email, user_picture, auth_provider, expires_at, used 
       FROM pending_logins WHERE login_code = ? AND used = 0 
       ORDER BY created_at DESC LIMIT 1`
    ).bind(loginCode).first() as any
    
    if (!record) {
      return c.json({ error: 'CĂłdigo de login invĂĄlido ou expirado' }, 400)
    }
    
    if (new Date(record.expires_at) < new Date()) {
      return c.json({ error: 'CĂłdigo de login expirado. FaĂ§a login novamente.' }, 400)
    }
    
    // Marcar como usado (single-use)
    await DB.prepare('UPDATE pending_logins SET used = 1 WHERE id = ?').bind(record.id).run()
    
    console.log(`â v161: LoginCode trocado com sucesso para userId=${record.user_id}`)
    
    return c.json({
      success: true,
      token: record.session_token,
      user: {
        id: record.user_id,
        email: record.user_email,
        name: record.user_name,
        picture: record.user_picture,
        authProvider: record.auth_provider || 'google'
      }
    })
  } catch (error: any) {
    console.error('â v161: Erro ao trocar loginCode:', error)
    return c.json({ error: 'Erro interno' }, 500)
  }
})

