// â v161: Endpoint para verificar cĂłdigo 2FA do admin (usa authCode, nĂŁo token)
app.post('/api/auth/verify-2fa', async (c) => {
  const { DB } = c.env
  
  try {
    const { code, authCode } = await c.req.json()
    
    if (!code || !authCode) {
      return c.json({ error: 'CĂłdigo e authCode sĂŁo obrigatĂłrios' }, 400)
    }
    
    console.log(`đ v161: Tentativa de verificaĂ§ĂŁo 2FA com cĂłdigo ${code.substring(0, 2)}****`)
    
    // Auto-criar tabela se necessĂĄrio
    await DB.prepare(`CREATE TABLE IF NOT EXISTS admin_2fa (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      code TEXT NOT NULL,
      token_hash TEXT NOT NULL,
      auth_code TEXT,
      session_token TEXT,
      user_name TEXT,
      user_picture TEXT,
      expires_at DATETIME NOT NULL,
      used INTEGER DEFAULT 0,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )`).run()
    
    // Buscar sessĂŁo 2FA pendente por authCode
    const record = await DB.prepare(
      `SELECT id, user_id, code, session_token, expires_at, used FROM admin_2fa 
       WHERE auth_code = ? AND used = 0 
       ORDER BY created_at DESC LIMIT 1`
    ).bind(authCode).first() as any
    
    if (!record) {
      console.warn('đ¨ v161: Nenhum cĂłdigo 2FA encontrado para authCode')
      return c.json({ error: 'SessĂŁo expirada ou jĂĄ utilizada. FaĂ§a login novamente.' }, 400)
    }
    
    // Verificar expiraĂ§ĂŁo
    if (new Date(record.expires_at) < new Date()) {
      console.warn(`đ¨ v161: CĂłdigo 2FA expirado`)
      return c.json({ error: 'CĂłdigo expirado. FaĂ§a login novamente.' }, 400)
    }
    
    // Verificar cĂłdigo (comparaĂ§ĂŁo segura)
    const providedCode = code.trim()
    if (providedCode !== record.code) {
      console.warn('đ¨ v161: CĂłdigo 2FA incorreto para admin')
      return c.json({ error: 'CĂłdigo incorreto. Tente novamente.' }, 400)
    }
    
    // â CĂłdigo correto! Marcar como usado
    await DB.prepare('UPDATE admin_2fa SET used = 1 WHERE id = ?').bind(record.id).run()
    
    // Recuperar token da sessĂŁo pendente
    const sessionToken = record.session_token
    if (!sessionToken) {
      console.error('đ¨ v161: Token da sessĂŁo nĂŁo encontrado no registro 2FA')
      return c.json({ error: 'Erro interno. FaĂ§a login novamente.' }, 500)
    }
    
    // Verificar se o usuĂĄrio ĂŠ o admin
    const user = await DB.prepare('SELECT id, email, name FROM users WHERE id = ?').bind(record.user_id).first() as any
    if (!user || user.email !== ADMIN_EMAIL) {
      console.warn(`đ¨ v161: Tentativa de 2FA por nĂŁo-admin userId=${record.user_id}`)
      return c.json({ error: 'Acesso negado' }, 403)
    }
    
    // â Registrar sessĂŁo (agora sim, 2FA validado)
    await registerSession(DB, user.id, sessionToken, c)
    
    // â v163: Marcar dispositivo como confiĂĄvel apĂłs 2FA bem-sucedido
    try {
      const record2fa = await DB.prepare(
        `SELECT ua_hash, device_info FROM admin_2fa WHERE auth_code = ? ORDER BY created_at DESC LIMIT 1`
      ).bind(authCode).first() as any
      
      if (record2fa?.ua_hash) {
        await DB.prepare(`CREATE TABLE IF NOT EXISTS admin_trusted_devices (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          user_id INTEGER NOT NULL,
          device_info TEXT NOT NULL,
          ip_address TEXT,
          user_agent_hash TEXT,
          trusted_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          last_used_at DATETIME DEFAULT CURRENT_TIMESTAMP,
          is_active INTEGER DEFAULT 1
        )`).run()
        
        // Verificar se jĂĄ nĂŁo existe
        const existing = await DB.prepare(
          'SELECT id FROM admin_trusted_devices WHERE user_id = ? AND user_agent_hash = ?'
        ).bind(user.id, record2fa.ua_hash).first()
        
        if (!existing) {
          const verifyIP = c.req.header('cf-connecting-ip') || c.req.header('x-forwarded-for') || ''
          await DB.prepare(
            `INSERT INTO admin_trusted_devices (user_id, device_info, ip_address, user_agent_hash)
             VALUES (?, ?, ?, ?)`
          ).bind(user.id, record2fa.device_info || 'Desconhecido', verifyIP, record2fa.ua_hash).run()
          console.log(`đ v163: Dispositivo "${record2fa.device_info}" marcado como confiĂĄvel para admin`)
        }
      }
    } catch (e) {
      console.log('â ď¸ v163: Erro ao marcar dispositivo confiĂĄvel (nĂŁo crĂ­tico):', e)
    }
    
    console.log(`â v161: 2FA validado com sucesso para admin ${user.id}`)
    
    // â v161 SEGURANĂA: Token sĂł ĂŠ revelado APĂS 2FA validado
    return c.json({ 
      success: true, 
      message: 'AutenticaĂ§ĂŁo em duas etapas concluĂ­da com sucesso',
      token: sessionToken,
      user: {
        id: user.id,
        email: user.email,
        name: user.name
      },
      isAdmin: true
    })
  } catch (error: any) {
    console.error('â v160: Erro na verificaĂ§ĂŁo 2FA:', error)
    return c.json({ error: 'Erro ao verificar cĂłdigo' }, 500)
  }
})

// Endpoint para atualizar tokens do Google (refresh)
app.post('/api/auth/google/refresh', async (c) => {
  const { DB } = c.env
  const { user_id } = await c.req.json()
  
  // â v155 SEGURANĂA: Exigir autenticaĂ§ĂŁo e sĂł permitir refresh do prĂłprio token
  const authenticatedUserId = await getAuthenticatedUserId(c)
  if (!authenticatedUserId || authenticatedUserId.toString() !== user_id?.toString()) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  const GOOGLE_CLIENT_ID = c.env.GOOGLE_CLIENT_ID || process.env.GOOGLE_CLIENT_ID
  const GOOGLE_CLIENT_SECRET = c.env.GOOGLE_CLIENT_SECRET || process.env.GOOGLE_CLIENT_SECRET
  
  try {
    const user = await DB.prepare(
      'SELECT google_refresh_token FROM users WHERE id = ?'
    ).bind(user_id).first() as any
    
    if (!user?.google_refresh_token) {
      return c.json({ error: 'UsuĂĄrio nĂŁo conectado ao Google' }, 400)
    }
    
    const tokenResponse = await fetch('https://oauth2.googleapis.com/token', {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams({
        client_id: GOOGLE_CLIENT_ID!,
        client_secret: GOOGLE_CLIENT_SECRET!,
        refresh_token: user.google_refresh_token,
        grant_type: 'refresh_token'
      })
    })
    
    const tokens = await tokenResponse.json() as any
    
    if (tokens.error) {
      return c.json({ error: 'Falha ao renovar token' }, 400)
    }
    
    const tokenExpires = new Date(Date.now() + (tokens.expires_in * 1000)).toISOString()
    
    await DB.prepare(`
      UPDATE users SET 
        google_access_token = ?,
        google_token_expires = ?
      WHERE id = ?
    `).bind(tokens.access_token, tokenExpires, user_id).run()
    
    return c.json({ 
      success: true, 
      access_token: tokens.access_token,
      expires_at: tokenExpires
    })
  } catch (error) {
    console.error('Erro ao renovar token:', error)
    return c.json({ error: 'Erro ao renovar token' }, 500)
  }
})

// â v155 SEGURANĂA: Verificar status da conexĂŁo Google â requer autenticaĂ§ĂŁo
app.get('/api/auth/google/status/:user_id', async (c) => {
  const { DB } = c.env
  const user_id = c.req.param('user_id')
  
  // â v155: Exigir autenticaĂ§ĂŁo e sĂł permitir para o prĂłprio usuĂĄrio
  const authenticatedUserId = await getAuthenticatedUserId(c)
  if (!authenticatedUserId || (authenticatedUserId.toString() !== user_id.toString() && !await isAdmin(c))) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    // Primeiro, verificar se as colunas do Google existem
    let user: any = null
    
    try {
      user = await DB.prepare(`
        SELECT google_id, google_email, google_picture, auth_provider, 
               google_token_expires, last_sync_at
        FROM users WHERE id = ?
      `).bind(user_id).first()
    } catch (columnError: any) {
      // Se as colunas nĂŁo existem, retornar status desconectado
      if (columnError.message?.includes('no such column')) {
        console.log('â ď¸ Colunas Google ainda nĂŁo existem - retornando status desconectado')
        return c.json({
          connected: false,
          email: null,
          picture: null,
          authProvider: 'email',
          tokenValid: false,
          lastSync: null,
          googleNotConfigured: true
        })
      }
      throw columnError
    }
    
    if (!user) {
      return c.json({ error: 'UsuĂĄrio nĂŁo encontrado' }, 404)
    }
    
    const isConnected = !!user.google_id
    const tokenExpired = user.google_token_expires ? new Date(user.google_token_expires) < new Date() : true
    
    return c.json({
      connected: isConnected,
      email: user.google_email,
      picture: user.google_picture,
      authProvider: user.auth_provider || 'email',
      tokenValid: isConnected && !tokenExpired,
      lastSync: user.last_sync_at
    })
  } catch (error) {
    console.error('Erro ao verificar status Google:', error)
    // Retornar status desconectado em vez de erro
    return c.json({
      connected: false,
      email: null,
      picture: null,
      authProvider: 'email',
      tokenValid: false,
      lastSync: null
    })
  }
})

// Desconectar Google
app.post('/api/auth/google/disconnect', async (c) => {
  const { DB } = c.env
  const { user_id } = await c.req.json()
  
  // â v155 SEGURANĂA: Exigir autenticaĂ§ĂŁo e sĂł permitir para o prĂłprio usuĂĄrio
  const authenticatedUserId = await getAuthenticatedUserId(c)
  if (!authenticatedUserId || authenticatedUserId.toString() !== user_id?.toString()) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    const user = await DB.prepare(
      'SELECT email, auth_provider, password FROM users WHERE id = ?'
    ).bind(user_id).first() as any
    
    if (!user) {
      return c.json({ error: 'UsuĂĄrio nĂŁo encontrado' }, 404)
    }
    
    // â v155: Admin NUNCA pode desconectar Google (ĂŠ a Ăşnica forma de auth)
    if (user.email === ADMIN_EMAIL) {
      return c.json({ error: 'Conta admin nĂŁo pode desconectar Google' }, 403)
    }
    
    // Se o usuĂĄrio sĂł tem Google (sem senha), nĂŁo pode desconectar
    if (user.auth_provider === 'google' && (!user.password || user.password === '')) {
      return c.json({ 
        error: 'VocĂŞ precisa definir uma senha antes de desconectar o Google',
        needsPassword: true
      }, 400)
    }
    
    await DB.prepare(`
      UPDATE users SET 
        google_id = NULL,
        google_email = NULL,
        google_picture = NULL,
        google_access_token = NULL,
        google_refresh_token = NULL,
        google_token_expires = NULL,
        auth_provider = 'email'
      WHERE id = ?
    `).bind(user_id).run()
    
    return c.json({ success: true, message: 'Google desconectado com sucesso' })
  } catch (error) {
    console.error('Erro ao desconectar Google:', error)
    return c.json({ error: 'Erro ao desconectar' }, 500)
  }
})

// Verificar email com token
app.get('/api/verify-email/:token', async (c) => {
  const { DB } = c.env
  const token = c.req.param('token')
  
  console.log('đ VerificaĂ§ĂŁo de email - Token recebido:', token?.substring(0, 10) + '...')
  
  if (!token) {
    return c.json({ error: 'Token invĂĄlido' }, 400)
  }
  
  // â v157 SEGURANĂA: Removido token de teste hardcoded â era uma vulnerabilidade
  
  try {
    // Buscar usuĂĄrio pelo token (sem verificar expiraĂ§ĂŁo em SQL para evitar problemas de timezone)
    const user = await DB.prepare(
      `SELECT id, name, email, email_verified, verification_token_expires 
       FROM users 
       WHERE verification_token = ?`
    ).bind(token).first() as any
    
    console.log('đ UsuĂĄrio encontrado:', user ? `ID ${user.id}, email ${user.email}` : 'NENHUM')
    
    if (!user) {
      console.log('â Token nĂŁo encontrado no banco')
      return c.json({ 
        error: 'Token invĂĄlido ou jĂĄ utilizado. Solicite um novo email de verificaĂ§ĂŁo.' 
      }, 400)
    }
    
    // Verificar expiraĂ§ĂŁo em JavaScript (mais confiĂĄvel que datetime() do SQLite)
    if (user.verification_token_expires) {
      const now = new Date()
      const expires = new Date(user.verification_token_expires)
      console.log('â° VerificaĂ§ĂŁo de expiraĂ§ĂŁo - Agora:', now.toISOString(), '| Expira:', expires.toISOString())
      
      if (now > expires) {
        console.log('â Token expirado')
        return c.json({ 
          error: 'Token expirado. Solicite um novo link de verificaĂ§ĂŁo.' 
        }, 400)
      }
    }
    
    // Se jĂĄ estĂĄ verificado
    if (user.email_verified) {
      console.log('âšď¸ Email jĂĄ verificado anteriormente')
      return c.json({ 
        message: 'Email jĂĄ verificado. VocĂŞ pode fazer login.',
        alreadyVerified: true,
        success: true
      })
    }
    
    // Verificar o email
    await DB.prepare(
      `UPDATE users 
       SET email_verified = 1, 
           verification_token = NULL, 
           verification_token_expires = NULL 
       WHERE id = ?`
    ).bind(user.id).run()
    
    console.log('â Email verificado com sucesso para:', user.email)
    
    // Enviar email de boas-vindas
    try {
      await sendWelcomeEmail(user.email, user.name || 'UsuĂĄrio', c.env);
    } catch (welcomeError) {
      console.log('â ď¸ Erro ao enviar email de boas-vindas (nĂŁo crĂ­tico):', welcomeError)
    }
    
    // â v157: Gerar token de sessĂŁo no verify-email (usuĂĄrio provou posse do email via link)
    // Isso ĂŠ seguro porque o token de verificaĂ§ĂŁo ĂŠ single-use e foi enviado ao email do usuĂĄrio
    const secret = getAuthSecret(c.env)
    const sessionToken = await generateSessionToken(user.id, secret)
    await registerSession(DB, user.id, sessionToken, c)
    
    return c.json({ 
      message: 'Email verificado com sucesso! Agora vocĂŞ pode fazer login.',
      email: user.email,
      success: true,
      verified: true,
      token: sessionToken,
      user: { id: user.id, email: user.email, name: user.name }
    })
  } catch (error) {
    console.error('â Erro ao verificar email:', error)
    return c.json({ error: 'Erro ao verificar email' }, 500)
  }
})

// Solicitar recuperaĂ§ĂŁo de senha
app.post('/api/forgot-password', async (c) => {
  const { DB } = c.env
  const body = await c.req.json()
  const email = body.email?.toLowerCase()?.trim()
  
  if (!email || !isValidEmail(email)) {
    return c.json({ error: 'Email invĂĄlido' }, 400)
  }
  
  // â SEGURANĂA v146: Admin nĂŁo pode usar recuperaĂ§ĂŁo de senha (Google Only)
  if (email === ADMIN_EMAIL) {
    console.warn(`đ¨ SEGURANĂA: Tentativa de reset de senha bloqueada para admin (${email})`)
    return c.json({ 
      error: 'Esta conta utiliza exclusivamente autenticaĂ§ĂŁo via Google. NĂŁo ĂŠ possĂ­vel recuperar senha.',
      googleOnly: true
    }, 403)
  }
  
  try {
    // Buscar usuĂĄrio
    const user = await DB.prepare(
      'SELECT id, name, email_verified FROM users WHERE email = ?'
    ).bind(email).first() as any
    
    if (!user) {
      // Por seguranĂ§a, nĂŁo revelar se o email existe ou nĂŁo
      return c.json({ 
        message: 'Se o email estiver cadastrado, vocĂŞ receberĂĄ instruĂ§Ăľes de recuperaĂ§ĂŁo.',
        success: true 
      })
    }
    
    // Se email nĂŁo estĂĄ verificado, nĂŁo permitir reset
    if (!user.email_verified) {
      return c.json({ 
        error: 'Email nĂŁo verificado. Verifique seu email primeiro.',
        needsVerification: true 
      }, 403)
    }
    
    // Gerar token de reset
    const resetToken = generateSecureToken()
    
    // Salvar token no banco (vĂĄlido por 1 hora)
    await DB.prepare(
      `UPDATE users 
       SET reset_token = ?, 
           reset_token_expires = datetime('now', '+1 hour') 
       WHERE id = ?`
    ).bind(resetToken, user.id).run()
    
    // Enviar email de reset
    const emailSent = await sendPasswordResetEmail(email, resetToken, user.name, c.env)
    const APP_URL = c.env?.APP_URL || 'https://iaprova.app'
    const resetUrl = `${APP_URL}/resetar-senha?token=${resetToken}`
    
    console.log('đ Token de reset gerado:', resetToken)
    console.log('đ§ Email de reset enviado:', emailSent)
    
    // SEMPRE retornar o token para permitir reset manual
    return c.json({ 
      message: emailSent 
        ? 'Se o email estiver cadastrado, vocĂŞ receberĂĄ instruĂ§Ăľes de recuperaĂ§ĂŁo. Se nĂŁo receber, use o link abaixo.'
        : 'â Use o link abaixo para redefinir sua senha.',
      success: true,
      // SEMPRE retornar token e URL para permitir reset manual
      devToken: resetToken,
      devMode: !emailSent,
      resetUrl
    })
  } catch (error) {
    console.error('Erro ao processar recuperaĂ§ĂŁo de senha:', error)
    return c.json({ error: 'Erro ao processar solicitaĂ§ĂŁo' }, 500)
  }
})

