// â v157 SEGURANĂA: Endpoint para buscar usuĂĄrio por email â REQUER autenticaĂ§ĂŁo
// Nunca gera token â apenas retorna dados bĂĄsicos
app.get('/api/user-by-email', async (c) => {
  const { DB } = c.env
  const email = c.req.query('email')?.toLowerCase()?.trim()
  
  if (!email) {
    return c.json({ error: 'Email nĂŁo fornecido' }, 400)
  }
  
  // â v157: Exigir autenticaĂ§ĂŁo
  const authenticatedUserId = await getAuthenticatedUserId(c)
  if (!authenticatedUserId) {
    return c.json({ error: 'AutenticaĂ§ĂŁo obrigatĂłria' }, 401)
  }
  
  try {
    // Verificar se o solicitante ĂŠ o dono do email ou admin
    const requestingUser = await DB.prepare('SELECT email FROM users WHERE id = ?').bind(authenticatedUserId).first() as any
    const isAdminUser = requestingUser?.email === ADMIN_EMAIL
    
    if (!isAdminUser && requestingUser?.email !== email) {
      return c.json({ error: 'Acesso negado â sĂł pode consultar seu prĂłprio email' }, 403)
    }
    
    const user = await DB.prepare(
      'SELECT id, email, name, created_at, email_verified FROM users WHERE email = ?'
    ).bind(email).first() as any
    
    if (!user) {
      return c.json({ error: 'UsuĂĄrio nĂŁo encontrado' }, 404)
    }
    
    return c.json({ 
      user: { id: user.id, email: user.email, name: user.name, email_verified: user.email_verified }
    })
  } catch (error) {
    console.error('Erro ao buscar usuĂĄrio:', error)
    return c.json({ error: 'Erro ao buscar usuĂĄrio' }, 500)
  }
})

