// Atualizar usuĂĄrio
// â ď¸ SEGURANĂA: Email NĂO pode ser alterado pelo usuĂĄrio (apenas admin)
// â v155 SEGURANĂA: Atualizar perfil â REQUER token autenticado
// O usuĂĄrio sĂł pode alterar SEU PRĂPRIO perfil, NUNCA o de outro
// Conta admin ĂŠ IMUTĂVEL por esta rota
app.put('/api/users/:id', async (c) => {
  const { DB } = c.env
  const id = c.req.param('id')

  // â v155: EXIGIR autenticaĂ§ĂŁo por token
  const authenticatedUserId = await getAuthenticatedUserId(c)
  if (!authenticatedUserId) {
    return c.json({ error: 'AutenticaĂ§ĂŁo obrigatĂłria' }, 401)
  }

  // â v155: SĂł pode editar SEU PRĂPRIO perfil
  if (authenticatedUserId.toString() !== id.toString()) {
    console.warn(`đ¨ SEGURANĂA v155: UsuĂĄrio ${authenticatedUserId} tentou editar perfil do usuĂĄrio ${id}`)
    return c.json({ error: 'Acesso negado â vocĂŞ sĂł pode editar seu prĂłprio perfil' }, 403)
  }

  const { name, password } = await c.req.json()

  try {
    const user = await DB.prepare(
      'SELECT id, email FROM users WHERE id = ?'
    ).bind(id).first() as any

    if (!user) {
      return c.json({ error: 'UsuĂĄrio nĂŁo encontrado' }, 404)
    }

    // â v155: Conta admin ĂŠ IMUTĂVEL por esta rota
    if (user.email === ADMIN_EMAIL) {
      console.warn(`đ¨ SEGURANĂA v155: Tentativa de alterar conta admin via PUT /api/users/${id} â BLOQUEADO`)
      return c.json({ error: 'Conta de administrador nĂŁo pode ser alterada por esta rota' }, 403)
    }

    // Apenas name e password â email NUNCA ĂŠ alterĂĄvel
    const updates: string[] = []
    const params: any[] = []

    if (name && typeof name === 'string' && name.trim().length > 0 && name.trim().length <= 100) {
      updates.push('name = ?')
      params.push(name.trim())
    }
    if (password && typeof password === 'string' && password.length >= 4) {
      updates.push('password = ?')
      params.push(password)
    }

    if (updates.length === 0) {
      return c.json({ error: 'Nenhum dado vĂĄlido para atualizar' }, 400)
    }

    params.push(id)

    await DB.prepare(
      `UPDATE users SET ${updates.join(', ')} WHERE id = ?`
    ).bind(...params).run()

    const updatedUser = await DB.prepare(
      'SELECT id, name, email, created_at FROM users WHERE id = ?'
    ).bind(id).first()

    return c.json({ 
      ...updatedUser,
      message: 'Perfil atualizado com sucesso'
    })
  } catch (error) {
    console.error('Erro ao atualizar usuĂĄrio:', error)
    return c.json({ error: 'Erro ao atualizar usuĂĄrio' }, 500)
  }
})

