    if (cargoUpper.includes('FISIOTERAPEUTA')) variacoesCargo.push('FISIOTERAPEUTA', 'FISIOTERAPIA')
    if (cargoUpper.includes('NUTRICIONISTA')) variacoesCargo.push('NUTRICIONISTA', 'NUTRIĂĂO')
    if (cargoUpper.includes('PSICĂLOGO')) variacoesCargo.push('PSICĂLOGO', 'PSICĂLOGA', 'PSICOLOGIA')
    if (cargoUpper.includes('ADMINISTRADOR')) variacoesCargo.push('ADMINISTRADOR', 'ADMINISTRAĂĂO')
