// â CRUD de TĂłpicos - Excluir tĂłpico
// â CORREĂĂO DEFINITIVA v8: Remover TODAS as referĂŞncias antes de excluir
app.delete('/api/topicos/:topico_id', async (c) => {
  const { DB } = c.env
  const topico_id = c.req.param('topico_id')
  
  console.log(`đď¸ Iniciando exclusĂŁo do tĂłpico ${topico_id}`)
  
  try {
    // â CORREĂĂO v8: Remover TODAS as FKs em ordem correta
    
    // 1. Remover progresso do usuĂĄrio
    try {
      await DB.prepare('DELETE FROM user_topicos_progresso WHERE topico_id = ?').bind(topico_id).run()
      console.log(`   â Removido progresso do tĂłpico ${topico_id}`)
    } catch (e) {
      console.log(`   â  Tabela user_topicos_progresso: ${e}`)
    }
    
    // 2. Remover relaĂ§Ăľes com conteĂşdos
    try {
      await DB.prepare('DELETE FROM conteudo_topicos WHERE topico_id = ?').bind(topico_id).run()
      console.log(`   â Removido conteudo_topicos do tĂłpico ${topico_id}`)
    } catch (e) {
      console.log(`   â  Tabela conteudo_topicos: ${e}`)
    }
    
    // 3. â NOVO: Desvinvular materiais_salvos (SET NULL em vez de DELETE)
    try {
      await DB.prepare('UPDATE materiais_salvos SET topico_id = NULL WHERE topico_id = ?').bind(topico_id).run()
      console.log(`   â Desvinculado materiais_salvos do tĂłpico ${topico_id}`)
    } catch (e) {
      console.log(`   â  Tabela materiais_salvos: ${e}`)
    }
    
    // 4. â NOVO: Remover de conteudo_estudo se existir
    try {
      await DB.prepare('UPDATE conteudo_estudo SET topico_id = NULL WHERE topico_id = ?').bind(topico_id).run()
      console.log(`   â Desvinculado conteudo_estudo do tĂłpico ${topico_id}`)
    } catch (e) {
      console.log(`   â  Tabela conteudo_estudo: ${e}`)
    }
    
    // 5. Agora excluir o tĂłpico
    const result = await DB.prepare('DELETE FROM topicos_edital WHERE id = ?').bind(topico_id).run()
    
    if (result.meta.changes === 0) {
      console.log(`â ď¸ TĂłpico ${topico_id} nĂŁo encontrado ou jĂĄ excluĂ­do`)
      return c.json({ success: true, warning: 'TĂłpico jĂĄ nĂŁo existia' })
    }
    
    console.log(`â TĂłpico ${topico_id} excluĂ­do com sucesso`)
    return c.json({ success: true })
  } catch (error: any) {
    console.error('â Erro ao excluir tĂłpico:', error)
    return c.json({ error: 'Erro ao excluir tĂłpico: ' + error.message }, 500)
  }
})

