// â NOVO: Sincronizar pesos dos tĂłpicos com disciplinas pai
app.post('/api/topicos/sincronizar-pesos', async (c) => {
  const { DB } = c.env
  
  try {
    console.log('đ Iniciando sincronizaĂ§ĂŁo de pesos dos tĂłpicos...')
    
    // Atualizar peso dos tĂłpicos baseado na disciplina pai via edital_disciplinas
    // edital_disciplinas tem o peso correto da disciplina
    const result = await DB.prepare(`
      UPDATE topicos_edital 
      SET peso = (
        SELECT COALESCE(ed.peso, 1)
        FROM edital_disciplinas ed 
        WHERE ed.disciplina_id = topicos_edital.disciplina_id
        LIMIT 1
      )
      WHERE disciplina_id IN (
        SELECT DISTINCT disciplina_id FROM edital_disciplinas WHERE peso IS NOT NULL
      )
    `).run()
    
    console.log(`â TĂłpicos atualizados: ${result.meta.changes || 0}`)
    
    // Buscar estatĂ­sticas
    const stats = await DB.prepare(`
      SELECT 
        COUNT(*) as total_topicos,
        SUM(CASE WHEN peso = 1 THEN 1 ELSE 0 END) as peso_1,
        SUM(CASE WHEN peso = 2 THEN 1 ELSE 0 END) as peso_2,
        SUM(CASE WHEN peso = 3 THEN 1 ELSE 0 END) as peso_3
      FROM topicos_edital
    `).first()
    
    return c.json({ 
      success: true, 
      message: 'Pesos dos tĂłpicos sincronizados com sucesso!',
      topicos_atualizados: result.meta.changes || 0,
      estatisticas: stats
    })
  } catch (error) {
    console.error('Erro ao sincronizar pesos:', error)
    return c.json({ error: 'Erro ao sincronizar pesos' }, 500)
  }
})

// â NOVO v2: Limpar tĂłpicos duplicados mantendo apenas um de cada POR USUĂRIO
app.post('/api/topicos/limpar-duplicados', async (c) => {
  const { DB } = c.env
  
  try {
    console.log('đ§š Iniciando limpeza de tĂłpicos duplicados por usuĂĄrio...')
    
    // 1. Contar duplicados antes
    const antes = await DB.prepare(`
      SELECT COUNT(*) as total FROM topicos_edital
    `).first() as any
    
    // 2. Identificar duplicados: mesmo user_id + disciplina_id + nome
    // Manter apenas o com menor ID (mais antigo) para cada combinaĂ§ĂŁo
    const duplicados = await DB.prepare(`
      DELETE FROM topicos_edital 
      WHERE id NOT IN (
        SELECT MIN(id) 
        FROM topicos_edital 
        GROUP BY COALESCE(user_id, 0), disciplina_id, LOWER(TRIM(nome))
      )
    `).run()
    
    // 3. Contar apĂłs limpeza
    const depois = await DB.prepare(`
      SELECT COUNT(*) as total FROM topicos_edital
    `).first() as any
    
    // 4. EstatĂ­sticas por usuĂĄrio e disciplina
    const { results: estatsPorUsuario } = await DB.prepare(`
      SELECT 
        user_id,
        COUNT(DISTINCT disciplina_id) as total_disciplinas,
        COUNT(*) as total_topicos
      FROM topicos_edital
      GROUP BY user_id
    `).all()
    
    console.log(`â Limpeza concluĂ­da: ${antes.total} â ${depois.total} tĂłpicos (${duplicados.meta.changes} removidos)`)
    
    return c.json({ 
      success: true, 
      message: 'TĂłpicos duplicados removidos com sucesso!',
      antes: antes.total,
      depois: depois.total,
      removidos: duplicados.meta.changes || 0,
      por_usuario: estatsPorUsuario
    })
  } catch (error) {
    console.error('Erro ao limpar duplicados:', error)
    return c.json({ error: 'Erro ao limpar duplicados' }, 500)
  }
})

// Criar/atualizar tĂłpicos para uma disciplina (baseado no edital/ĂĄrea)
app.post('/api/topicos/gerar/:disciplina_id', async (c) => {
  const { DB } = c.env
  const disciplina_id = c.req.param('disciplina_id')
  const { topicos, user_id } = await c.req.json() // Array de { nome, categoria, ordem, peso } + user_id
  
  if (!user_id) {
    return c.json({ error: 'user_id ĂŠ obrigatĂłrio' }, 400)
  }
  
  try {
    // â Limpar tĂłpicos existentes APENAS DESTE USUĂRIO
    await DB.prepare('DELETE FROM topicos_edital WHERE disciplina_id = ? AND user_id = ?').bind(disciplina_id, user_id).run()
    
    // â v54 BATCH: Inserir novos tĂłpicos com user_id em batch
    if (topicos && topicos.length > 0) {
      const batchTopicosGerar = topicos.map((topico: any) =>
        DB.prepare(`INSERT INTO topicos_edital (disciplina_id, nome, categoria, ordem, peso, user_id) VALUES (?, ?, ?, ?, ?, ?)`)
          .bind(disciplina_id, topico.nome, topico.categoria || 'Geral', topico.ordem || 0, topico.peso || 1, user_id)
      )
      const BATCH_GER = 80
      for (let s = 0; s < batchTopicosGerar.length; s += BATCH_GER) {
        await DB.batch(batchTopicosGerar.slice(s, s + BATCH_GER))
      }
    }
    
    return c.json({ success: true, total: topicos.length })
  } catch (error) {
    console.error('Erro ao gerar tĂłpicos:', error)
    return c.json({ error: 'Erro ao gerar tĂłpicos' }, 500)
  }
})

// Popular tĂłpicos para todas as disciplinas de um usuĂĄrio
app.post('/api/topicos/popular-usuario/:user_id', async (c) => {
  const { DB } = c.env
  const user_id = c.req.param('user_id')
  
  try {
    // Buscar todas as disciplinas do usuĂĄrio
    const { results: disciplinas } = await DB.prepare(`
      SELECT ud.disciplina_id, d.nome
      FROM user_disciplinas ud
      JOIN disciplinas d ON ud.disciplina_id = d.id
      WHERE ud.user_id = ?
    `).bind(user_id).all()
    
    let totalPopulado = 0
    
    for (const disc of disciplinas) {
      await popularTopicosEdital(DB, disc.disciplina_id)
      
      // Verificar quantos foram inseridos
      const { results: topicos } = await DB.prepare(
        'SELECT id FROM topicos_edital WHERE disciplina_id = ?'
      ).bind(disc.disciplina_id).all()
      
      if (topicos && topicos.length > 0) {
        totalPopulado++
      }
    }
    
    return c.json({ 
      success: true, 
      disciplinas_processadas: disciplinas.length,
      disciplinas_com_topicos: totalPopulado
    })
  } catch (error) {
    console.error('Erro ao popular tĂłpicos do usuĂĄrio:', error)
    return c.json({ error: 'Erro ao popular tĂłpicos' }, 500)
  }
})

// Buscar progresso do usuĂĄrio nos tĂłpicos de uma disciplina
// â CORREĂĂO v5: Aceita ?plano_id=X para filtrar por plano especĂ­fico
app.get('/api/user-topicos/:user_id/:disciplina_id', async (c) => {
  const { DB } = c.env
  const user_id = c.req.param('user_id')
  const disciplina_id = c.req.param('disciplina_id')
  const plano_id = c.req.query('plano_id') // â NOVO: Filtrar por plano

  // â CORREĂĂO v5: Se plano_id fornecido, filtrar por plano (isolamento entre planos)
  let results: any[] = []
  
  if (plano_id) {
    // Buscar tĂłpicos APENAS do plano especĂ­fico
    console.log(`đ Buscando tĂłpicos da disciplina ${disciplina_id} no plano ${plano_id}...`)
    
    const { results: topicosPlano } = await DB.prepare(`
      SELECT 
        te.id,
        te.disciplina_id,
        te.nome,
        te.categoria,
        te.ordem,
        COALESCE(te.peso, 1) as peso,
        COALESCE(utp.vezes_estudado, 0) as vezes_estudado,
        COALESCE(utp.nivel_dominio, 0) as nivel_dominio,
        utp.ultima_vez
      FROM topicos_edital te
      LEFT JOIN user_topicos_progresso utp ON te.id = utp.topico_id AND utp.plano_id = ?
      WHERE te.disciplina_id = ? AND te.plano_id = ?
      ORDER BY te.ordem, te.nome
    `).bind(plano_id, disciplina_id, plano_id).all()
    
    results = topicosPlano || []
    console.log(`â Encontrados ${results.length} tĂłpicos no plano ${plano_id}`)
  } else {
    // Fallback: filtrar por user_id (comportamento antigo para compatibilidade)
    const { results: topicosUser } = await DB.prepare(`
      SELECT 
        te.id,
        te.disciplina_id,
        te.nome,
        te.categoria,
        te.ordem,
        COALESCE(te.peso, (
          SELECT ed.peso FROM edital_disciplinas ed 
          WHERE ed.disciplina_id = te.disciplina_id 
          LIMIT 1
        ), 1) as peso,
        COALESCE(utp.vezes_estudado, 0) as vezes_estudado,
        COALESCE(utp.nivel_dominio, 0) as nivel_dominio,
        utp.ultima_vez
      FROM topicos_edital te
      LEFT JOIN user_topicos_progresso utp ON te.id = utp.topico_id AND utp.user_id = ?
      WHERE te.disciplina_id = ? AND te.user_id = ?
      ORDER BY te.ordem, te.nome
    `).bind(user_id, disciplina_id, user_id).all()
    
    results = topicosUser || []
  }

  // â Se nĂŁo encontrou tĂłpicos e temos plano_id, tentar copiar do edital para o plano
  if ((!results || results.length === 0) && plano_id) {
    console.log(`đ Nenhum tĂłpico no plano ${plano_id}, tentando copiar do edital...`)
    
    // Buscar edital do usuĂĄrio
    const editalUsuario = await DB.prepare(`
      SELECT id FROM editais WHERE user_id = ? ORDER BY created_at DESC LIMIT 1
    `).bind(user_id).first() as any
    
    // Copiar tĂłpicos para este plano
    await copiarTopicosParaPlano(
      DB,
      parseInt(plano_id),
      parseInt(user_id),
      [parseInt(disciplina_id)],
      editalUsuario?.id || undefined
    )
    
    // Buscar novamente
    const { results: novosTopicos } = await DB.prepare(`
      SELECT 
        te.id,
        te.disciplina_id,
        te.nome,
        te.categoria,
        te.ordem,
        COALESCE(te.peso, 1) as peso,
        COALESCE(utp.vezes_estudado, 0) as vezes_estudado,
        COALESCE(utp.nivel_dominio, 0) as nivel_dominio,
        utp.ultima_vez
      FROM topicos_edital te
      LEFT JOIN user_topicos_progresso utp ON te.id = utp.topico_id AND utp.plano_id = ?
      WHERE te.disciplina_id = ? AND te.plano_id = ?
      ORDER BY te.ordem, te.nome
    `).bind(plano_id, disciplina_id, plano_id).all()
    
    results = novosTopicos || []
    console.log(`â Copiados e encontrados ${results.length} tĂłpicos no plano ${plano_id}`)
  }
  // Fallback legado (sem plano_id): buscar em edital_topicos
  else if (!results || results.length === 0) {
    console.log(`đ Buscando tĂłpicos em edital_topicos para disciplina ${disciplina_id} do user ${user_id}...`)
    
    // â CORREĂĂO v4: Buscar apenas tĂłpicos do edital DO USUĂRIO
    const { results: editalTopicos } = await DB.prepare(`
      SELECT 
        et.id,
        et.nome,
        et.ordem,
        'ConteĂşdo ProgramĂĄtico' as categoria,
        COALESCE(ed.peso, 1) as peso,
        ed.disciplina_id,
        0 as vezes_estudado,
        0 as nivel_dominio,
        NULL as ultima_vez
      FROM edital_topicos et
      JOIN edital_disciplinas ed ON et.edital_disciplina_id = ed.id
      JOIN editais e ON ed.edital_id = e.id
      WHERE ed.disciplina_id = ? AND e.user_id = ?
      ORDER BY et.ordem, et.nome
    `).bind(disciplina_id, user_id).all()
    
    if (editalTopicos && editalTopicos.length > 0) {
      console.log(`â Encontrados ${editalTopicos.length} tĂłpicos no edital com pesos herdados para user ${user_id}`)
      
      // â CORREĂĂO: Copiar para topicos_edital COM o peso da disciplina E user_id
      for (const topico of editalTopicos as any[]) {
        try {
          await DB.prepare(`
            INSERT OR IGNORE INTO topicos_edital (disciplina_id, nome, categoria, ordem, peso, user_id)
            VALUES (?, ?, ?, ?, ?, ?)
          `).bind(disciplina_id, topico.nome, 'ConteĂşdo ProgramĂĄtico', topico.ordem, topico.peso, user_id).run()
        } catch (e) {
          // Ignorar duplicatas
        }
      }
      
      // â CORREĂĂO v2: Buscar novamente sem duplicaĂ§ĂŁo - FILTRANDO POR USER_ID
      const { results: novosTopicos } = await DB.prepare(`
        SELECT 
          te.id,
          te.disciplina_id,
          te.nome,
          te.categoria,
          te.ordem,
          COALESCE(te.peso, (
            SELECT ed.peso FROM edital_disciplinas ed 
            WHERE ed.disciplina_id = te.disciplina_id 
            LIMIT 1
          ), 1) as peso,
          COALESCE(utp.vezes_estudado, 0) as vezes_estudado,
          COALESCE(utp.nivel_dominio, 0) as nivel_dominio,
          utp.ultima_vez
        FROM topicos_edital te
        LEFT JOIN user_topicos_progresso utp ON te.id = utp.topico_id AND utp.user_id = ?
        WHERE te.disciplina_id = ? AND te.user_id = ?
        ORDER BY te.ordem, te.nome
      `).bind(user_id, disciplina_id, user_id).all()
      
      results = novosTopicos
    }
  }

  return c.json(results)
})

// â POST para salvar/atualizar progresso de um tĂłpico
// â CORREĂĂO v5: Aceita plano_id para isolamento entre planos
app.post('/api/user-topicos/progresso', async (c) => {
  const { DB } = c.env
  const { user_id, topico_id, vezes_estudado, nivel_dominio, plano_id } = await c.req.json()
  
  console.log('đ Atualizando progresso do tĂłpico:', { user_id, topico_id, vezes_estudado, nivel_dominio, plano_id })
  
  try {
    // â CORREĂĂO DEFINITIVA v8: Buscar plano ativo se nĂŁo fornecido
    let planoAtivo = plano_id
    if (!planoAtivo) {
      const plano = await DB.prepare(`
        SELECT id FROM planos_estudo WHERE user_id = ? AND ativo = 1 LIMIT 1
      `).bind(user_id).first() as any
      planoAtivo = plano?.id || null
    }
    
    // â CORREĂĂO v8: Usar INSERT OR REPLACE para evitar problemas de constraint
    // A tabela tem UNIQUE(user_id, topico_id), entĂŁo precisamos atualizar/inserir por essa combinaĂ§ĂŁo
    // Mas tambĂŠm precisamos garantir que o plano_id seja considerado
    
    // Primeiro, verificar se existe registro para este usuĂĄrio/tĂłpico
    const existing = await DB.prepare(`
      SELECT id, plano_id FROM user_topicos_progresso WHERE user_id = ? AND topico_id = ?
    `).bind(user_id, topico_id).first() as any
    
    if (existing) {
      // â v85: Atualizar registro e FORĂAR plano_id quando fornecido
      await DB.prepare(`
        UPDATE user_topicos_progresso 
        SET vezes_estudado = ?, 
            nivel_dominio = ?, 
            ultima_vez = CURRENT_TIMESTAMP,
            plano_id = ?
        WHERE user_id = ? AND topico_id = ?
      `).bind(vezes_estudado, nivel_dominio, planoAtivo || existing.plano_id, user_id, topico_id).run()
      console.log(`â Progresso atualizado (UPDATE) para tĂłpico ${topico_id}, plano: ${planoAtivo || existing.plano_id}`)
    } else {
      // â Inserir novo registro
      await DB.prepare(`
        INSERT INTO user_topicos_progresso (user_id, topico_id, vezes_estudado, nivel_dominio, ultima_vez, plano_id)
        VALUES (?, ?, ?, ?, CURRENT_TIMESTAMP, ?)
      `).bind(user_id, topico_id, vezes_estudado, nivel_dominio, planoAtivo).run()
      console.log(`â Progresso inserido (INSERT) para tĂłpico ${topico_id}, plano: ${planoAtivo}`)
    }
    
    return c.json({ success: true })
  } catch (error: any) {
    console.error('â Erro ao atualizar progresso:', error)
    return c.json({ error: 'Erro ao atualizar progresso: ' + error.message }, 500)
  }
})

// FunĂ§ĂŁo auxiliar para popular tĂłpicos do edital baseado na disciplina
async function popularTopicosEdital(DB: any, disciplina_id: number, user_id?: number) {
  try {
    // Buscar nome da disciplina
    const disciplina = await DB.prepare('SELECT nome FROM disciplinas WHERE id = ?').bind(disciplina_id).first()
    if (!disciplina) return
    
    const nomeDisciplina = disciplina.nome
    const topicos = TOPICOS_POR_DISCIPLINA[nomeDisciplina]
    
    if (!topicos || topicos.length === 0) {
      console.log(`â ď¸ NĂŁo hĂĄ tĂłpicos prĂŠ-definidos para: ${nomeDisciplina}`)
      return
    }
    
    // â CORREĂĂO: Verificar se jĂĄ existem tĂłpicos para essa disciplina E USUĂRIO
    const { results: topicosExistentes } = await DB.prepare(
      user_id 
        ? 'SELECT id FROM topicos_edital WHERE disciplina_id = ? AND user_id = ?'
        : 'SELECT id FROM topicos_edital WHERE disciplina_id = ? AND user_id IS NULL'
    ).bind(...(user_id ? [disciplina_id, user_id] : [disciplina_id])).all()
    
    if (topicosExistentes && topicosExistentes.length > 0) {
      console.log(`â Disciplina ${nomeDisciplina} jĂĄ possui ${topicosExistentes.length} tĂłpicos para user ${user_id || 'global'}`)
      return
    }
    
    // â CORREĂĂO: Inserir tĂłpicos COM user_id (INSERT OR IGNORE para evitar duplicatas)
    for (const topico of topicos) {
      await DB.prepare(`
        INSERT OR IGNORE INTO topicos_edital (disciplina_id, nome, categoria, ordem, peso, user_id)
        VALUES (?, ?, ?, ?, ?, ?)
      `).bind(
        disciplina_id,
        topico.nome,
        topico.categoria,
        topico.ordem,
        topico.peso,
        user_id || null
      ).run()
    }
    
    console.log(`â Inseridos ${topicos.length} tĂłpicos para: ${nomeDisciplina}`)
  } catch (error) {
    console.error('â Erro ao popular tĂłpicos do edital:', error)
  }
}

// Algoritmo de distĂ˘ncia de Levenshtein para similaridade de strings
function levenshteinDistance(str1: string, str2: string): number {
  const len1 = str1.length
  const len2 = str2.length
  const matrix: number[][] = []

  // Inicializar matriz
  for (let i = 0; i <= len1; i++) {
    matrix[i] = [i]
  }
  for (let j = 0; j <= len2; j++) {
    matrix[0][j] = j
  }

  // Calcular distĂ˘ncias
  for (let i = 1; i <= len1; i++) {
    for (let j = 1; j <= len2; j++) {
      const cost = str1[i - 1] === str2[j - 1] ? 0 : 1
      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1,     // DeleĂ§ĂŁo
        matrix[i][j - 1] + 1,     // InserĂ§ĂŁo
        matrix[i - 1][j - 1] + cost // SubstituiĂ§ĂŁo
      )
    }
  }

  return matrix[len1][len2]
}

// Calcular similaridade entre duas strings (0 a 1, onde 1 = idĂŞnticas)
function calcularSimilaridade(str1: string, str2: string): number {
  const maxLen = Math.max(str1.length, str2.length)
  if (maxLen === 0) return 1.0
  
  const distance = levenshteinDistance(str1.toLowerCase(), str2.toLowerCase())
  return 1 - (distance / maxLen)
}

