// â Endpoint para retornar progresso de metas desde a Semana 1 atĂŠ a prova (ou indefinidamente)
app.get('/api/estatisticas/:user_id/progresso-semanal', async (c) => {
  const { DB } = c.env
  const user_id = c.req.param('user_id')
  const visualizacao = c.req.query('view') || 'semana' // 'semana' ou 'mes'
  
  try {
    // Buscar plano ativo do usuĂĄrio com data_prova (jĂĄ na tabela planos_estudo)
    const plano = await DB.prepare(`
      SELECT * FROM planos_estudo 
      WHERE user_id = ? AND ativo = 1
      ORDER BY created_at DESC LIMIT 1
    `).bind(user_id).first() as any
    
    if (!plano) {
      return c.json({ 
        semanas: [], 
        meses: [],
        mediaGeral: 0,
        temDataProva: false,
        semanasAteFim: 0
      })
    }
    
    const dataInicioPlano = new Date(plano.created_at)
    const hoje = new Date()
    const dataProva = plano.data_prova ? new Date(plano.data_prova) : null
    
    // Calcular semanas desde o inĂ­cio do plano
    const semanas: any[] = []
    const meses: any[] = []
    
    // Calcular quantas semanas mostrar
    let dataFinal = dataProva || hoje
    if (dataFinal < hoje) dataFinal = hoje // Se a prova jĂĄ passou, mostrar atĂŠ hoje
    
    const diffMs = dataFinal.getTime() - dataInicioPlano.getTime()
    const totalSemanas = Math.max(1, Math.ceil(diffMs / (7 * 24 * 60 * 60 * 1000)))
    const semanaAtual = Math.ceil((hoje.getTime() - dataInicioPlano.getTime()) / (7 * 24 * 60 * 60 * 1000))
    
    // Gerar dados para cada semana
    for (let i = 1; i <= totalSemanas; i++) {
      const inicioSemana = new Date(dataInicioPlano)
      inicioSemana.setDate(dataInicioPlano.getDate() + ((i - 1) * 7))
      
      const fimSemana = new Date(inicioSemana)
      fimSemana.setDate(inicioSemana.getDate() + 6)
      
      const inicioStr = inicioSemana.toISOString().split('T')[0]
      const fimStr = fimSemana.toISOString().split('T')[0]
      
      // SĂł buscar dados para semanas passadas ou atual
      let metasConcluidas = 0
      let metasTotal = 0
      let diasEstudados = 0
      let tempoMinutos = 0
      
      if (inicioSemana <= hoje) {
        // Buscar dados do historico_estudos que jĂĄ tem metas_concluidas agregadas por dia
        const historicoRes = await DB.prepare(`
          SELECT 
            COALESCE(SUM(metas_concluidas), 0) as metas_concluidas,
            COALESCE(SUM(metas_total), 0) as metas_total,
            COUNT(DISTINCT CASE WHEN status != 'nao_estudou' THEN data END) as dias_estudados,
            COALESCE(SUM(tempo_estudado_minutos), 0) as tempo_minutos
          FROM historico_estudos
          WHERE user_id = ? AND data >= ? AND data <= ?
        `).bind(user_id, inicioStr, fimStr).first() as any
        
        metasConcluidas = historicoRes?.metas_concluidas || 0
        metasTotal = historicoRes?.metas_total || 0
        diasEstudados = historicoRes?.dias_estudados || 0
        tempoMinutos = historicoRes?.tempo_minutos || 0
      }
      
      const percentual = metasTotal > 0 ? Math.round((metasConcluidas / metasTotal) * 100) : 0
      const isFutura = inicioSemana > hoje
      const isAtual = i === semanaAtual
      const isProva = dataProva && i === totalSemanas
      
      semanas.push({
        numero: i,
        label: `Sem ${i}`,
        inicio: inicioStr,
        fim: fimStr,
        metasConcluidas,
        metasTotal,
        diasEstudados,
        tempoMinutos,
        percentual,
        isFutura,
        isAtual,
        isProva
      })
    }
    
    // Agrupar por mĂŞs
    const mesesMap = new Map<string, any>()
    semanas.forEach(sem => {
      const mesAno = sem.inicio.substring(0, 7) // YYYY-MM
      const [ano, mes] = mesAno.split('-')
      const labelMes = new Date(parseInt(ano), parseInt(mes) - 1).toLocaleDateString('pt-BR', { month: 'short', year: '2-digit' })
      
      if (!mesesMap.has(mesAno)) {
        mesesMap.set(mesAno, {
          label: labelMes,
          mesAno,
          metasConcluidas: 0,
          metasTotal: 0,
          diasEstudados: 0,
          tempoMinutos: 0,
          semanasCount: 0
        })
      }
      
      const mesData = mesesMap.get(mesAno)
      mesData.metasConcluidas += sem.metasConcluidas
      mesData.metasTotal += sem.metasTotal
      mesData.diasEstudados += sem.diasEstudados
      mesData.tempoMinutos += sem.tempoMinutos
      mesData.semanasCount++
    })
    
    mesesMap.forEach((mes, key) => {
      mes.percentual = mes.metasTotal > 0 ? Math.round((mes.metasConcluidas / mes.metasTotal) * 100) : 0
      meses.push(mes)
    })
    
    // Calcular mĂŠdia geral (apenas semanas passadas)
    const semanasConcluidas = semanas.filter(s => !s.isFutura)
    const mediaGeral = semanasConcluidas.length > 0 
      ? Math.round(semanasConcluidas.reduce((acc, s) => acc + s.percentual, 0) / semanasConcluidas.length)
      : 0
    
    return c.json({
      semanas,
      meses,
      mediaGeral,
      temDataProva: !!dataProva,
      dataProva: dataProva?.toISOString().split('T')[0] || null,
      semanaAtual,
      totalSemanas,
      semanasRestantes: Math.max(0, totalSemanas - semanaAtual)
    })
  } catch (error) {
    console.error('Erro ao buscar progresso semanal:', error)
    return c.json({ error: 'Erro ao buscar estatĂ­sticas' }, 500)
  }
})

// ============== ROTAS DE METAS SEMANAIS ==============

// 1. Gerar metas para uma semana completa
app.post('/api/metas/gerar-semana/:user_id', async (c) => {
  const { DB } = c.env
  const user_id = parseInt(c.req.param('user_id'))
  const { plano_id, data_inicio, dias_customizados } = await c.req.json()

  console.log('đ Gerando metas semanais:', { user_id, plano_id, data_inicio, dias_customizados })

  try {
    // â CORREĂĂO: Desativar TODAS as semanas antigas do usuĂĄrio antes de criar nova
    await DB.prepare(`
      UPDATE semanas_estudo 
      SET status = 'concluida' 
      WHERE user_id = ? AND status = 'ativa'
    `).bind(user_id).run()
    
    console.log(`â Semanas antigas desativadas para user_id ${user_id}`)

    // Calcular data_fim (domingo da mesma semana)
    const dataInicio = new Date(data_inicio)
    const diaInicioNum = dataInicio.getDay() // 0=Dom, 1=Seg, ..., 6=SĂĄb
    
    // â CORREĂĂO: Calcular data_fim como o prĂłximo domingo
    // Se hoje ĂŠ quinta (4), faltam 6-4=2 dias atĂŠ sĂĄbado + 1 = 3 dias atĂŠ domingo
    // Mas domingo ĂŠ 0, entĂŁo: (7 - diaInicio) % 7 = dias atĂŠ domingo
    const dataFim = new Date(dataInicio)
    const diasAteDomingo = diaInicioNum === 0 ? 0 : (7 - diaInicioNum)
    dataFim.setDate(dataFim.getDate() + diasAteDomingo)
    
    console.log(`đ Semana: ${data_inicio} (${['Dom','Seg','Ter','Qua','Qui','Sex','SĂĄb'][diaInicioNum]}) atĂŠ ${dataFim.toISOString().split('T')[0]} (Dom)`)

    // Calcular nĂşmero da semana baseado na DATA do plano (nĂŁo no COUNT)
    const plano = await DB.prepare('SELECT id, created_at FROM planos_estudo WHERE id = ?').bind(plano_id).first()
    
    // â CORREĂĂO: Validar se plano existe
    if (!plano || !plano.id) {
      console.error(`â Plano nĂŁo encontrado: ${plano_id}`)
      return c.json({ error: 'Plano de estudos nĂŁo encontrado', code: 'PLAN_NOT_FOUND' }, 404)
    }
    
    const dataInicioPlano = new Date(plano.created_at || new Date())
    const diffTime = Math.abs(dataInicio.getTime() - dataInicioPlano.getTime())
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24))
    const numeroSemana = Math.max(1, Math.floor(diffDays / 7) + 1) // Garante mĂ­nimo 1

    // Criar registro de semana
    const semanaResult = await DB.prepare(`
      INSERT INTO semanas_estudo (user_id, plano_id, numero_semana, data_inicio, data_fim, status)
      VALUES (?, ?, ?, ?, ?, 'ativa')
    `).bind(user_id, plano_id, numeroSemana, data_inicio, dataFim.toISOString().split('T')[0]).run()

    const semana_id = semanaResult.meta.last_row_id

    // Buscar ciclos do plano
    const { results: ciclos } = await DB.prepare(`
      SELECT * FROM ciclos_estudo 
      WHERE plano_id = ? 
      ORDER BY ordem
    `).bind(plano_id).all()

    // â CORREĂĂO: Validar se existem ciclos
    if (!ciclos || ciclos.length === 0) {
      console.error(`â Nenhum ciclo encontrado para o plano ${plano_id}`)
      return c.json({ 
        error: 'Nenhum ciclo de estudos encontrado. Crie um novo plano.', 
        code: 'NO_CYCLES_IN_PLAN' 
      }, 400)
    }

    // â CORREĂĂO v19.5: Buscar APENAS disciplinas ĂNICAS do PLANO (ciclos_estudo)
    // NĂŁo usar edital completo, apenas as disciplinas SELECIONADAS pelo usuĂĄrio
    
    const { results: disciplinasDoPlano } = await DB.prepare(`
      SELECT 
        c.disciplina_id,
        d.nome,
        MAX(ed.id) as edital_disciplina_id
      FROM ciclos_estudo c
      JOIN disciplinas d ON c.disciplina_id = d.id
      LEFT JOIN edital_disciplinas ed ON LOWER(TRIM(ed.nome)) = LOWER(TRIM(d.nome))
      WHERE c.plano_id = ?
      GROUP BY c.disciplina_id, d.nome
    `).bind(plano_id).all()

    console.log(`đ METAS - Disciplinas do plano: ${disciplinasDoPlano.map(d => d.nome).join(', ')}`)
    console.log(`đ Total: ${disciplinasDoPlano.length} disciplinas`)

    // â CORREĂĂO: Validar se existem disciplinas no plano
    if (!disciplinasDoPlano || disciplinasDoPlano.length === 0) {
      console.error(`â Nenhuma disciplina encontrada para o plano ${plano_id}`)
      return c.json({ 
        error: 'Nenhuma disciplina encontrada no plano. Crie um novo plano com disciplinas selecionadas.', 
        code: 'NO_DISCIPLINES_IN_PLAN' 
      }, 400)
    }

    const userDisciplinas = disciplinasDoPlano.map(d => ({
      disciplina_id: d.disciplina_id,
      nome: d.nome,
      dificuldade: 5, // PadrĂŁo: mĂŠdia
      edital_disciplina_id: d.edital_disciplina_id
    }))

    // Buscar tempo disponĂ­vel por dia e dias da semana do plano
    const planoInfo = await DB.prepare(`
      SELECT i.tempo_disponivel_dia, i.dias_semana
      FROM planos_estudo p
      JOIN interviews i ON p.interview_id = i.id
      WHERE p.id = ?
    `).bind(plano_id).first() as any
    
    const TEMPO_DISPONIVEL_DIA = planoInfo?.tempo_disponivel_dia || 120 // padrĂŁo: 2h
    
    // â NOVO: Dias da semana que o usuĂĄrio pode estudar (0=Dom, 1=Seg, ..., 6=SĂĄb)
    let diasDisponiveis: number[] = [1, 2, 3, 4, 5] // Default: seg a sex
    
    // â v123: Se dias_customizados for enviado, usar ele no lugar dos dias da entrevista
    if (dias_customizados && Array.isArray(dias_customizados) && dias_customizados.length > 0) {
      diasDisponiveis = dias_customizados
      console.log(`đ Usando dias CUSTOMIZADOS pelo usuĂĄrio: ${diasDisponiveis.join(', ')}`)
    } else if (planoInfo?.dias_semana) {
      try {
        diasDisponiveis = JSON.parse(planoInfo.dias_semana)
      } catch (e) {
        console.warn('â ď¸ Erro ao parsear dias_semana, usando default')
      }
    }
    console.log(`â° Limite de tempo por dia: ${TEMPO_DISPONIVEL_DIA} minutos`)
    console.log(`đ Dias disponĂ­veis para estudo: ${diasDisponiveis.join(', ')} (0=Dom...6=SĂĄb)`)

    // â NOVO: Calcular apenas dias a partir de data_inicio atĂŠ fim da semana
    // Se hoje ĂŠ quinta (dia 4), sĂł gera metas de quinta a domingo
    const dataInicioDate = new Date(data_inicio)
    const diaInicioSemana = dataInicioDate.getDay() // 0=Dom, 1=Seg, ..., 6=SĂĄb
    console.log(`đ Data inĂ­cio: ${data_inicio}, dia da semana: ${diaInicioSemana}`)

    // Distribuir metas pelos dias da semana RESPEITANDO O LIMITE DIĂRIO E DIAS DISPONĂVEIS
    const metas = []
    const tempoPorDia = [0, 0, 0, 0, 0, 0, 0] // Tempo usado em cada dia (Ă­ndice = dia da semana 0-6)
    const disciplinasPorDia = [new Set(), new Set(), new Set(), new Set(), new Set(), new Set(), new Set()] // Disciplinas Ăşnicas por dia
    const MAX_DISCIPLINAS_DIA = 4 // LIMITE: mĂĄximo 4 disciplinas por dia
    let ordem = 0
    
    // â CORREĂĂO: Calcular quais dias efetivamente usar nesta semana
    // ComeĂ§ar do dia de inĂ­cio atĂŠ domingo (ou atĂŠ o fim da semana)
    const diasAtivos: number[] = []
    
    // Se comeĂ§a no domingo (0), considerar a semana toda (0-6)
    if (diaInicioSemana === 0) {
      for (let d = 0; d <= 6; d++) {
        if (diasDisponiveis.includes(d)) {
          diasAtivos.push(d)
        }
      }
    } else {
      // Se comeĂ§a em outro dia, vai atĂŠ o sĂĄbado (6)
      for (let d = diaInicioSemana; d <= 6; d++) {
        if (diasDisponiveis.includes(d)) {
          diasAtivos.push(d)
        }
      }
      // E tambĂŠm inclui o domingo (0) se estiver disponĂ­vel e for depois do inĂ­cio
      if (diasDisponiveis.includes(0) && diaInicioSemana > 0) {
        diasAtivos.push(0)
      }
    }
    console.log(`â Dias ativos para metas nesta semana: ${diasAtivos.join(', ')}`)

    // EstratĂŠgia: RODAR ciclos entre disciplinas
    // Exemplo: Disc1-Teoria, Disc2-Teoria, Disc3-Teoria, Disc1-ExercĂ­cios, Disc2-ExercĂ­cios...
    // Isso garante que TODAS as disciplinas sejam contempladas
    
    const atividades = []
    for (const ciclo of ciclos) {
      for (const disciplina of userDisciplinas) {
        atividades.push({ disciplina, ciclo })
      }
    }

    console.log(`đ Total de atividades a alocar: ${atividades.length} (${userDisciplinas.length} disciplinas Ă ${ciclos.length} ciclos)`)

    // đŻ v126: Carregar tĂłpicos de cada disciplina FILTRANDO JĂ CONCLUĂDOS
    // Um tĂłpico ĂŠ considerado concluĂ­do se existe em metas_semana com concluida=1 
    // para o mesmo user_id e disciplina_id
    const topicosCache = new Map<number, any[]>()
    const topicoIndex = new Map<number, number>() // Rastrear Ă­ndice atual por disciplina
    
    // Buscar IDs de tĂłpicos jĂĄ concluĂ­dos pelo usuĂĄrio neste plano
    const { results: metasConcluidas } = await DB.prepare(`
      SELECT ms.topicos_sugeridos
      FROM metas_semana ms
      INNER JOIN semanas_estudo se ON ms.semana_id = se.id
      WHERE ms.user_id = ? AND se.plano_id = ? AND ms.concluida = 1
        AND ms.topicos_sugeridos IS NOT NULL AND ms.topicos_sugeridos != '[]' AND ms.topicos_sugeridos != ''
    `).bind(user_id, plano_id).all()
    
    const setTopicosConcluidos = new Set<number>()
    for (const mc of metasConcluidas) {
      try {
        const topicos = JSON.parse(mc.topicos_sugeridos as string)
        if (Array.isArray(topicos) && topicos.length > 0 && topicos[0]?.id) {
          setTopicosConcluidos.add(topicos[0].id)
        }
      } catch (e) {
        // JSON invĂĄlido, ignorar
      }
    }
    console.log(`đ TĂłpicos jĂĄ concluĂ­dos pelo usuĂĄrio: ${setTopicosConcluidos.size}`)
    
    for (const disc of userDisciplinas) {
      if (disc.edital_disciplina_id) {
        const { results: todosTopicos } = await DB.prepare(`
          SELECT id, nome, ordem
          FROM edital_topicos
          WHERE edital_disciplina_id = ?
          ORDER BY ordem ASC
        `).bind(disc.edital_disciplina_id).all()
        
        // Filtrar tĂłpicos nĂŁo concluĂ­dos
        const topicosNaoConcluidos = todosTopicos.filter((t: any) => !setTopicosConcluidos.has(t.id))
        
        topicosCache.set(disc.edital_disciplina_id, topicosNaoConcluidos)
        topicoIndex.set(disc.edital_disciplina_id, 0) // ComeĂ§ar no tĂłpico 0
        
        console.log(`  đ ${disc.nome}: ${todosTopicos.length} tĂłpicos total, ${topicosNaoConcluidos.length} pendentes (${todosTopicos.length - topicosNaoConcluidos.length} jĂĄ concluĂ­dos)`)
      }
    }

    // â CORREĂĂO: Se nĂŁo houver dias ativos, avisar e retornar
    if (diasAtivos.length === 0) {
      console.error(`â Nenhum dia disponĂ­vel para estudo nesta semana`)
      return c.json({ 
        error: 'Nenhum dia disponĂ­vel para estudo nesta semana. Verifique os dias selecionados na entrevista.', 
        code: 'NO_DAYS_AVAILABLE' 
      }, 400)
    }

    // Distribuir atividades dia a dia, respeitando o limite E APENAS nos dias ativos
    for (const { disciplina, ciclo } of atividades) {
      // Encontrar prĂłximo dia disponĂ­vel (que tenha tempo suficiente E nĂŁo exceda 4 disciplinas)
      let diaEncontrado = false
      
      // â NOVO: Iterar apenas sobre os dias ativos (respeitando dias da semana e data inĂ­cio)
      for (const dia of diasAtivos) {
        const jaTemDisciplina = disciplinasPorDia[dia].has(disciplina.disciplina_id)
        const quantidadeDisciplinas = disciplinasPorDia[dia].size
        
        // ValidaĂ§Ăľes: tempo disponĂ­vel E (jĂĄ tem disciplina OU menos de 4 disciplinas)
        if (tempoPorDia[dia] + ciclo.tempo_minutos <= TEMPO_DISPONIVEL_DIA && 
            (jaTemDisciplina || quantidadeDisciplinas < MAX_DISCIPLINAS_DIA)) {
          // Dia tem espaĂ§o disponĂ­vel!
          
          // â v125: Calcular a data correta baseada no dia da semana
          // Domingo (0) ĂŠ tratado como dia 7 quando o inĂ­cio ĂŠ durante a semana
          const dataMeta = new Date(dataInicioDate)
          let diffDias = dia - diaInicioSemana
          if (diffDias < 0) {
            // Dia da semana ĂŠ anterior ao dia de inĂ­cio
            // Ex: domingo (0) quando comeĂ§ou segunda (1): diff = -1
            // Domingo vem DEPOIS de sĂĄbado, entĂŁo adicionar 7
            diffDias += 7
          }
          dataMeta.setDate(dataMeta.getDate() + diffDias)

          // đŻ NOVO: Pegar prĂłximo tĂłpico EM ORDEM (nĂŁo sempre os mesmos 3)
          let topicosArray = []

          // 1ď¸âŁ Se disciplina veio do edital, pegar prĂłximos tĂłpicos em ORDEM
          if (disciplina.edital_disciplina_id && topicosCache.has(disciplina.edital_disciplina_id)) {
            const todosTopicos = topicosCache.get(disciplina.edital_disciplina_id)!
            const indiceAtual = topicoIndex.get(disciplina.edital_disciplina_id)!
            
            // Pegar 1 tĂłpico por vez (sequencial - apenas nĂŁo concluĂ­dos)
            if (todosTopicos && todosTopicos.length > 0) {
              if (indiceAtual < todosTopicos.length) {
                const topicoAtual = todosTopicos[indiceAtual]
                if (topicoAtual && topicoAtual.id !== undefined) {
                  topicosArray = [{ id: topicoAtual.id, nome: topicoAtual.nome || 'TĂłpico sem nome' }]
                  topicoIndex.set(disciplina.edital_disciplina_id, indiceAtual + 1)
                  console.log(`    âĄď¸ ${disciplina.nome} â TĂłpico ${indiceAtual + 1}/${todosTopicos.length}: ${topicoAtual.nome}`)
                }
              } else {
                // â v126: Todos os tĂłpicos pendentes jĂĄ foram alocados nesta semana
                // NĂO reiniciar ciclo - disciplina jĂĄ cobriu todos os pendentes
                console.log(`    â­ď¸ ${disciplina.nome} â Todos os ${todosTopicos.length} tĂłpicos pendentes jĂĄ foram alocados, pulando`)
                continue
              }
            }
          }

          // 2ď¸âŁ Se nĂŁo houver tĂłpicos do edital, buscar da base padrĂŁo
          if (topicosArray.length === 0 && disciplina.disciplina_id > 0) {
            const { results: topicosPadrao } = await DB.prepare(`
              SELECT te.id, te.nome
              FROM topicos_edital te
              LEFT JOIN user_topicos_progresso utp ON te.id = utp.topico_id AND utp.user_id = ?
              WHERE te.disciplina_id = ?
              ORDER BY COALESCE(utp.nivel_dominio, 0) ASC, te.peso DESC
              LIMIT 1
            `).bind(user_id, disciplina.disciplina_id).all()

            topicosArray = topicosPadrao.map(t => ({ id: t.id, nome: t.nome }))
          }

          // 3ď¸âŁ Fallback: tĂłpico genĂŠrico baseado no tipo de ciclo
          if (topicosArray.length === 0) {
            const tituloGenerico = ciclo.tipo === 'teoria' 
              ? `Conceitos fundamentais de ${disciplina.nome}`
              : ciclo.tipo === 'exercicios'
              ? `ExercĂ­cios prĂĄticos de ${disciplina.nome}`
              : `RevisĂŁo geral de ${disciplina.nome}`
            
            topicosArray = [{ id: 0, nome: tituloGenerico }]
          }

          // â CORREĂĂO: Converter dia_semana de 0-6 (JS) para 1-7 (frontend: 1=Seg, 7=Dom)
          // JavaScript: 0=Dom, 1=Seg, 2=Ter, 3=Qua, 4=Qui, 5=Sex, 6=SĂĄb
          // Frontend:   7=Dom, 1=Seg, 2=Ter, 3=Qua, 4=Qui, 5=Sex, 6=SĂĄb
          const diaSemanaParaBanco = dia === 0 ? 7 : dia // Converte domingo de 0 para 7
          
          // Inserir meta
          const metaResult = await DB.prepare(`
            INSERT INTO metas_semana (
              semana_id, user_id, disciplina_id, dia_semana, data, 
              tipo, tempo_minutos, topicos_sugeridos, ordem
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
          `).bind(
            semana_id,
            user_id,
            disciplina.disciplina_id,
            diaSemanaParaBanco, // â CORRIGIDO: Formato 1-7 para o frontend
            dataMeta.toISOString().split('T')[0],
            ciclo.tipo,
            ciclo.tempo_minutos,
            JSON.stringify(topicosArray),
            ordem
          ).run()

          metas.push({
            id: metaResult.meta.last_row_id,
            disciplina_nome: disciplina.nome,
            dia_semana: diaSemanaParaBanco, // â CORRIGIDO: Formato 1-7 para o frontend
            data: dataMeta.toISOString().split('T')[0],
            tipo: ciclo.tipo,
            tempo_minutos: ciclo.tempo_minutos,
            topicos: topicosArray
          })

          // Atualizar tempo usado no dia e adicionar disciplina ao Set
          tempoPorDia[dia] += ciclo.tempo_minutos
          disciplinasPorDia[dia].add(disciplina.disciplina_id)
          const nomeDia = ['Dom','Seg','Ter','Qua','Qui','Sex','SĂĄb'][dia]
          console.log(`đ ${nomeDia} (${dataMeta.toISOString().split('T')[0]}): ${disciplina.nome} (${ciclo.tipo}) +${ciclo.tempo_minutos}min (total: ${tempoPorDia[dia]}/${TEMPO_DISPONIVEL_DIA}min, ${disciplinasPorDia[dia].size} disciplinas)`)
          
          ordem++
          diaEncontrado = true
          break
        }
      }

      if (!diaEncontrado) {
        console.warn(`â ď¸ NĂŁo foi possĂ­vel alocar ${ciclo.tipo} de ${disciplina.nome} (${ciclo.tempo_minutos}min) - semana cheia`)
      }
    }

    console.log(`â ${metas.length} metas geradas para semana ${numeroSemana}`)

    return c.json({
      semana_id,
      numero_semana: numeroSemana,
      data_inicio,
      data_fim: dataFim.toISOString().split('T')[0],
      metas
    })

  } catch (error) {
    console.error('â Erro ao gerar metas semanais:', error)
    return c.json({ error: 'Erro ao gerar metas semanais' }, 500)
  }
})

// Endpoint: Sincronizar metas semanais â metas diĂĄrias (hoje)
app.post('/api/metas/sincronizar-dia/:user_id', async (c) => {
  const { DB } = c.env
  const user_id = parseInt(c.req.param('user_id'))

  console.log('đ Sincronizando metas semanais â diĂĄrias para user:', user_id)

  try {
    const hoje = new Date().toISOString().split('T')[0]
    const diaSemanaHoje = new Date().getDay() || 7 // 1-7 (seg-dom, domingo=7)

    // Buscar metas semanais de hoje da semana ativa
    const { results: metasSemanais } = await DB.prepare(`
      SELECT 
        ms.*,
        d.nome as disciplina_nome,
        se.plano_id
      FROM metas_semana ms
      JOIN semanas_estudo se ON ms.semana_id = se.id
      JOIN disciplinas d ON ms.disciplina_id = d.id
      WHERE ms.user_id = ?
        AND se.status = 'ativa'
        AND ms.dia_semana = ?
      ORDER BY ms.ordem
    `).bind(user_id, diaSemanaHoje).all()

    if (metasSemanais.length === 0) {
      return c.json({ message: 'Nenhuma meta semanal para hoje', criadas: 0 })
    }

    // Verificar se jĂĄ existem metas diĂĄrias para hoje
    const { results: metasExistentes } = await DB.prepare(`
      SELECT id FROM metas_diarias 
      WHERE user_id = ? AND data = ?
    `).bind(user_id, hoje).all()

    if (metasExistentes.length > 0) {
      console.log(`âšď¸  JĂĄ existem ${metasExistentes.length} metas diĂĄrias para hoje`)
      return c.json({ message: 'Metas diĂĄrias jĂĄ existem para hoje', criadas: 0 })
    }

    // â CORREĂĂO v19.6: Buscar ciclo_id correspondente para cada meta
    const metasCriadas = []
    for (const metaSemanal of metasSemanais) {
      // Buscar ciclo_id correspondente Ă  disciplina e tipo
      const ciclo = await DB.prepare(`
        SELECT id FROM ciclos_estudo 
        WHERE plano_id = ? 
          AND disciplina_id = ? 
          AND tipo = ?
        LIMIT 1
      `).bind(
        metaSemanal.plano_id,
        metaSemanal.disciplina_id,
        metaSemanal.tipo
      ).first()

      if (!ciclo) {
        console.warn(`â ď¸  Ciclo nĂŁo encontrado para ${metaSemanal.disciplina_nome} (${metaSemanal.tipo})`)
        continue
      }

      try {
        const result = await DB.prepare(`
          INSERT INTO metas_diarias (
            user_id, plano_id, data, ciclo_id
          ) VALUES (?, ?, ?, ?)
        `).bind(
          user_id,
          metaSemanal.plano_id,
          hoje,
          ciclo.id
        ).run()

        metasCriadas.push({
          id: result.meta.last_row_id,
          disciplina: metaSemanal.disciplina_nome,
          tipo: metaSemanal.tipo,
          tempo: metaSemanal.tempo_minutos
        })
      } catch (insertError) {
        // Se der erro de UNIQUE constraint, significa que meta jĂĄ existe - ignorar
        if (insertError.message.includes('UNIQUE constraint failed')) {
          console.log(`âšď¸  Meta jĂĄ existe para ${metaSemanal.disciplina_nome} (${metaSemanal.tipo})`)
        } else {
          throw insertError // Re-lanĂ§ar outros erros
        }
      }
    }

    console.log(`â ${metasCriadas.length} metas diĂĄrias criadas a partir das metas semanais`)

    return c.json({
      message: 'Metas diĂĄrias sincronizadas com sucesso',
      criadas: metasCriadas.length,
      metas: metasCriadas
    })

  } catch (error) {
    console.error('â Erro ao sincronizar metas:', error)
    return c.json({ error: 'Erro ao sincronizar metas' }, 500)
  }
})

// 1b. Listar todas as semanas de um usuĂĄrio (para histĂłrico)
app.get('/api/metas/semanas/:user_id', async (c) => {
  const { DB } = c.env
  const user_id = parseInt(c.req.param('user_id'))

  try {
    const { results: semanas } = await DB.prepare(`
      SELECT 
        se.id, se.numero_semana, se.data_inicio, se.data_fim, se.status,
        COUNT(ms.id) as metas_totais,
        SUM(CASE WHEN ms.concluida = 1 THEN 1 ELSE 0 END) as metas_concluidas
      FROM semanas_estudo se
      LEFT JOIN metas_semana ms ON ms.semana_id = se.id
      WHERE se.user_id = ?
      GROUP BY se.id
      ORDER BY se.data_inicio DESC
    `).bind(user_id).all()

    return c.json(semanas || [])
  } catch (error) {
    console.error('â Erro ao listar semanas:', error)
    return c.json([], 200)
  }
})

// 2. Buscar metas de uma semana
app.get('/api/metas/semana/:semana_id', async (c) => {
  const { DB } = c.env
  const semana_id = parseInt(c.req.param('semana_id'))

  try {
    // Buscar informaĂ§Ăľes da semana
    const semana = await DB.prepare(
      'SELECT * FROM semanas_estudo WHERE id = ?'
    ).bind(semana_id).first()

    if (!semana) {
      return c.json({ error: 'Semana nĂŁo encontrada' }, 404)
    }

    // Buscar metas da semana
    const { results: metas } = await DB.prepare(`
      SELECT 
        ms.*,
        d.nome as disciplina_nome,
        ce.id as conteudo_id
      FROM metas_semana ms
      JOIN disciplinas d ON ms.disciplina_id = d.id
      LEFT JOIN conteudo_estudo ce ON ms.conteudo_id = ce.id
      WHERE ms.semana_id = ?
      ORDER BY ms.dia_semana, ms.ordem
    `).bind(semana_id).all()

    return c.json({
      semana,
      metas: metas.map(m => ({
        ...m,
        topicos_sugeridos: m.topicos_sugeridos ? JSON.parse(m.topicos_sugeridos) : []
      }))
    })

  } catch (error) {
    console.error('â Erro ao buscar metas da semana:', error)
    return c.json({ error: 'Erro ao buscar metas da semana' }, 500)
  }
})

// 3. Buscar semana ativa do usuĂĄrio
app.get('/api/metas/semana-ativa/:user_id', async (c) => {
  const { DB } = c.env
  const user_id = parseInt(c.req.param('user_id'))

  try {
    // â CORREĂĂO: Buscar plano ativo do usuĂĄrio primeiro
    const planoAtivo = await DB.prepare(`
      SELECT id FROM planos_estudo 
      WHERE user_id = ? AND ativo = 1 
      ORDER BY created_at DESC LIMIT 1
    `).bind(user_id).first()
    
    if (!planoAtivo) {
      console.log(`â ď¸ Nenhum plano ativo para user_id ${user_id}`)
      return c.json({ semana: null, metas: [] })
    }

    // â CORREĂĂO: Buscar semana ativa DO PLANO ATIVO (nĂŁo apenas do usuĂĄrio)
    const semana = await DB.prepare(`
      SELECT * FROM semanas_estudo 
      WHERE user_id = ? 
      AND plano_id = ?
      AND status = 'ativa'
      ORDER BY id DESC
      LIMIT 1
    `).bind(user_id, planoAtivo.id).first()

    if (!semana) {
      console.log(`âšď¸ Nenhuma semana ativa para plano ${planoAtivo.id}`)
      return c.json({ semana: null, metas: [], plano_id: planoAtivo.id })
    }

    // Buscar metas da semana com conteudo_id (sem duplicatas)
    const { results: metas } = await DB.prepare(`
      SELECT 
        ms.*,
        d.nome as disciplina_nome,
        (SELECT id FROM conteudo_estudo WHERE meta_id = ms.id LIMIT 1) as conteudo_id
      FROM metas_semana ms
      JOIN disciplinas d ON ms.disciplina_id = d.id
      WHERE ms.semana_id = ?
      GROUP BY ms.id
      ORDER BY ms.dia_semana, ms.ordem
    `).bind(semana.id).all()

    return c.json({
      semana,
      metas: metas.map(m => {
        const topicos = m.topicos_sugeridos ? JSON.parse(m.topicos_sugeridos) : []
        return {
          ...m,
          plano_id: semana.plano_id, // â Adicionar plano_id para o botĂŁo de editar disciplina
          topicos_sugeridos: topicos,
          topico_nome: topicos[0]?.nome || '', // â Extrair nome do primeiro tĂłpico para uso direto
          topico_id: topicos[0]?.id || null // â Extrair ID do primeiro tĂłpico
        }
      })
    })

  } catch (error) {
    console.error('â Erro ao buscar semana ativa:', error)
    return c.json({ error: 'Erro ao buscar semana ativa' }, 500)
  }
})

