// 7. Adicionar nova meta
app.post('/api/metas/adicionar', async (c) => {
  const { DB } = c.env
  const { semana_id, user_id, disciplina_id, dia_semana, data, tipo, tempo_minutos, topicos_sugeridos } = await c.req.json()

  console.log('â Adicionando nova meta:', { semana_id, disciplina_id, dia_semana, tipo })

  try {
    // Buscar ordem mĂĄxima do dia
    const maxOrdem = await DB.prepare(`
      SELECT COALESCE(MAX(ordem), -1) as max_ordem
      FROM metas_semana
      WHERE semana_id = ? AND dia_semana = ?
    `).bind(semana_id, dia_semana).first()

    const novaOrdem = (maxOrdem?.max_ordem || 0) + 1

    // Inserir meta (trigger atualiza totais automaticamente)
    const result = await DB.prepare(`
      INSERT INTO metas_semana (
        semana_id, user_id, disciplina_id, dia_semana, data,
        tipo, tempo_minutos, topicos_sugeridos, ordem
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).bind(
      semana_id,
      user_id,
      disciplina_id,
      dia_semana,
      data,
      tipo,
      tempo_minutos,
      JSON.stringify(topicos_sugeridos || []),
      novaOrdem
    ).run()

    return c.json({ id: result.meta.last_row_id, success: true })

  } catch (error) {
    console.error('â Erro ao adicionar meta:', error)
    return c.json({ error: 'Erro ao adicionar meta' }, 500)
  }
})

// 8. Marcar meta como concluĂ­da
app.put('/api/metas/concluir/:meta_id', async (c) => {
  const { DB } = c.env
  const meta_id = parseInt(c.req.param('meta_id'))
  const { tempo_real_minutos } = await c.req.json()

  console.log('â Concluindo meta:', { meta_id, tempo_real_minutos })

  try {
    // 1. Buscar dados da meta COMPLETOS (incluindo tĂłpicos e status atual)
    const meta = await DB.prepare(`
      SELECT ms.user_id, ms.data, ms.disciplina_id, ms.topicos_sugeridos, ms.semana_id, ms.concluida,
             se.plano_id
      FROM metas_semana ms
      INNER JOIN semanas_estudo se ON ms.semana_id = se.id
      WHERE ms.id = ?
    `).bind(meta_id).first() as any
    
    if (!meta) {
      return c.json({ error: 'Meta nĂŁo encontrada' }, 404)
    }

    // â v126: Se a meta JĂ estĂĄ concluĂ­da, nĂŁo fazer nada (evita dupla contagem)
    if (meta.concluida === 1) {
      console.log(`â ď¸ Meta ${meta_id} jĂĄ estĂĄ concluĂ­da, ignorando re-conclusĂŁo`)
      return c.json({ success: true, message: 'Meta jĂĄ estava concluĂ­da', already_completed: true })
    }

    // 2. Atualizar meta como concluĂ­da
    await DB.prepare(`
      UPDATE metas_semana 
      SET concluida = 1, tempo_real_minutos = ?, updated_at = CURRENT_TIMESTAMP
      WHERE id = ?
    `).bind(tempo_real_minutos, meta_id).run()

    // 3. â v126: Atualizar progresso dos tĂłpicos da meta (com plano_id)
    if (meta.topicos_sugeridos) {
      try {
        const topicos = JSON.parse(meta.topicos_sugeridos)
        console.log(`đ Atualizando progresso de ${topicos.length} tĂłpico(s)`)
        
        for (const topico of topicos) {
          const topicoId = topico.id
          if (!topicoId) continue
          
          // Verificar se jĂĄ existe registro de progresso (com plano_id)
          const existingProgress = await DB.prepare(`
            SELECT id, vezes_estudado, nivel_dominio 
            FROM user_topicos_progresso 
            WHERE user_id = ? AND topico_id = ? AND (plano_id = ? OR plano_id IS NULL)
          `).bind(meta.user_id, topicoId, meta.plano_id).first() as any
          
          if (existingProgress) {
            // Incrementar vezes_estudado e aumentar nivel_dominio
            const novoNivel = Math.min(10, (existingProgress.nivel_dominio || 0) + 2)
            await DB.prepare(`
              UPDATE user_topicos_progresso 
              SET vezes_estudado = vezes_estudado + 1, 
                  nivel_dominio = ?, 
                  plano_id = COALESCE(plano_id, ?),
                  ultima_vez = CURRENT_TIMESTAMP
              WHERE id = ?
            `).bind(novoNivel, meta.plano_id, existingProgress.id).run()
            console.log(`  â TĂłpico ${topicoId}: vezes+1, nivel ${existingProgress.nivel_dominio} â ${novoNivel}`)
          } else {
            // Criar novo registro com nivel 2 (primeira vez estudado) incluindo plano_id
            await DB.prepare(`
              INSERT INTO user_topicos_progresso (user_id, topico_id, plano_id, vezes_estudado, nivel_dominio, ultima_vez)
              VALUES (?, ?, ?, 1, 2, CURRENT_TIMESTAMP)
            `).bind(meta.user_id, topicoId, meta.plano_id).run()
            console.log(`  â TĂłpico ${topicoId}: novo registro (nivel 2, plano ${meta.plano_id})`)
          }
        }
      } catch (parseError) {
        console.warn('â ď¸ NĂŁo foi possĂ­vel parsear topicos_sugeridos:', parseError)
      }
    }

    // 4. Criar/atualizar registro no historico_estudos (para estatĂ­sticas)
    const dataFormatada = meta.data // JĂĄ estĂĄ no formato YYYY-MM-DD
    
    // Verificar se jĂĄ existe registro para esse dia
    const registroExistente = await DB.prepare(`
      SELECT id, tempo_estudado_minutos 
      FROM historico_estudos 
      WHERE user_id = ? AND data = ?
    `).bind(meta.user_id, dataFormatada).first()
    
    if (registroExistente) {
      // Atualizar registro existente (somar minutos)
      await DB.prepare(`
        UPDATE historico_estudos 
        SET tempo_estudado_minutos = tempo_estudado_minutos + ?,
            status = 'concluido',
            updated_at = CURRENT_TIMESTAMP
        WHERE id = ?
      `).bind(tempo_real_minutos, registroExistente.id).run()
    } else {
      // Criar novo registro
      await DB.prepare(`
        INSERT INTO historico_estudos (user_id, data, tempo_estudado_minutos, status, percentual_conclusao)
        VALUES (?, ?, ?, 'concluido', 100)
      `).bind(meta.user_id, dataFormatada, tempo_real_minutos).run()
    }

    console.log('â Meta concluĂ­da + Progresso tĂłpicos + HistĂłrico atualizado')
    return c.json({ success: true })

  } catch (error) {
    console.error('â Erro ao concluir meta:', error)
    return c.json({ error: 'Erro ao concluir meta' }, 500)
  }
})

// 8.5. Atualizar tĂłpico sugerido da meta (trocar por outro estudado)
app.put('/api/metas/atualizar-topico/:meta_id', async (c) => {
  const { DB } = c.env
  const meta_id = parseInt(c.req.param('meta_id'))
  const { topico_id, topico_nome } = await c.req.json()

  console.log('đ Atualizando tĂłpico da meta:', meta_id, 'â', topico_nome)

  try {
    // Buscar meta atual
    const meta = await DB.prepare('SELECT topicos_sugeridos FROM metas_semana WHERE id = ?')
      .bind(meta_id).first()
    
    if (!meta) {
      return c.json({ error: 'Meta nĂŁo encontrada' }, 404)
    }

    // Criar novo array de tĂłpicos com o tĂłpico atualizado
    const novoTopico = JSON.stringify([{ id: topico_id, nome: topico_nome }])
    
    // Atualizar a meta com o novo tĂłpico
    await DB.prepare(`
      UPDATE metas_semana 
      SET topicos_sugeridos = ?, updated_at = CURRENT_TIMESTAMP
      WHERE id = ?
    `).bind(novoTopico, meta_id).run()

    console.log('â TĂłpico da meta atualizado')
    return c.json({ success: true, topico_nome })

  } catch (error) {
    console.error('â Erro ao atualizar tĂłpico da meta:', error)
    return c.json({ error: 'Erro ao atualizar tĂłpico' }, 500)
  }
})

// 8.6. Trocar disciplina e tĂłpico da meta completamente
app.put('/api/metas/:meta_id/trocar-disciplina', async (c) => {
  const { DB } = c.env
  const meta_id = parseInt(c.req.param('meta_id'))
  const { nova_disciplina_id, nova_disciplina_nome, novo_topico_id, novo_topico_nome, plano_id } = await c.req.json()

  console.log('đ Trocando disciplina da meta:', meta_id, 'â', nova_disciplina_nome, '/', novo_topico_nome)

  try {
    // 1. Verificar se a meta existe e nĂŁo estĂĄ concluĂ­da
    const meta = await DB.prepare(`
      SELECT id, concluida, disciplina_id 
      FROM metas_semana 
      WHERE id = ?
    `).bind(meta_id).first()
    
    if (!meta) {
      console.log('â Meta nĂŁo encontrada:', meta_id)
      return c.json({ error: 'Meta nĂŁo encontrada' }, 404)
    }
    
    if (meta.concluida) {
      console.log('â Meta jĂĄ concluĂ­da:', meta_id)
      return c.json({ error: 'NĂŁo ĂŠ possĂ­vel alterar uma meta jĂĄ concluĂ­da' }, 400)
    }

    // 2. â NOVO: Apagar conteĂşdos gerados da disciplina anterior
    console.log('đď¸ Apagando conteĂşdos gerados da meta:', meta_id)
    
    // Apagar de conteudo_estudo
    const deleteConteudo = await DB.prepare(`
      DELETE FROM conteudo_estudo WHERE meta_id = ?
    `).bind(meta_id).run()
    console.log(`  â Deletados ${deleteConteudo.meta?.changes || 0} registros de conteudo_estudo`)
    
    // Apagar de materiais_salvos
    const deleteMateriais = await DB.prepare(`
      DELETE FROM materiais_salvos WHERE meta_id = ?
    `).bind(meta_id).run()
    console.log(`  â Deletados ${deleteMateriais.meta?.changes || 0} registros de materiais_salvos`)

    // 3. Preparar tĂłpicos sugeridos no formato esperado
    const novoTopicosSugeridos = JSON.stringify([{ 
      id: novo_topico_id, 
      nome: novo_topico_nome 
    }])
    
    // 4. Atualizar a meta com nova disciplina e tĂłpico
    await DB.prepare(`
      UPDATE metas_semana 
      SET disciplina_id = ?,
          topicos_sugeridos = ?,
          updated_at = CURRENT_TIMESTAMP
      WHERE id = ?
    `).bind(
      nova_disciplina_id,
      novoTopicosSugeridos,
      meta_id
    ).run()

    console.log('â Meta atualizada com nova disciplina:', nova_disciplina_nome)
    
    return c.json({ 
      success: true, 
      message: 'Disciplina e tĂłpico atualizados. ConteĂşdos anteriores foram removidos.',
      nova_disciplina: nova_disciplina_nome,
      novo_topico: novo_topico_nome,
      conteudos_removidos: true
    })

  } catch (error) {
    console.error('â Erro ao trocar disciplina da meta:', error)
    return c.json({ error: 'Erro ao trocar disciplina' }, 500)
  }
})

// 9. Desmarcar meta como concluĂ­da
app.put('/api/metas/desmarcar/:meta_id', async (c) => {
  const { DB } = c.env
  const meta_id = parseInt(c.req.param('meta_id'))

  console.log('âŠď¸ Desmarcando meta:', meta_id)

  try {
    // 1. Buscar dados da meta (incluindo tempo_real_minutos)
    const meta = await DB.prepare(`
      SELECT user_id, data, tempo_real_minutos 
      FROM metas_semana 
      WHERE id = ?
    `).bind(meta_id).first()
    
    if (!meta) {
      return c.json({ error: 'Meta nĂŁo encontrada' }, 404)
    }

    // 2. Desmarcar meta
    await DB.prepare(`
      UPDATE metas_semana 
      SET concluida = 0, tempo_real_minutos = NULL, updated_at = CURRENT_TIMESTAMP
      WHERE id = ?
    `).bind(meta_id).run()

    // 3. Atualizar historico_estudos (subtrair minutos)
    if (meta.tempo_real_minutos && meta.tempo_real_minutos > 0) {
      const dataFormatada = meta.data
      
      const registroHistorico = await DB.prepare(`
        SELECT id, tempo_estudado_minutos 
        FROM historico_estudos 
        WHERE user_id = ? AND data = ?
      `).bind(meta.user_id, dataFormatada).first()
      
      if (registroHistorico) {
        const novoTempo = Math.max(0, registroHistorico.tempo_estudado_minutos - meta.tempo_real_minutos)
        
        if (novoTempo === 0) {
          // Se zerou, deletar registro
          await DB.prepare(`
            DELETE FROM historico_estudos WHERE id = ?
          `).bind(registroHistorico.id).run()
        } else {
          // Se ainda tem tempo, atualizar
          await DB.prepare(`
            UPDATE historico_estudos 
            SET tempo_estudado_minutos = ?,
                updated_at = CURRENT_TIMESTAMP
            WHERE id = ?
          `).bind(novoTempo, registroHistorico.id).run()
        }
      }
    }

    console.log('âŠď¸ Meta desmarcada + HistĂłrico ajustado')
    return c.json({ success: true })

  } catch (error) {
    console.error('â Erro ao desmarcar meta:', error)
    return c.json({ error: 'Erro ao desmarcar meta' }, 500)
  }
})

