function gerarObjetivos(disciplina: string, tipo: string, dificuldade: string, contexto: any = {}): string[] {
  if (tipo === 'teoria') {
    return [`Dominar ${disciplina}`, 'Entender aplicaĂ§Ăľes prĂĄticas']
  } else if (tipo === 'exercicios') {
    return ['Resolver questĂľes corretamente', 'Identificar pegadinhas']
  } else {
    return ['Consolidar conhecimento', 'Fixar conceitos principais']
  }
}

function gerarConteudoDetalhado(disciplina: string, tipo: string, tempo: number, topicos: string[], dificuldade: string, contexto: any = {}) {
  // Criar introduĂ§ĂŁo simples e direta
  let introducao = `SessĂŁo de ${tipo === 'teoria' ? 'estudo teĂłrico' : tipo === 'exercicios' ? 'prĂĄtica de questĂľes' : 'revisĂŁo'} de ${disciplina} - ${tempo} minutos.`
  
  if (contexto.tipo === 'concurso_especifico' && contexto.concurso) {
    introducao += ` Adaptado para ${contexto.concurso}.`
  }
  
  const conteudoBase = {
    introducao,
    orientacoes: tipo === 'teoria' ? [
      'FaĂ§a anotaĂ§Ăľes dos pontos principais',
      'Marque dĂşvidas para revisar depois'
    ] : tipo === 'exercicios' ? [
      'Analise cada erro cometido',
      'Anote as questĂľes erradas'
    ] : [
      'Teste sua memĂłria antes de reler',
      'Foque nos pontos de dificuldade'
    ],
    secoes: topicos.map((topico, index) => {
      const tempoSecao = Math.round(tempo / topicos.length)
      return {
        titulo: topico,
        tempo_estimado: tempoSecao,
        ordem: index + 1,
        conteudo: gerarConteudoSecao(topico, tipo, dificuldade, disciplina, tempoSecao)
      }
    }),
    recursos_adicionais: [],
    proximos_passos: tipo === 'teoria' ? `FaĂ§a um resumo e resolva questĂľes sobre o tema.` : tipo === 'exercicios' ? `Revise os erros e estude a teoria correspondente.` : `Revise novamente em 3 dias.`
  }

  return conteudoBase
}

