// â v80: ANALYTICS ADMIN - ConteĂşdos gerados + Feedbacks globais
// âââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ
app.get('/api/admin/analytics', async (c) => {
  const { DB } = c.env
  
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403)
  }
  
  try {
    // âââ 1. CONTEĂDOS GERADOS POR TIPO (totais) âââ
    const conteudoTotais = await DB.prepare(`
      SELECT 
        tipo,
        COUNT(*) as total
      FROM conteudo_estudo
      GROUP BY tipo
      ORDER BY total DESC
    `).all()
    
    // âââ 2. CONTEĂDOS POR DIA (Ăşltimos 30 dias, agrupado por tipo e data) âââ
    const conteudoPorDia = await DB.prepare(`
      SELECT 
        DATE(created_at) as dia,
        tipo,
        COUNT(*) as total
      FROM conteudo_estudo
      WHERE created_at >= datetime('now', '-30 days')
      GROUP BY dia, tipo
      ORDER BY dia ASC
    `).all()
    
    // âââ 3. FLASHCARDS GERADOS (totais e por dia) âââ
    const flashcardsTotais = await DB.prepare(`
      SELECT COUNT(*) as total FROM flashcards
    `).first() as any
    
    const flashcardsPorDia = await DB.prepare(`
      SELECT 
        DATE(created_at) as dia,
        COUNT(*) as total
      FROM flashcards
      WHERE created_at >= datetime('now', '-30 days')
      GROUP BY dia
      ORDER BY dia ASC
    `).all()
    
    // âââ 4. SIMULADOS GERADOS (totais e por dia) âââ
    const simuladosTotais = await DB.prepare(`
      SELECT COUNT(*) as total FROM simulados_historico
    `).first() as any
    
    const simuladosPorDia = await DB.prepare(`
      SELECT 
        DATE(data_realizacao) as dia,
        COUNT(*) as total
      FROM simulados_historico
      WHERE data_realizacao >= datetime('now', '-30 days')
      GROUP BY dia
      ORDER BY dia ASC
    `).all()
    
    // âââ 5. EXERCĂCIOS (resultados) âââ
    const exerciciosTotais = await DB.prepare(`
      SELECT COUNT(*) as total FROM exercicios_resultados
    `).first() as any
    
    const exerciciosPorDia = await DB.prepare(`
      SELECT 
        DATE(created_at) as dia,
        COUNT(*) as total
      FROM exercicios_resultados
      WHERE created_at >= datetime('now', '-30 days')
      GROUP BY dia
      ORDER BY dia ASC
    `).all()
    
    // âââ 6. REVISĂES âââ
    const revisoesTotais = await DB.prepare(`
      SELECT COUNT(*) as total FROM revisoes
    `).first() as any
    
    // âââ 7. FEEDBACKS - Totais por tipo âââ
    const feedbacksPorTipo = await DB.prepare(`
      SELECT 
        feedback_type,
        COUNT(*) as total,
        ROUND(AVG(rating), 1) as media_rating
      FROM user_feedbacks
      GROUP BY feedback_type
      ORDER BY total DESC
    `).all()
    
    // âââ 8. FEEDBACKS - Por dia (Ăşltimos 30 dias) âââ
    const feedbacksPorDia = await DB.prepare(`
      SELECT 
        DATE(created_at) as dia,
        feedback_type,
        COUNT(*) as total
      FROM user_feedbacks
      WHERE created_at >= datetime('now', '-30 days')
      GROUP BY dia, feedback_type
      ORDER BY dia ASC
    `).all()
    
    // âââ 9. FEEDBACKS - Lista completa (Ăşltimos 100) âââ
    const feedbacksLista = await DB.prepare(`
      SELECT 
        f.id, f.user_id, f.rating, f.feedback_type, f.message, 
        f.page_context, f.is_read, f.admin_response, f.responded_at,
        f.created_at,
        u.name as user_name, u.email as user_email
      FROM user_feedbacks f
      LEFT JOIN users u ON u.id = f.user_id
      ORDER BY f.created_at DESC
      LIMIT 100
    `).all()
    
    // âââ 10. FEEDBACKS - EstatĂ­sticas gerais âââ
    const feedbacksStats = await DB.prepare(`
      SELECT 
        COUNT(*) as total,
        SUM(CASE WHEN is_read = 0 THEN 1 ELSE 0 END) as nao_lidos,
        SUM(CASE WHEN is_read = 1 THEN 1 ELSE 0 END) as lidos,
        ROUND(AVG(rating), 1) as media_geral,
        SUM(CASE WHEN rating >= 4 THEN 1 ELSE 0 END) as positivos,
        SUM(CASE WHEN rating <= 2 THEN 1 ELSE 0 END) as negativos
      FROM user_feedbacks
    `).first() as any
    
    // âââ 11. CHATS COM LILU - Totais e por dia âââ
    let chatTotal = 0
    let chatPorDia: any[] = []
    let chatUsuariosUnicos = 0
    try {
      const chatTotaisResult = await DB.prepare(`
        SELECT COUNT(*) as total FROM chat_interactions
      `).first() as any
      chatTotal = chatTotaisResult?.total || 0
      
      const chatPorDiaResult = await DB.prepare(`
        SELECT 
          DATE(created_at) as dia,
          COUNT(*) as total
        FROM chat_interactions
        WHERE created_at >= datetime('now', '-30 days')
        GROUP BY dia
        ORDER BY dia ASC
      `).all()
      chatPorDia = chatPorDiaResult.results || []
      
      const chatUsuariosResult = await DB.prepare(`
        SELECT COUNT(DISTINCT user_id) as total FROM chat_interactions
      `).first() as any
      chatUsuariosUnicos = chatUsuariosResult?.total || 0
    } catch (e) {
      console.log('â ď¸ Tabela chat_interactions pode nĂŁo existir ainda:', e)
    }
    
    // âââ 12. CRESCIMENTO DE USUĂRIOS âââ
    let userGrowthDaily: any[] = []
    let userGrowthMonthly: any[] = []
    let userGrowthYearly: any[] = []
    let totalUsers = 0
    try {
      // Total de usuĂĄrios
      const totalUsersResult = await DB.prepare(`SELECT COUNT(*) as total FROM users`).first() as any
      totalUsers = totalUsersResult?.total || 0
      
      // Por dia (Ăşltimos 90 dias) - novos por dia
      const dailyResult = await DB.prepare(`
        SELECT 
          DATE(created_at) as dia,
          COUNT(*) as novos
        FROM users
        WHERE created_at >= datetime('now', '-90 days')
        GROUP BY DATE(created_at)
        ORDER BY dia ASC
      `).all()
      const dailyRaw = dailyResult.results || []
      
      // Calcular acumulado no servidor (mais eficiente que subconsulta)
      // Primeiro pegar total de users antes dos Ăşltimos 90 dias
      const beforeResult = await DB.prepare(`
        SELECT COUNT(*) as total FROM users WHERE created_at < datetime('now', '-90 days')
      `).first() as any
      let runningTotal = beforeResult?.total || 0
      
      userGrowthDaily = dailyRaw.map((d: any) => {
        runningTotal += (d.novos || 0)
        return { dia: d.dia, novos: d.novos || 0, total_acumulado: runningTotal }
      })
      
      // Por mĂŞs - novos por mĂŞs
      const monthlyResult = await DB.prepare(`
        SELECT 
          strftime('%Y-%m', created_at) as mes,
          COUNT(*) as novos
        FROM users
        GROUP BY strftime('%Y-%m', created_at)
        ORDER BY mes ASC
      `).all()
      const monthlyRaw = monthlyResult.results || []
      let monthRunning = 0
      userGrowthMonthly = monthlyRaw.map((d: any) => {
        monthRunning += (d.novos || 0)
        return { mes: d.mes, novos: d.novos || 0, total_acumulado: monthRunning }
      })
      
      // Por ano - novos por ano
      const yearlyResult = await DB.prepare(`
        SELECT 
          strftime('%Y', created_at) as ano,
          COUNT(*) as novos
        FROM users
        GROUP BY strftime('%Y', created_at)
        ORDER BY ano ASC
      `).all()
      const yearlyRaw = yearlyResult.results || []
      let yearRunning = 0
      userGrowthYearly = yearlyRaw.map((d: any) => {
        yearRunning += (d.novos || 0)
        return { ano: d.ano, novos: d.novos || 0, total_acumulado: yearRunning }
      })
      
      console.log('đ User growth data:', { totalUsers, daily: userGrowthDaily.length, monthly: userGrowthMonthly.length, yearly: userGrowthYearly.length })
    } catch (e) {
      console.log('â ď¸ Erro ao buscar crescimento de usuĂĄrios:', e)
    }
    
    return c.json({
      conteudos: {
        totais: conteudoTotais.results || [],
        por_dia: conteudoPorDia.results || [],
        flashcards_total: flashcardsTotais?.total || 0,
        flashcards_por_dia: flashcardsPorDia.results || [],
        simulados_total: simuladosTotais?.total || 0,
        simulados_por_dia: simuladosPorDia.results || [],
        exercicios_total: exerciciosTotais?.total || 0,
        exercicios_por_dia: exerciciosPorDia.results || [],
        revisoes_total: revisoesTotais?.total || 0
      },
      feedbacks: {
        stats: feedbacksStats || {},
        por_tipo: feedbacksPorTipo.results || [],
        por_dia: feedbacksPorDia.results || [],
        lista: feedbacksLista.results || []
      },
      chat_lilu: {
        total: chatTotal,
        por_dia: chatPorDia,
        usuarios_unicos: chatUsuariosUnicos
      },
      user_growth: {
        total: totalUsers,
        daily: userGrowthDaily,
        monthly: userGrowthMonthly,
        yearly: userGrowthYearly
      }
    })
  } catch (error: any) {
    console.error('Erro analytics admin:', error)
    return c.json({ error: 'Erro ao buscar analytics', details: error.message }, 500)
  }
})

// ============== CONCURSOS PĂBLICOS API ==============
// v72: Proxy para API de concursos pĂşblicos do Brasil

const UFS_BRASIL = ['ac','al','ap','am','ba','ce','df','es','go','ma','mt','ms','mg','pa','pb','pr','pe','pi','rj','rn','rs','ro','rr','sc','sp','se','to']

// Buscar concursos de uma UF especĂ­fica (com cache D1 diĂĄrio)
app.get('/api/concursos/:uf', async (c) => {
  const uf = c.req.param('uf').toLowerCase()
  
  if (!UFS_BRASIL.includes(uf)) {
    return c.json({ error: 'UF invĂĄlida' }, 400)
  }
  
  try {
    // Tentar buscar do cache D1 do dia
    const hoje = new Date().toISOString().split('T')[0]
    const cached = await c.env.DB.prepare(
      'SELECT data_json FROM concursos_cache WHERE cache_date = ?'
    ).bind(hoje).first() as any
    
    if (cached) {
      const allData = JSON.parse(cached.data_json)
      const ufData = allData.find((e: any) => (e.uf || '').toLowerCase() === uf)
      if (ufData) return c.json(ufData)
    }
    
    // Sem cache, buscar da API externa
    const response = await fetch(`https://concursos-api.deno.dev/${uf}`, {
      headers: { 'Accept': 'application/json' }
    })
    const data = await response.json() as any
    return c.json(data)
  } catch (error: any) {
    console.error(`Erro ao buscar concursos ${uf}:`, error)
    return c.json({ error: 'Erro ao buscar concursos', details: error.message }, 500)
  }
})

// Buscar concursos de TODAS as UFs (cache D1 diĂĄrio â 1 requisiĂ§ĂŁo por dia)
app.get('/api/concursos', async (c) => {
  try {
    const hoje = new Date().toISOString().split('T')[0]
    const forceRefresh = c.req.query('force') === '1'
    
    // 1. Carregar cache D1 existente (sempre, para usar como fallback/merge)
    let cachedData: any[] | null = null
    let cachedTotals = { abertos: 0, previstos: 0 }
    try {
      const cached = await c.env.DB.prepare(
        'SELECT data_json, total_abertos, total_previstos, total_ufs FROM concursos_cache WHERE cache_date = ?'
      ).bind(hoje).first() as any
      if (cached) {
        cachedData = JSON.parse(cached.data_json)
        cachedTotals = { abertos: cached.total_abertos || 0, previstos: cached.total_previstos || 0 }
      }
    } catch (e) { /* ignore */ }
    
    // 2. Se nĂŁo forĂ§ar refresh e cache existe, retornar cache
    if (!forceRefresh && cachedData) {
      return c.json({
        success: true,
        total_ufs: cachedData.length,
        cached: true,
        cache_date: hoje,
        estados: cachedData
      })
    }
    
    // 3. Helper: buscar uma UF com retry automĂĄtico
    async function fetchUFComRetry(uf: string, maxRetries = 3): Promise<any> {
      for (let attempt = 1; attempt <= maxRetries; attempt++) {
        try {
          const controller = new AbortController()
          const timeoutId = setTimeout(() => controller.abort(), 10000)
          const response = await fetch(`https://concursos-api.deno.dev/${uf}`, {
            headers: { 'Accept': 'application/json' },
            signal: controller.signal
          })
          clearTimeout(timeoutId)
          const data = await response.json() as any
          const ab = (data.concursos_abertos || []).length
          const pr = (data.concursos_previstos || []).length
          // Se retornou dados, sucesso
          if (ab > 0 || pr > 0) {
            return { ...data, uf: data.uf || uf }
          }
          // Retornou vazio - tentar novamente (pode ser cold start da API)
          if (attempt < maxRetries) {
            await new Promise(r => setTimeout(r, 300 * attempt))
          }
        } catch (e) {
          if (attempt < maxRetries) {
            await new Promise(r => setTimeout(r, 500 * attempt))
          }
        }
      }
      // Todas as tentativas falharam
      return { uf, estado: uf.toUpperCase(), concursos_abertos: [], concursos_previstos: [] }
    }
    
    // 4. Buscar em lotes de 9 para nĂŁo sobrecarregar a API
    const batchSize = 9
    const allResults: any[] = []
    for (let i = 0; i < UFS_BRASIL.length; i += batchSize) {
      const batch = UFS_BRASIL.slice(i, i + batchSize)
      const batchResults = await Promise.all(batch.map(uf => fetchUFComRetry(uf)))
      allResults.push(...batchResults)
    }
    
    // 5. Mesclar com cache anterior: se uma UF veio vazia agora mas tinha dados no cache, manter o cache
    if (cachedData && cachedData.length > 0) {
      const cacheMap = new Map<string, any>()
      cachedData.forEach((e: any) => { if (e.uf) cacheMap.set(e.uf.toLowerCase(), e) })
      
      for (let i = 0; i < allResults.length; i++) {
        const r = allResults[i]
        const uf = (r.uf || '').toLowerCase()
        const ab = (r.concursos_abertos || []).length
        const pr = (r.concursos_previstos || []).length
        if (ab === 0 && pr === 0 && cacheMap.has(uf)) {
          const cached = cacheMap.get(uf)
          if ((cached.concursos_abertos || []).length > 0 || (cached.concursos_previstos || []).length > 0) {
            allResults[i] = cached // preservar dados do cache
          }
        }
      }
    }
    
    // 6. Calcular totais
    let totalAbertos = 0, totalPrevistos = 0, ufsComDados = 0
    allResults.forEach((e: any) => {
      const ab = (e.concursos_abertos || []).length
      const pr = (e.concursos_previstos || []).length
      totalAbertos += ab
      totalPrevistos += pr
      if (ab > 0 || pr > 0) ufsComDados++
    })
    
    // 7. Salvar no cache se dados sĂŁo melhores que o cache existente ou bons o suficiente
    const qualidadeBoa = ufsComDados >= 14
    const melhorQueCache = totalAbertos + totalPrevistos >= cachedTotals.abertos + cachedTotals.previstos
    if (qualidadeBoa || melhorQueCache) {
      try {
        await c.env.DB.prepare(
          'INSERT OR REPLACE INTO concursos_cache (cache_date, data_json, total_abertos, total_previstos, total_ufs) VALUES (?, ?, ?, ?, ?)'
        ).bind(hoje, JSON.stringify(allResults), totalAbertos, totalPrevistos, allResults.length).run()
        
        // Limpar caches antigos (manter 7 dias)
        await c.env.DB.prepare(
          'DELETE FROM concursos_cache WHERE cache_date < ?'
        ).bind(new Date(Date.now() - 7 * 86400000).toISOString().split('T')[0]).run()
      } catch (dbErr) {
        console.error('Erro ao salvar cache concursos:', dbErr)
      }
    }
    
    return c.json({
      success: true,
      total_ufs: allResults.length,
      cached: false,
      cache_date: hoje,
      ufs_com_dados: ufsComDados,
      estados: allResults
    })
  } catch (error: any) {
    console.error('Erro ao buscar todos concursos:', error)
    return c.json({ error: 'Erro ao buscar concursos', details: error.message }, 500)
  }
})

// ============== MENSAGENS ADMIN <-> USUĂRIO ==============

// Enviar mensagem do admin para um usuĂĄrio
app.post('/api/admin/messages', async (c) => {
  const { env } = c;
  const body = await c.req.json();
  const { admin_id, user_id, message } = body;
  
  if (!admin_id || !user_id || !message) {
    return c.json({ error: 'admin_id, user_id e message sĂŁo obrigatĂłrios' }, 400);
  }
  
  // â SEGURANĂA v146: Usar isAdmin() padrĂŁo
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403);
  }
  
  // Criar tabela se nĂŁo existir
  await env.DB.prepare(`CREATE TABLE IF NOT EXISTS admin_messages (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    admin_id INTEGER NOT NULL,
    user_id INTEGER NOT NULL,
    sender_type TEXT NOT NULL DEFAULT 'admin',
    message TEXT NOT NULL,
    read_at DATETIME DEFAULT NULL,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )`).run();
  
  const result = await env.DB.prepare(
    'INSERT INTO admin_messages (admin_id, user_id, sender_type, message) VALUES (?, ?, ?, ?)'
  ).bind(admin_id, user_id, 'admin', message).run();
  
  return c.json({ success: true, id: result.meta.last_row_id });
});

// UsuĂĄrio responde ao admin
app.post('/api/messages/reply', async (c) => {
  const { env } = c;
  const body = await c.req.json();
  const { user_id, message } = body;
  
  if (!user_id || !message) {
    return c.json({ error: 'user_id e message sĂŁo obrigatĂłrios' }, 400);
  }
  
  // Buscar o admin_id da Ăşltima conversa
  const lastMsg = await env.DB.prepare(
    'SELECT admin_id FROM admin_messages WHERE user_id = ? ORDER BY created_at DESC LIMIT 1'
  ).bind(user_id).first();
  
  const admin_id = lastMsg?.admin_id || 1; // fallback para admin padrĂŁo
  
  const result = await env.DB.prepare(
    'INSERT INTO admin_messages (admin_id, user_id, sender_type, message) VALUES (?, ?, ?, ?)'
  ).bind(admin_id, user_id, 'user', message).run();
  
  return c.json({ success: true, id: result.meta.last_row_id });
});

// Listar todas conversas do admin (lista de usuĂĄrios com mensagens)
// IMPORTANTE: Esta rota DEVE vir ANTES de /api/admin/messages/:user_id
// para que "conversations" nĂŁo seja capturado como :user_id
app.get('/api/admin/messages/conversations', async (c) => {
  const { env } = c;
  
  // â SEGURANĂA v146: VerificaĂ§ĂŁo admin OBRIGATĂRIA
  if (!await isAdmin(c)) {
    return c.json({ error: 'Acesso negado' }, 403);
  }
  
  try {
    // Criar tabela se nĂŁo existir
    await env.DB.prepare(`CREATE TABLE IF NOT EXISTS admin_messages (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      admin_id INTEGER NOT NULL,
      user_id INTEGER NOT NULL,
      sender_type TEXT NOT NULL DEFAULT 'admin',
      message TEXT NOT NULL,
      read_at DATETIME DEFAULT NULL,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )`).run();
    
    const conversations = await env.DB.prepare(`
      SELECT 
        am.user_id,
        u.name as user_name,
        u.email as user_email,
        MAX(am.created_at) as last_message_at,
        (SELECT message FROM admin_messages am2 WHERE am2.user_id = am.user_id ORDER BY am2.created_at DESC LIMIT 1) as last_message,
        (SELECT sender_type FROM admin_messages am3 WHERE am3.user_id = am.user_id ORDER BY am3.created_at DESC LIMIT 1) as last_sender,
        SUM(CASE WHEN am.sender_type = 'user' AND am.read_at IS NULL THEN 1 ELSE 0 END) as unread_from_user,
        COUNT(*) as total_messages
      FROM admin_messages am
      LEFT JOIN users u ON u.id = am.user_id
      GROUP BY am.user_id
      ORDER BY last_message_at DESC
    `).all();
    
    return c.json({ conversations: conversations.results || [] });
  } catch (e: any) {
    console.error('Erro conversations:', e?.message || e);
    return c.json({ conversations: [] });
  }
});

